class DoxaBase:
    """A small SQLite-backed RDF memory capsule.

    V1 stores RDF terms as strings in a simple quad table. RDFLib handles
    parsing/serialization and pySHACL handles explicit validation.
    """

    def __init__(
        self,
        path: str | Path = ".doxabase.sqlite",
        *,
        initialize: bool = True,
        seed: bool = True,
        read_only: bool = False,
    ) -> None:
        self.path = Path(path)
        self.read_only = read_only
        if read_only:
            if initialize:
                raise DoxaBaseError(
                    "Read-only DoxaBase connections cannot initialize or seed a "
                    "capsule; use DoxaBase.open_readonly(path) for existing "
                    "capsules."
                )
            uri = f"{self.path.resolve().as_uri()}?mode=ro"
            self._conn = sqlite3.connect(uri, uri=True)
        else:
            self._conn = sqlite3.connect(self.path)
        self._conn.row_factory = sqlite3.Row
        self._search_index_error: str | None = None
        self._staged_apply_check_cache: (
            dict[StagedApplyCheckCacheKey, StagedRevisionApplyCheck] | None
        ) = None
        if initialize:
            self._ensure_schema()
            self._ensure_default_graphs()
            if seed:
                self.seed_base_graphs()

    @contextmanager
    def _scoped_staged_apply_check_cache(
        self,
        cache: dict[StagedApplyCheckCacheKey, StagedRevisionApplyCheck] | None = None,
    ) -> Iterator[dict[StagedApplyCheckCacheKey, StagedRevisionApplyCheck]]:
        if self._staged_apply_check_cache is not None:
            yield self._staged_apply_check_cache
            return
        previous_cache = self._staged_apply_check_cache
        active_cache: dict[StagedApplyCheckCacheKey, StagedRevisionApplyCheck] = (
            cache if cache is not None else {}
        )
        self._staged_apply_check_cache = active_cache
        try:
            yield active_cache
        finally:
            self._staged_apply_check_cache = previous_cache

    @classmethod
    def create(
        cls,
        path: str | Path = ".doxabase.sqlite",
        *,
        overwrite: bool = False,
        seed: bool = True,
    ) -> "DoxaBase":
        db_path = Path(path)
        if overwrite and db_path.exists():
            db_path.unlink()
        return cls(db_path, initialize=True, seed=seed)

    @classmethod
    def open_readonly(cls, path: str | Path) -> "DoxaBase":
        """Open an existing capsule through a SQLite read-only connection."""

        return cls(path, initialize=False, seed=False, read_only=True)

    def close(self) -> None:
        self._conn.close()

    def __enter__(self) -> "DoxaBase":
        return self

    def __exit__(self, *_: object) -> None:
        self.close()

    def seed_base_graphs(self) -> None:
        for name, _, _, system_seed, source_path in DEFAULT_GRAPHS:
            if not system_seed or source_path is None:
                continue
            if self.triple_count(name) == 0:
                self._ensure_mutable(name, allow_immutable=True)
                self._ensure_graph(name)
                self._insert_graph(name, self._seed_graph_for_path(source_path))

    def _seed_graph_for_path(self, source_path: Path) -> Graph:
        source_path = Path(source_path)
        stat = source_path.stat()
        cache_key = (
            str(source_path.resolve()),
            "turtle",
            stat.st_mtime_ns,
            stat.st_size,
        )
        cached = _SEED_GRAPH_CACHE.get(cache_key)
        if cached is None:
            cached = self._parse_rdf_payload(
                source_path,
                format="turtle",
                payload_name="source",
                parser_context="import_turtle",
            )
            _SEED_GRAPH_CACHE[cache_key] = cached
        return cached

    def graph_overview(self, limit: int = 100) -> GraphOverview:
        graph_rows = self._conn.execute(
            """
            SELECT
                ng.name,
                ng.description,
                ng.mutable,
                ng.system_seed,
                ng.source_path,
                COUNT(q.subject) AS triple_count
            FROM named_graphs ng
            LEFT JOIN quads q ON q.graph = ng.name
            GROUP BY ng.name
            ORDER BY ng.system_seed DESC, ng.name
            """
        ).fetchall()
        named_graphs = [
            NamedGraphInfo(
                name=row["name"],
                description=row["description"],
                mutable=bool(row["mutable"]),
                system_seed=bool(row["system_seed"]),
                source_path=row["source_path"],
                triple_count=int(row["triple_count"]),
            )
            for row in graph_rows
        ]

        class_counts = self._count_objects(str(RDF.type), limit=limit)
        predicate_counts = [
            (row["predicate"], int(row["count"]))
            for row in self._conn.execute(
                """
                SELECT predicate, COUNT(*) AS count
                FROM quads
                GROUP BY predicate
                ORDER BY count DESC, predicate
                LIMIT ?
                """,
                (limit,),
            )
        ]
        key_counts = {
            "datasets": self._count_type("rc:Dataset"),
            "tables": self._count_type("rc:Table"),
            "columns": self._count_type("rc:Column"),
            "observations": self._count_type("rc:Observation")
            + self._count_type("rc:ProfileObservation"),
            "claims": self._count_type("rc:Claim"),
            "patterns": self._count_type("rc:Pattern"),
            "evidence": self._count_type("rc:Evidence"),
            "source_spans": self._count_type("rc:SourceSpan"),
            "graph_revisions": self._count_type("rc:GraphRevision"),
            "graph_patches": self._count_type("rc:GraphPatch"),
            "graph_snapshots": self._count_type("rc:GraphSnapshot"),
            "storage_accesses": self._count_type("rc:StorageAccess"),
            "shapes": self._count_type("sh:NodeShape"),
        }
        return GraphOverview(
            named_graphs=named_graphs,
            class_counts=class_counts,
            predicate_counts=predicate_counts,
            key_counts=key_counts,
            namespaces=PREFIXES.copy(),
        )

    def project_brief(
        self,
        *,
        limit: int = 20,
        profile_candidate_limit: int = 2,
    ) -> ProjectBrief:
        """Summarize current project work queues without mutating the capsule."""
        if limit < 1:
            raise DoxaBaseError("limit must be at least 1")
        if profile_candidate_limit < 0:
            raise DoxaBaseError("profile_candidate_limit must be non-negative")

        overview = self.graph_overview(limit=limit)
        entity_scan_limit = max(
            limit,
            overview.key_counts.get("datasets", 0),
            overview.key_counts.get("tables", 0),
        )
        dataset_entities = self._project_brief_dataset_entities(entity_scan_limit)
        datasets: list[ProjectBriefDatasetSummary] = []
        readiness_counts: dict[str, int] = {}
        returned_readiness_counts: dict[str, int] = {}
        recommended_tasks: list[ProjectBriefRecommendedTask] = []
        all_dataset_summaries: list[ProjectBriefDatasetSummary] = []
        staged_review = self._project_brief_staged_review(limit=limit)
        pending_detection_staged_review = staged_review
        if staged_review.omitted_count:
            pending_detection_staged_review = self._project_brief_staged_review(
                limit=staged_review.count
            )
        staged_frontier_task = self._project_brief_staged_frontier_task(
            staged_review
        )
        if staged_frontier_task is not None:
            recommended_tasks.append(staged_frontier_task)

        for entity_index, entity in enumerate(dataset_entities):
            description = self.describe_dataset(entity.iri)
            is_table = self._dataset_description_is_table(description)
            query_summary = (
                self._project_brief_query_summary(description.iri)
                if is_table
                else self._project_brief_non_tabular_query_summary()
            )
            readiness_counts[query_summary.readiness] = (
                readiness_counts.get(query_summary.readiness, 0) + 1
            )
            profile_summary = self._project_brief_profile_summary(
                description,
                profile_candidate_limit=profile_candidate_limit,
                staged_review=pending_detection_staged_review,
            )
            dataset_summary = ProjectBriefDatasetSummary(
                dataset=self._privacy_redacted_resource_summary(
                    ResourceSummary(
                        iri=description.iri,
                        label=description.label,
                        description=description.description,
                    )
                ),
                is_table=is_table,
                query=query_summary,
                profile=profile_summary,
            )
            all_dataset_summaries.append(dataset_summary)
            if entity_index < limit:
                datasets.append(dataset_summary)
                returned_readiness_counts[query_summary.readiness] = (
                    returned_readiness_counts.get(query_summary.readiness, 0)
                    + 1
                )
            recommended_tasks.extend(
                self._project_brief_dataset_tasks(
                    dataset_summary,
                    staged_review=pending_detection_staged_review,
                )
            )

        recommended_tasks.extend(
            self._project_brief_staged_tasks(staged_review)
        )
        recommended_tasks.sort(key=lambda task: (task.priority, task.task_type))
        selected_tasks = self._project_brief_select_recommended_tasks(
            recommended_tasks,
            limit=limit,
        )
        queue_counts = self._project_brief_task_type_counts(recommended_tasks)
        if staged_review.count:
            queue_counts["staged_review"] = max(
                staged_review.count,
                queue_counts.get("staged_review", 0),
            )
        returned_queue_counts = self._project_brief_task_type_counts(selected_tasks)
        omitted_queue_counts = {
            task_type: count - returned_queue_counts.get(task_type, 0)
            for task_type, count in queue_counts.items()
            if count > returned_queue_counts.get(task_type, 0)
        }
        limit_crowded_queue_types = (
            self._project_brief_limit_crowded_queue_types(
                queue_counts,
                returned_queue_counts,
                limit=limit,
            )
        )
        profile_queue_counts = self._project_brief_profile_queue_counts(
            all_dataset_summaries
        )
        suggested_profile_candidate_limit = (
            self._project_brief_suggested_profile_candidate_limit(
                all_dataset_summaries,
                profile_candidate_limit=profile_candidate_limit,
            )
        )
        health_tasks = self._project_brief_health_tasks(
            limit=limit,
            profile_candidate_limit=profile_candidate_limit,
            profile_candidate_omitted_count=profile_queue_counts.get(
                "profile_candidate_omitted",
                0,
            ),
            suggested_profile_candidate_limit=suggested_profile_candidate_limit,
            active_queue_type_count=len(queue_counts),
            omitted_queue_counts=omitted_queue_counts,
            limit_crowded_queue_types=limit_crowded_queue_types,
            total_queue_count=sum(queue_counts.values()),
            current_staged_revision_count=staged_review.count,
            queue_counts=queue_counts,
            storage_access_count=overview.key_counts.get("storage_accesses", 0),
        )
        selected_tasks = self._project_brief_attach_fixture_staleness_advisories(
            selected_tasks,
            all_tasks=recommended_tasks,
            health_tasks=health_tasks,
        )
        next_best_expansion = self._project_brief_next_best_expansion(
            health_tasks
        )
        full_frontier_expansion = self._project_brief_full_frontier_expansion(
            limit=limit,
            profile_candidate_limit=profile_candidate_limit,
            total_queue_count=sum(queue_counts.values()),
            profile_candidate_omitted_count=profile_queue_counts.get(
                "profile_candidate_omitted",
                0,
            ),
            suggested_profile_candidate_limit=suggested_profile_candidate_limit,
            health_tasks=health_tasks,
        )
        safety_first_source, safety_first_action = (
            self._project_brief_safety_first_action(health_tasks)
        )
        frontier_first_source, frontier_first_action = (
            self._project_brief_frontier_first_action(
                full_frontier_expansion=full_frontier_expansion,
                next_best_expansion=next_best_expansion,
                recommended_tasks=selected_tasks,
            )
        )
        first_unattended_source, first_unattended_action = (
            self._project_brief_first_unattended_action(
                safety_first_source=safety_first_source,
                safety_first_action=safety_first_action,
                frontier_first_source=frontier_first_source,
                frontier_first_action=frontier_first_action,
            )
        )
        frontier_status = self._project_brief_frontier_status(
            queue_counts=queue_counts,
            returned_queue_counts=returned_queue_counts,
            omitted_queue_counts=omitted_queue_counts,
            hidden_profile_candidate_count=profile_queue_counts.get(
                "profile_candidate_omitted",
                0,
            ),
            next_best_expansion=next_best_expansion,
            full_frontier_expansion=full_frontier_expansion,
            safety_first_action=safety_first_action,
            frontier_first_action=frontier_first_action,
            first_unattended_source=first_unattended_source,
            first_unattended_action=first_unattended_action,
        )

        return ProjectBrief(
            key_counts=overview.key_counts,
            dataset_count=max(
                overview.key_counts.get("datasets", 0),
                overview.key_counts.get("tables", 0),
                len(dataset_entities),
            ),
            returned_dataset_count=len(datasets),
            dataset_query_readiness_counts=readiness_counts,
            returned_dataset_query_readiness_counts=returned_readiness_counts,
            profile_queue_counts=profile_queue_counts,
            queue_counts=queue_counts,
            returned_queue_counts=returned_queue_counts,
            omitted_queue_counts=omitted_queue_counts,
            active_queue_type_count=len(queue_counts),
            returned_queue_type_count=len(returned_queue_counts),
            limit_crowded_queue_types=limit_crowded_queue_types,
            health_tasks=health_tasks,
            next_best_expansion=next_best_expansion,
            full_frontier_expansion=full_frontier_expansion,
            safety_first_action=safety_first_action,
            safety_first_call=(
                safety_first_action.call
                if safety_first_action is not None
                else None
            ),
            safety_first_source=safety_first_source,
            frontier_first_action=frontier_first_action,
            frontier_first_call=(
                frontier_first_action.call
                if frontier_first_action is not None
                else None
            ),
            frontier_first_source=frontier_first_source,
            first_unattended_action=first_unattended_action,
            first_unattended_call=(
                first_unattended_action.call
                if first_unattended_action is not None
                else None
            ),
            first_unattended_source=first_unattended_source,
            frontier_status=frontier_status,
            datasets=datasets,
            staged_review=staged_review,
            recommended_next_tasks=selected_tasks,
            limit=limit,
            profile_candidate_limit=profile_candidate_limit,
        )

    def _project_brief_dataset_entities(self, limit: int) -> list[EntityRow]:
        entities_by_iri: dict[str, EntityRow] = {}
        for type_iri in ("rc:Table", "rc:Dataset"):
            for entity in self.list_entities(
                type=type_iri,
                graph="map",
                limit=limit,
            ).entities:
                entities_by_iri.setdefault(entity.iri, entity)
        return sorted(
            entities_by_iri.values(),
            key=lambda entity: (entity.label or entity.iri, entity.iri),
        )

    def _project_brief_query_summary(
        self,
        dataset_iri: str,
    ) -> ProjectBriefDatasetQuerySummary:
        query_context = self.describe_query_context(dataset_iri)
        return ProjectBriefDatasetQuerySummary(
            readiness=query_context.readiness,
            readiness_note=query_context.readiness_note,
            issue_codes=self._query_issue_codes(query_context.issues),
            repair_action_group_count=(
                query_context.suggested_repair_action_group_count
            ),
            candidate_count=len(query_context.query_target_candidates),
            ready_candidate_indexes=query_context.ready_candidate_indexes,
            direct_clean_candidate_indexes=(
                query_context.direct_clean_candidate_indexes
            ),
            suggested_next_actions=query_context.suggested_next_actions[:3],
            suggested_next_calls=query_context.suggested_next_calls[:3],
        )

    def _dataset_description_is_table(self, dataset: DatasetDescription) -> bool:
        return self.expand_iri("rc:Table") in dataset.types

    @staticmethod
    def _project_brief_non_tabular_query_summary() -> ProjectBriefDatasetQuerySummary:
        return ProjectBriefDatasetQuerySummary(
            readiness="not_applicable_non_tabular_asset",
            readiness_note=(
                "This map dataset is not typed as rc:Table; use resource or "
                "context-slice handoffs unless an explicit queryable table "
                "route is modeled."
            ),
            issue_codes=[],
            repair_action_group_count=0,
            candidate_count=0,
            ready_candidate_indexes=[],
            direct_clean_candidate_indexes=[],
            suggested_next_actions=[],
            suggested_next_calls=[],
        )

    def _project_brief_profile_summary(
        self,
        dataset: DatasetDescription,
        *,
        profile_candidate_limit: int,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> ProjectBriefDatasetProfileSummary:
        profile_summary = dataset.profile_summary
        candidates = profile_summary.profile_run_candidates
        draft_evidence_iris = self._project_brief_profile_draft_evidence_iris(
            profile_summary
        )
        selected_draft_evidence_iris = draft_evidence_iris[:profile_candidate_limit]
        omitted_draft_evidence_iris = draft_evidence_iris[profile_candidate_limit:]
        drafts: list[ProjectBriefProfileDraftSummary] = []
        for evidence_iri in selected_draft_evidence_iris:
            pending_staged_profile_update_iris = (
                self._project_brief_pending_staged_profile_update_iris(
                    dataset.iri,
                    evidence_iri,
                    staged_review,
                )
            )
            draft = self.draft_profile_map_updates(
                dataset.iri,
                evidence_iri,
                known_pending_staged_profile_update_iris=(
                    pending_staged_profile_update_iris
                ),
            )
            suggested_next_actions = [
                self._privacy_redacted_suggested_next_action(action)
                for action in draft.suggested_next_actions[:3]
            ]
            drafts.append(
                ProjectBriefProfileDraftSummary(
                    evidence_iri=evidence_iri,
                    profile_observation_count=len(draft.profile_observation_iris),
                    recommendation_count=draft.recommendation_count,
                    scalar_conflict_group_count=draft.scalar_conflict_group_count,
                    metric_advisory_count=draft.metric_advisory_count,
                    metric_advisory_status_counts=(
                        draft.metric_advisory_status_counts
                    ),
                    type_advisory_count=draft.type_advisory_count,
                    type_advisory_status_counts=draft.type_advisory_status_counts,
                    action_group_names=list(draft.suggested_next_action_groups),
                    suggested_next_actions=suggested_next_actions,
                    suggested_next_calls=[
                        action.call for action in suggested_next_actions
                    ],
                )
            )
        return ProjectBriefDatasetProfileSummary(
            total_profile_count=profile_summary.total_profile_count,
            returned_profile_count=profile_summary.returned_profile_count,
            omitted_profile_count=profile_summary.omitted_profile_count,
            profile_evidence_count=len(profile_summary.evidence_iris),
            profile_evidence_iris=profile_summary.evidence_iris,
            profile_run_candidate_count=len(candidates),
            profile_run_evidence_iris=[
                candidate.evidence_iri for candidate in candidates
            ],
            draft_candidate_count=len(draft_evidence_iris),
            profile_candidate_omitted_count=len(omitted_draft_evidence_iris),
            omitted_draft_evidence_iris=omitted_draft_evidence_iris,
            draft_count=len(drafts),
            draft_evidence_iris=[draft.evidence_iri for draft in drafts],
            drafts=drafts,
        )

    def _project_brief_profile_draft_evidence_iris(
        self,
        profile_summary: ProfileSummary,
    ) -> list[str]:
        evidence_iris: list[str] = []
        for candidate in profile_summary.profile_run_candidates:
            evidence_iris.append(candidate.evidence_iri)
        evidence_iris.extend(profile_summary.shared_evidence_iris)
        evidence_iris.extend(profile_summary.evidence_iris)
        return list(dict.fromkeys(evidence_iris))

    @staticmethod
    def _project_brief_suggested_profile_candidate_limit(
        datasets: list[ProjectBriefDatasetSummary],
        *,
        profile_candidate_limit: int,
    ) -> int | None:
        required_limit = max(
            (
                dataset.profile.draft_candidate_count
                for dataset in datasets
                if dataset.profile.profile_candidate_omitted_count > 0
            ),
            default=0,
        )
        if required_limit <= profile_candidate_limit:
            return None
        return required_limit

    def _project_brief_staged_frontier_task(
        self,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> ProjectBriefRecommendedTask | None:
        if staged_review.count <= 0:
            return None
        action = self._project_brief_plan_staged_revision_recovery_action()
        return ProjectBriefRecommendedTask(
            priority=5,
            task_type="staged_frontier_review",
            source="plan_staged_revision_recovery",
            resource=None,
            reason=(
                "Current staged work exists; inspect the staged mutation frontier "
                "and apply-one-then-recheck hazards before staging duplicate "
                "profile or query repair work."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
        )

    def _project_brief_plan_staged_revision_recovery_action(
        self,
    ) -> SuggestedNextAction:
        arguments = {"current_staged_work_only": True}
        return SuggestedNextAction(
            action_label="Plan current staged recovery",
            tool_name="plan_staged_revision_recovery",
            mcp_tool_name="doxabase.plan_staged_revision_recovery",
            arguments=arguments,
            reason=(
                "Inspect current staged work, mutation_frontier_iris, and "
                "requires_recheck_after_each_apply before taking another graph "
                "mutation."
            ),
            call=self._suggested_call_string(
                "plan_staged_revision_recovery",
                arguments,
            ),
        )

    def _project_brief_health_tasks(
        self,
        *,
        limit: int,
        profile_candidate_limit: int,
        profile_candidate_omitted_count: int,
        suggested_profile_candidate_limit: int | None,
        active_queue_type_count: int,
        omitted_queue_counts: dict[str, int],
        limit_crowded_queue_types: list[str],
        total_queue_count: int,
        current_staged_revision_count: int,
        queue_counts: dict[str, int],
        storage_access_count: int,
    ) -> list[ProjectBriefHealthTask]:
        tasks: list[ProjectBriefHealthTask] = []
        expand_task = self._project_brief_expand_health_task(
            limit=limit,
            profile_candidate_limit=profile_candidate_limit,
            active_queue_type_count=active_queue_type_count,
            omitted_queue_counts=omitted_queue_counts,
            limit_crowded_queue_types=limit_crowded_queue_types,
            total_queue_count=total_queue_count,
        )
        if expand_task is not None:
            tasks.append(expand_task)

        profile_candidate_task = (
            self._project_brief_profile_candidate_limit_health_task(
                limit=limit,
                profile_candidate_omitted_count=(
                    profile_candidate_omitted_count
                ),
                suggested_profile_candidate_limit=(
                    suggested_profile_candidate_limit
                ),
            )
        )
        if profile_candidate_task is not None:
            tasks.append(profile_candidate_task)

        fixture_storage_task = self._project_brief_fixture_storage_health_task(
            queue_counts=queue_counts,
            storage_access_count=storage_access_count,
        )
        if fixture_storage_task is not None:
            tasks.append(fixture_storage_task)

        privacy_task = self._project_brief_privacy_health_task()
        if privacy_task is not None:
            tasks.append(privacy_task)

        seed_task = self._project_brief_seed_recovery_health_task(
            current_staged_revision_count=current_staged_revision_count,
        )
        if seed_task is not None:
            tasks.append(seed_task)

        return sorted(tasks, key=lambda task: (task.priority, task.task_type))

    @staticmethod
    def _project_brief_next_best_expansion(
        health_tasks: list[ProjectBriefHealthTask],
    ) -> ProjectBriefHealthTask | None:
        expansion_priority = (
            "expand_project_brief",
            "expand_profile_candidate_limit",
        )
        for task_type in expansion_priority:
            for task in health_tasks:
                if task.task_type == task_type:
                    return task
        return None

    def _project_brief_full_frontier_expansion(
        self,
        *,
        limit: int,
        profile_candidate_limit: int,
        total_queue_count: int,
        profile_candidate_omitted_count: int,
        suggested_profile_candidate_limit: int | None,
        health_tasks: list[ProjectBriefHealthTask],
    ) -> ProjectBriefHealthTask | None:
        expansion_tasks = [
            task
            for task in health_tasks
            if task.task_type in {
                "expand_project_brief",
                "expand_profile_candidate_limit",
            }
        ]
        if not expansion_tasks:
            return None

        full_limit = max(limit, total_queue_count)
        full_profile_candidate_limit = profile_candidate_limit
        if (
            suggested_profile_candidate_limit is not None
            and profile_candidate_omitted_count > 0
        ):
            full_profile_candidate_limit = suggested_profile_candidate_limit
            full_limit = max(
                full_limit,
                total_queue_count + profile_candidate_omitted_count,
            )
        if (
            full_limit == limit
            and full_profile_candidate_limit == profile_candidate_limit
        ):
            return None

        arguments = {
            "limit": full_limit,
            "profile_candidate_limit": full_profile_candidate_limit,
        }
        action = SuggestedNextAction(
            action_label="Expand full project brief frontier",
            tool_name="project_brief",
            mcp_tool_name="doxabase.project_brief",
            arguments=arguments,
            reason=(
                "Expose all currently counted recommended-task payloads and any "
                "profile drafts hidden by profile_candidate_limit in one rerun."
            ),
            call=self._suggested_call_string("project_brief", arguments),
        )
        queue_types: list[str] = []
        omitted_queue_counts: dict[str, int] = {}
        for task in expansion_tasks:
            queue_types.extend(task.queue_types)
            omitted_queue_counts.update(task.omitted_queue_counts)
        return ProjectBriefHealthTask(
            priority=9,
            task_type="expand_full_project_brief",
            source="project_brief",
            reason=(
                "The current bounded brief does not expose the full project "
                "frontier; this synthesized action expands both task and profile "
                "candidate limits together."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
            queue_types=list(dict.fromkeys(queue_types)),
            omitted_queue_counts=omitted_queue_counts,
            suggested_limit=full_limit,
            exhaustive_suggested_limit=full_limit,
            suggested_profile_candidate_limit=full_profile_candidate_limit,
            profile_candidate_omitted_count=(
                profile_candidate_omitted_count
                if profile_candidate_omitted_count > 0
                else None
            ),
        )

    @staticmethod
    def _project_brief_safety_first_action(
        health_tasks: list[ProjectBriefHealthTask],
    ) -> tuple[str | None, SuggestedNextAction | None]:
        for task in health_tasks:
            if (
                task.task_type == "privacy_export_review"
                and task.suggested_next_action is not None
                and (task.sensitive_literal_count or 0) > 0
            ):
                return (
                    "health_tasks:privacy_export_review",
                    task.suggested_next_action,
                )
        for task in health_tasks:
            if (
                task.task_type == "seed_recovery_review"
                and task.suggested_next_action is not None
            ):
                return (
                    "health_tasks:seed_recovery_review",
                    task.suggested_next_action,
                )
        return None, None

    @staticmethod
    def _project_brief_frontier_first_action(
        *,
        full_frontier_expansion: ProjectBriefHealthTask | None,
        next_best_expansion: ProjectBriefHealthTask | None,
        recommended_tasks: list[ProjectBriefRecommendedTask],
    ) -> tuple[str | None, SuggestedNextAction | None]:
        if (
            full_frontier_expansion is not None
            and full_frontier_expansion.suggested_next_action is not None
        ):
            return (
                "full_frontier_expansion",
                full_frontier_expansion.suggested_next_action,
            )
        if (
            next_best_expansion is not None
            and next_best_expansion.suggested_next_action is not None
        ):
            return "next_best_expansion", next_best_expansion.suggested_next_action
        for task in recommended_tasks:
            if task.suggested_next_action is not None:
                return (
                    f"recommended_next_tasks:{task.task_type}",
                    task.suggested_next_action,
                )
        return None, None

    @staticmethod
    def _project_brief_first_unattended_action(
        *,
        safety_first_source: str | None,
        safety_first_action: SuggestedNextAction | None,
        frontier_first_source: str | None,
        frontier_first_action: SuggestedNextAction | None,
    ) -> tuple[str | None, SuggestedNextAction | None]:
        if safety_first_action is not None:
            return safety_first_source, safety_first_action
        return frontier_first_source, frontier_first_action

    @staticmethod
    def _project_brief_frontier_status(
        *,
        queue_counts: dict[str, int],
        returned_queue_counts: dict[str, int],
        omitted_queue_counts: dict[str, int],
        hidden_profile_candidate_count: int,
        next_best_expansion: ProjectBriefHealthTask | None,
        full_frontier_expansion: ProjectBriefHealthTask | None,
        safety_first_action: SuggestedNextAction | None,
        frontier_first_action: SuggestedNextAction | None,
        first_unattended_source: str | None,
        first_unattended_action: SuggestedNextAction | None,
    ) -> ProjectBriefFrontierStatus:
        hidden_task_count = sum(omitted_queue_counts.values())
        hidden_queue_types = list(omitted_queue_counts)
        if (
            hidden_profile_candidate_count > 0
            and "profile_review" not in hidden_queue_types
        ):
            hidden_queue_types.append("profile_review")
        must_rerun_action = (
            full_frontier_expansion.suggested_next_action
            if full_frontier_expansion is not None
            and full_frontier_expansion.suggested_next_action is not None
            else (
                next_best_expansion.suggested_next_action
                if next_best_expansion is not None
                else None
            )
        )
        is_complete = (
            hidden_task_count == 0
            and hidden_profile_candidate_count == 0
            and must_rerun_action is None
        )
        if safety_first_action is not None:
            mutation_allowed_after = (
                "safety_review_required_before_frontier_or_mutation"
            )
            note = (
                "Run the safety-first action before frontier expansion, export, "
                "or graph mutation."
            )
        elif must_rerun_action is not None:
            mutation_allowed_after = "frontier_expansion_required_before_mutation"
            note = (
                "Rerun project_brief with the suggested expanded bounds before "
                "choosing a mutation-oriented task."
            )
        elif frontier_first_action is not None:
            mutation_allowed_after = "current_frontier_task_available"
            note = (
                "The bounded brief has no hidden counted frontier; review the "
                "frontier-first task before mutating."
            )
        else:
            mutation_allowed_after = "no_current_recommended_task"
            note = (
                "No safety-first, expansion, or recommended frontier action is "
                "currently exposed by the brief."
            )
        return ProjectBriefFrontierStatus(
            is_complete=is_complete,
            hidden_task_count=hidden_task_count,
            hidden_profile_candidate_count=hidden_profile_candidate_count,
            hidden_queue_types=hidden_queue_types,
            active_queue_types=list(queue_counts),
            returned_queue_types=list(returned_queue_counts),
            must_rerun_call=(
                must_rerun_action.call if must_rerun_action is not None else None
            ),
            safety_first_call=(
                safety_first_action.call if safety_first_action is not None else None
            ),
            frontier_first_call=(
                frontier_first_action.call
                if frontier_first_action is not None
                else None
            ),
            first_unattended_call=(
                first_unattended_action.call
                if first_unattended_action is not None
                else None
            ),
            first_unattended_source=first_unattended_source,
            mutation_allowed_after=mutation_allowed_after,
            note=note,
        )

    def _project_brief_profile_candidate_limit_health_task(
        self,
        *,
        limit: int,
        profile_candidate_omitted_count: int,
        suggested_profile_candidate_limit: int | None,
    ) -> ProjectBriefHealthTask | None:
        if (
            profile_candidate_omitted_count <= 0
            or suggested_profile_candidate_limit is None
        ):
            return None
        arguments = {
            "limit": limit,
            "profile_candidate_limit": suggested_profile_candidate_limit,
        }
        action = SuggestedNextAction(
            action_label="Expand profile candidate frontier",
            tool_name="project_brief",
            mcp_tool_name="doxabase.project_brief",
            arguments=arguments,
            reason=(
                "Some profile evidence candidates were omitted before draft "
                "queues were built; rerun project_brief with a larger "
                "profile_candidate_limit before assuming profile_review is "
                "exhausted."
            ),
            call=self._suggested_call_string("project_brief", arguments),
        )
        return ProjectBriefHealthTask(
            priority=10,
            task_type="expand_profile_candidate_limit",
            source="project_brief",
            reason=(
                "The current profile_candidate_limit hides profile draft "
                "candidates before they can enter profile_review queues."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
            queue_types=["profile_review"],
            suggested_limit=limit,
            suggested_profile_candidate_limit=suggested_profile_candidate_limit,
            profile_candidate_omitted_count=profile_candidate_omitted_count,
        )

    def _project_brief_expand_health_task(
        self,
        *,
        limit: int,
        profile_candidate_limit: int,
        active_queue_type_count: int,
        omitted_queue_counts: dict[str, int],
        limit_crowded_queue_types: list[str],
        total_queue_count: int,
    ) -> ProjectBriefHealthTask | None:
        if not omitted_queue_counts and not limit_crowded_queue_types:
            return None
        suggested_limit = max(limit + 1, active_queue_type_count)
        if omitted_queue_counts:
            suggested_limit = max(
                suggested_limit,
                min(limit + sum(omitted_queue_counts.values()), limit * 2),
            )
        exhaustive_suggested_limit = max(suggested_limit, total_queue_count)
        arguments = {
            "limit": suggested_limit,
            "profile_candidate_limit": profile_candidate_limit,
        }
        action = SuggestedNextAction(
            action_label="Expand project brief frontier",
            tool_name="project_brief",
            mcp_tool_name="doxabase.project_brief",
            arguments=arguments,
            reason=(
                "Some active queues were omitted from the bounded recommended "
                "task slice; rerun project_brief with a larger limit before "
                "repeating the same visible tasks. The suggested limit may be "
                "iterative; use exhaustive_suggested_limit when you need one "
                "rerun that exposes every currently counted task payload."
            ),
            call=self._suggested_call_string("project_brief", arguments),
        )
        queue_types = list(
            dict.fromkeys(
                [*omitted_queue_counts.keys(), *limit_crowded_queue_types]
            )
        )
        return ProjectBriefHealthTask(
            priority=10,
            task_type="expand_project_brief",
            source="project_brief",
            reason=(
                "The current project_brief limit hides some concrete task "
                "payloads from recommended_next_tasks."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
            queue_types=queue_types,
            omitted_queue_counts=dict(omitted_queue_counts),
            suggested_limit=suggested_limit,
            exhaustive_suggested_limit=exhaustive_suggested_limit,
        )

    def _project_brief_fixture_storage_health_task(
        self,
        *,
        queue_counts: dict[str, int],
        storage_access_count: int,
    ) -> ProjectBriefHealthTask | None:
        if queue_counts.get("query_repair_review", 0) <= 0:
            return None
        hint = self._known_fixture_tables_without_storage_access_hint(
            storage_access_count=storage_access_count
        )
        if hint is None:
            return None
        known_fixture_table_iris = list(hint["known_fixture_table_iris"])
        representative_dataset_iri = known_fixture_table_iris[0]
        arguments = {"iri": representative_dataset_iri}
        action = SuggestedNextAction(
            action_label="Inspect fixture storage frontier",
            tool_name="describe_query_context",
            mcp_tool_name="doxabase.describe_query_context",
            arguments=arguments,
            reason=(
                "Known AIS or Polymarket fixture tables are present but the "
                "capsule has no rc:StorageAccess resources; inspect one "
                "representative query context before staging repeated "
                "missing-storage repairs."
            ),
            call=self._suggested_call_string("describe_query_context", arguments),
        )
        return ProjectBriefHealthTask(
            priority=15,
            task_type="query_fixture_staleness_review",
            source="fixture_storage_access_check",
            reason=(
                "Known query-planning fixture tables are present while the "
                "capsule has zero rc:StorageAccess resources. Treat the capsule "
                "as stale or intentionally reduced for storage-aware query "
                "trials until a representative query context is reviewed or "
                "fresh fixtures are loaded into scratch."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
            queue_types=["query_repair_review"],
            fixture_names=list(hint["fixture_names"]),
            known_fixture_table_iris=known_fixture_table_iris,
            storage_access_count=storage_access_count,
        )

    def _project_brief_attach_fixture_staleness_advisories(
        self,
        selected_tasks: list[ProjectBriefRecommendedTask],
        *,
        all_tasks: list[ProjectBriefRecommendedTask],
        health_tasks: list[ProjectBriefHealthTask],
    ) -> list[ProjectBriefRecommendedTask]:
        fixture_task = next(
            (
                task
                for task in health_tasks
                if task.task_type == "query_fixture_staleness_review"
            ),
            None,
        )
        if fixture_task is None or fixture_task.suggested_next_action is None:
            return selected_tasks
        known_fixture_iris = set(fixture_task.known_fixture_table_iris)
        if not known_fixture_iris:
            return selected_tasks

        def is_affected_query_task(task: ProjectBriefRecommendedTask) -> bool:
            return (
                task.task_type == "query_repair_review"
                and task.resource is not None
                and task.resource.iri in known_fixture_iris
            )

        group_member_count = sum(1 for task in all_tasks if is_affected_query_task(task))
        returned_group_member_count = sum(
            1 for task in selected_tasks if is_affected_query_task(task)
        )
        if group_member_count <= 0:
            return selected_tasks

        suggested_next_action = to_jsonable(fixture_task.suggested_next_action)
        advisory = {
            "code": "query_fixture_staleness_review",
            "severity": "warning",
            "source": fixture_task.source,
            "related_health_task_type": fixture_task.task_type,
            "recommended_handling": "review_health_task_before_staging",
            "reason": fixture_task.reason,
            "suggested_next_action": suggested_next_action,
            "suggested_next_call": fixture_task.suggested_next_call,
            "fixture_names": list(fixture_task.fixture_names),
            "known_fixture_table_iris": list(fixture_task.known_fixture_table_iris),
            "storage_access_count": fixture_task.storage_access_count,
        }
        group = {
            "group_key": (
                "query_fixture_staleness_review:"
                "known_fixture_tables_without_storage_accesses"
            ),
            "group_type": "query_fixture_staleness_review",
            "group_member_count": group_member_count,
            "returned_group_member_count": returned_group_member_count,
            "suppression_policy": "review_group_before_member_mutation",
            "representative_resource_iri": (
                fixture_task.known_fixture_table_iris[0]
                if fixture_task.known_fixture_table_iris
                else None
            ),
        }

        return [
            replace(
                task,
                task_advisories=[*task.task_advisories, copy.deepcopy(advisory)],
                task_group=copy.deepcopy(group),
            )
            if is_affected_query_task(task)
            else task
            for task in selected_tasks
        ]

    def _project_brief_privacy_health_task(
        self,
    ) -> ProjectBriefHealthTask | None:
        arguments = {
            "export_kind": "handoff_bundle",
            "graphs": ["project"],
            "limit": 20,
        }
        preflight = self.export_preflight(**arguments)
        if preflight.sensitive_literal_count == 0:
            return None
        action = SuggestedNextAction(
            action_label="Review export privacy",
            tool_name="export_preflight",
            mcp_tool_name="doxabase.export_preflight",
            arguments=arguments,
            reason=(
                "Run a redacted export preflight before sharing RDF or handoff "
                "exports; follow its blocking export action when the scanner is "
                "clean."
            ),
            call=self._suggested_call_string("export_preflight", arguments),
        )
        return ProjectBriefHealthTask(
            priority=20,
            task_type="privacy_export_review",
            source="export_preflight",
            reason=(
                "The default handoff-bundle export scope contains potential "
                "sensitive graph or revision-snapshot terms; project_brief "
                "reports only the count and a redacted export preflight route."
            ),
            suggested_next_action=action,
            suggested_next_call=action.call,
            sensitive_literal_count=preflight.sensitive_literal_count,
        )

    def _project_brief_seed_recovery_health_task(
        self,
        *,
        current_staged_revision_count: int,
    ) -> ProjectBriefHealthTask | None:
        required_terms = list(
            dict.fromkeys(
                [
                    *REQUIRED_STAGING_ONTOLOGY_TERMS,
                    *REQUIRED_REVISION_STANCE_ONTOLOGY_TERMS,
                ]
            )
        )
        missing_seed_terms = self._missing_base_ontology_terms(required_terms)
        if not missing_seed_terms:
            return None
        arguments = {
            "export_kind": "handoff_bundle",
            "graphs": ["project"],
            "limit": 20,
        }
        if current_staged_revision_count > 0:
            action = SuggestedNextAction(
                action_label="Preflight stale seed handoff export",
                tool_name="export_preflight",
                mcp_tool_name="doxabase.export_preflight",
                arguments=arguments,
                reason=(
                    "Current staged graph revision rows exist; preflight a "
                    "project/history plus revision snapshots handoff before "
                    "recovering into a fresh seeded capsule."
                ),
                call=self._suggested_call_string("export_preflight", arguments),
            )
            queue_types = ["staged_review"]
            staged_count: int | None = current_staged_revision_count
        else:
            action = SuggestedNextAction(
                action_label="Preflight stale seed project handoff export",
                tool_name="export_preflight",
                mcp_tool_name="doxabase.export_preflight",
                arguments=arguments,
                reason=(
                    "The immutable base_ontology is missing current staging seed "
                    "terms; preflight a project/history handoff before recovering "
                    "into a fresh seeded capsule. The companion revision snapshot "
                    "bundle may be empty."
                ),
                call=self._suggested_call_string("export_preflight", arguments),
            )
            queue_types = []
            staged_count = 0
        return ProjectBriefHealthTask(
            priority=5,
            task_type="seed_recovery_review",
            source="base_ontology_seed_check",
            reason=self._stale_seed_recovery_message(missing_seed_terms),
            suggested_next_action=action,
            suggested_next_call=action.call,
            queue_types=queue_types,
            missing_seed_terms=missing_seed_terms,
            current_staged_revision_count=staged_count,
        )

    def _project_brief_staged_review(
        self,
        *,
        limit: int,
    ) -> ProjectBriefStagedReviewSummary:
        listing = self.list_graph_revisions(
            current_staged_work_only=True,
            include_apply_checks=True,
            limit=limit,
        )
        queue_by_row = {
            item.row_iri: item for item in listing.next_action_queue_items
        }
        items: list[ProjectBriefStagedReviewItem] = []
        for revision in listing.revisions:
            queue_item = queue_by_row.get(revision.iri)
            items.append(
                ProjectBriefStagedReviewItem(
                    revision_iri=revision.iri,
                    summary=revision.summary,
                    record_kind=revision.record_kind,
                    application_status=revision.application_status,
                    queue=queue_item.queue if queue_item is not None else None,
                    resolved_target_iri=(
                        queue_item.resolved_target_iri
                        if queue_item is not None
                        else None
                    ),
                    revision_anchor_iris=self._objects(
                        ["history"],
                        revision.iri,
                        "rc:revisionAnchor",
                    ),
                    evidence_iris=self._objects(
                        ["history"],
                        revision.iri,
                        "rc:evidence",
                    ),
                    suggested_next_action=(
                        revision.suggested_next_actions[0]
                        if revision.suggested_next_actions
                        else None
                    ),
                )
            )
        return ProjectBriefStagedReviewSummary(
            count=listing.count,
            returned_count=listing.returned_count,
            omitted_count=max(0, listing.count - listing.returned_count),
            application_status_counts=(
                listing.returned_application_status_counts
            ),
            next_action_queue_item_counts=(
                listing.next_action_queue_item_counts
            ),
            items=items,
        )

    def _project_brief_dataset_tasks(
        self,
        dataset: ProjectBriefDatasetSummary,
        *,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> list[ProjectBriefRecommendedTask]:
        tasks: list[ProjectBriefRecommendedTask] = []
        if not dataset.is_table:
            action = self._project_brief_describe_context_slice_action(
                dataset.dataset.iri,
            )
            tasks.append(
                ProjectBriefRecommendedTask(
                    priority=25,
                    task_type="non_tabular_asset_review",
                    source="describe_context_slice",
                    resource=dataset.dataset,
                    reason=(
                        "Dataset is not typed as rc:Table; inspect map context, "
                        "caveats, patterns, observations, and evidence instead "
                        "of query-planning repair lanes."
                    ),
                    suggested_next_action=action,
                    suggested_next_call=action.call,
                )
            )
        else:
            if dataset.query.repair_action_group_count:
                repair_action = self._project_brief_describe_query_context_action(
                    dataset.dataset.iri
                )
                pending_staged_repair_iris = (
                    self._project_brief_pending_staged_repair_iris(
                        dataset.dataset.iri,
                        staged_review,
                    )
                )
                pending_note = (
                    " Pending staged repair(s) already anchor this dataset; "
                    "review the staged work before staging a duplicate repair."
                    if pending_staged_repair_iris
                    else ""
                )
                tasks.append(
                    ProjectBriefRecommendedTask(
                        priority=45 if pending_staged_repair_iris else 10,
                        task_type="query_repair_review",
                        source="describe_query_context",
                        resource=dataset.dataset,
                        reason=(
                            "Dataset query context exposes reviewed repair "
                            f"action groups.{pending_note}"
                        ),
                        suggested_next_action=repair_action,
                        suggested_next_call=repair_action.call,
                        pending_staged_repair_iris=pending_staged_repair_iris,
                    )
                )
            elif dataset.query.readiness not in {
                "ready_for_query_planning",
                "ready",
            }:
                review_action = self._project_brief_describe_query_context_action(
                    dataset.dataset.iri
                )
                tasks.append(
                    ProjectBriefRecommendedTask(
                        priority=20,
                        task_type="query_context_review",
                        source="describe_query_context",
                        resource=dataset.dataset,
                        reason=(
                            "Dataset query context is not ready for planning: "
                            f"{dataset.query.readiness}."
                        ),
                        suggested_next_action=review_action,
                        suggested_next_call=review_action.call,
                    )
                )
            else:
                handoff_action = self._project_brief_query_plan_handoff_action(
                    dataset
                )
                handoff_summary = self._project_brief_query_plan_handoff_summary(
                    handoff_action
                )
                tasks.append(
                    ProjectBriefRecommendedTask(
                        priority=60,
                        task_type="query_plan_handoff",
                        source=handoff_action.tool_name,
                        resource=dataset.dataset,
                        reason=(
                            "Dataset query context is ready for a non-executed "
                            "query-plan handoff; draft or inspect the handoff "
                            "before treating ready query work as exhausted."
                        ),
                        suggested_next_action=handoff_action,
                        suggested_next_call=handoff_action.call,
                        query_plan_handoff_summary=handoff_summary,
                    )
                )

        for draft in dataset.profile.drafts:
            if self._project_brief_profile_draft_requires_review(draft):
                inspection_action = self._project_brief_draft_profile_action(
                    dataset.dataset.iri,
                    draft.evidence_iri,
                )
                pending_staged_profile_update_iris = (
                    self._project_brief_pending_staged_profile_update_iris(
                        dataset.dataset.iri,
                        draft.evidence_iri,
                        staged_review,
                    )
                )
                open_profile_advisory_count = (
                    draft.scalar_conflict_group_count
                    + self._project_brief_metric_advisory_review_count(draft)
                    + draft.type_advisory_count
                )
                if pending_staged_profile_update_iris:
                    action = inspection_action
                else:
                    action = (
                        draft.suggested_next_actions[0]
                        if draft.suggested_next_actions
                        else inspection_action
                    )
                if pending_staged_profile_update_iris and open_profile_advisory_count:
                    pending_note = (
                        " Pending staged profile update(s) already anchor this "
                        "dataset/evidence, but profile advisory/conflict lanes "
                        "remain open; review the profile draft before assuming "
                        "staged work covers it."
                    )
                elif pending_staged_profile_update_iris:
                    pending_note = (
                        " Pending staged profile update(s) already anchor this "
                        "dataset/evidence; review staged frontier work before "
                        "staging another profile update."
                    )
                else:
                    pending_note = ""
                tasks.append(
                    ProjectBriefRecommendedTask(
                        priority=(
                            55
                            if pending_staged_profile_update_iris
                            and not open_profile_advisory_count
                            else 30
                        ),
                        task_type="profile_review",
                        source="draft_profile_map_updates",
                        resource=dataset.dataset,
                        reason=(
                            "Profile evidence has map updates, conflicts, "
                            f"metric vocabulary, or type findings to review.{pending_note}"
                        ),
                        suggested_next_action=action,
                        suggested_next_call=action.call,
                        inspection_next_action=inspection_action,
                        inspection_next_call=inspection_action.call,
                        profile_evidence_iri=draft.evidence_iri,
                        pending_staged_profile_update_iris=(
                            pending_staged_profile_update_iris
                        ),
                    )
                )
        return tasks

    @staticmethod
    def _project_brief_profile_draft_requires_review(
        draft: ProjectBriefProfileDraftSummary,
    ) -> bool:
        return bool(
            draft.recommendation_count
            or draft.scalar_conflict_group_count
            or DoxaBase._project_brief_metric_advisory_review_count(draft)
            or draft.type_advisory_count
        )

    @staticmethod
    def _project_brief_metric_advisory_review_count(
        draft: ProjectBriefProfileDraftSummary,
    ) -> int:
        context_only_count = draft.metric_advisory_status_counts.get(
            "project_metric_defined",
            0,
        )
        return max(0, draft.metric_advisory_count - context_only_count)

    def _project_brief_describe_context_slice_action(
        self,
        dataset_iri: str,
    ) -> SuggestedNextAction:
        arguments = {
            "seed_iris": [dataset_iri],
            "profile": "deep_lore",
        }
        return SuggestedNextAction(
            action_label="Inspect non-tabular asset context",
            tool_name="describe_context_slice",
            mcp_tool_name="doxabase.describe_context_slice",
            arguments=arguments,
            reason=(
                "Inspect the non-tabular asset's map context, caveats, "
                "patterns, observations, and evidence without treating it as a "
                "table query target."
            ),
            call=self._suggested_call_string(
                "describe_context_slice",
                arguments,
            ),
        )

    def _project_brief_describe_query_context_action(
        self,
        dataset_iri: str,
    ) -> SuggestedNextAction:
        arguments = {"iri": dataset_iri}
        return SuggestedNextAction(
            action_label="Review query context",
            tool_name="describe_query_context",
            mcp_tool_name="doxabase.describe_query_context",
            arguments=arguments,
            reason="Inspect the dataset query context before choosing a repair or plan.",
            call=self._suggested_call_string(
                "describe_query_context",
                arguments,
            ),
        )

    def _project_brief_query_plan_handoff_action(
        self,
        dataset: ProjectBriefDatasetSummary,
    ) -> SuggestedNextAction:
        for action in dataset.query.suggested_next_actions:
            if action.tool_name == "draft_query_plan":
                return action

        query_context = self.describe_query_context(dataset.dataset.iri)
        for action in query_context.suggested_next_actions:
            if action.tool_name == "draft_query_plan":
                return action

        arguments = {"iri": dataset.dataset.iri}
        candidate_indexes = (
            dataset.query.ready_candidate_indexes
            or dataset.query.direct_clean_candidate_indexes
        )
        if candidate_indexes:
            arguments["candidate_index"] = candidate_indexes[0]
        return SuggestedNextAction(
            action_label="Draft query plan handoff",
            tool_name="draft_query_plan",
            mcp_tool_name="doxabase.draft_query_plan",
            arguments=arguments,
            reason=(
                "Draft a non-executed query-plan handoff for a dataset whose "
                "query context is ready for planning."
            ),
            call=self._suggested_call_string("draft_query_plan", arguments),
        )

    def _project_brief_query_plan_handoff_summary(
        self,
        action: SuggestedNextAction,
    ) -> DraftQueryPlanHandoffSummary | None:
        if action.tool_name != "draft_query_plan":
            return None
        try:
            return self.draft_query_plan(**action.arguments).handoff_summary
        except DoxaBaseError:
            return None

    @staticmethod
    def _project_brief_select_recommended_tasks(
        tasks: list[ProjectBriefRecommendedTask],
        *,
        limit: int,
    ) -> list[ProjectBriefRecommendedTask]:
        selected: list[ProjectBriefRecommendedTask] = []
        selected_indexes: set[int] = set()
        seen_task_types: set[str] = set()
        for index, task in enumerate(tasks):
            if task.task_type in seen_task_types:
                continue
            representative_index = min(
                (
                    candidate_index
                    for candidate_index, candidate in enumerate(tasks)
                    if candidate.task_type == task.task_type
                    and candidate_index not in selected_indexes
                ),
                key=lambda candidate_index: (
                    DoxaBase._project_brief_representative_rank(
                        tasks[candidate_index]
                    ),
                    candidate_index,
                ),
            )
            selected.append(tasks[representative_index])
            selected_indexes.add(representative_index)
            seen_task_types.add(task.task_type)
            if len(selected) >= limit:
                return selected
        for index, task in enumerate(tasks):
            if index in selected_indexes:
                continue
            selected.append(task)
            if len(selected) >= limit:
                break
        return selected

    @staticmethod
    def _project_brief_representative_rank(
        task: ProjectBriefRecommendedTask,
    ) -> int:
        if task.pending_staged_repair_iris or task.pending_staged_profile_update_iris:
            return 0
        return 1

    @staticmethod
    def _project_brief_task_type_counts(
        tasks: list[ProjectBriefRecommendedTask],
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for task in tasks:
            counts[task.task_type] = counts.get(task.task_type, 0) + 1
        return counts

    @staticmethod
    def _project_brief_limit_crowded_queue_types(
        queue_counts: dict[str, int],
        returned_queue_counts: dict[str, int],
        *,
        limit: int,
    ) -> list[str]:
        if len(queue_counts) <= limit:
            return []
        return [
            task_type
            for task_type in queue_counts
            if returned_queue_counts.get(task_type, 0) == 0
        ]

    @staticmethod
    def _project_brief_profile_queue_counts(
        datasets: list[ProjectBriefDatasetSummary],
    ) -> dict[str, int]:
        drafts = [
            draft
            for dataset in datasets
            for draft in dataset.profile.drafts
        ]
        return {
            "profile_observations": sum(
                dataset.profile.total_profile_count for dataset in datasets
            ),
            "profile_evidence": sum(
                dataset.profile.profile_evidence_count for dataset in datasets
            ),
            "profile_run_candidates": sum(
                dataset.profile.profile_run_candidate_count
                for dataset in datasets
            ),
            "profile_draft_candidates": sum(
                dataset.profile.draft_candidate_count
                for dataset in datasets
            ),
            "profile_candidate_omitted": sum(
                dataset.profile.profile_candidate_omitted_count
                for dataset in datasets
            ),
            "profile_drafts": len(drafts),
            "profile_draft_recommendations": sum(
                draft.recommendation_count for draft in drafts
            ),
            "profile_scalar_conflict_groups": sum(
                draft.scalar_conflict_group_count for draft in drafts
            ),
            "profile_metric_advisories": sum(
                draft.metric_advisory_count for draft in drafts
            ),
            "profile_type_advisories": sum(
                draft.type_advisory_count for draft in drafts
            ),
        }

    def _project_brief_pending_staged_repair_iris(
        self,
        dataset_iri: str,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> list[str]:
        query_repair_anchor_iris = self._dataset_query_repair_anchor_iris(
            dataset_iri
        )
        ignored_queues = {
            None,
            "informational",
            "inspect_already_applied",
        }
        return [
            item.revision_iri
            for item in staged_review.items
            if item.suggested_next_action is not None
            and item.queue not in ignored_queues
            and query_repair_anchor_iris & set(item.revision_anchor_iris)
            and self._project_brief_staged_item_is_query_repair(item)
        ]

    def _dataset_query_repair_anchor_iris(
        self,
        dataset_iri: str,
        dataset: DatasetDescription | None = None,
    ) -> set[str]:
        if dataset is None:
            try:
                dataset = self.describe_dataset(dataset_iri)
            except DoxaBaseError:
                return {self.expand_iri(dataset_iri)}
        anchors = {self.expand_iri(dataset.iri)}
        anchors.update(access.iri for access in dataset.storage_accesses)
        anchors.update(layout.iri for layout in dataset.physical_layouts)
        anchors.update(partition.iri for partition in dataset.partition_schemes)
        anchors.update(column.iri for column in dataset.columns)
        for partition in dataset.partition_schemes:
            anchors.update(column.iri for column in partition.partition_columns)
        return anchors

    def _project_brief_staged_item_is_query_repair(
        self,
        item: ProjectBriefStagedReviewItem,
    ) -> bool:
        history_graphs = self._expand_graphs(["history"])
        review_note = self._first_object(
            history_graphs,
            item.revision_iri,
            "rc:reviewNote",
        )
        if review_note and "query planning guidance" in review_note:
            return True

        query_repair_predicates = {
            self.expand_iri(predicate) for predicate in QUERY_REPAIR_PREDICATE_CURIES
        }
        try:
            staged = self.describe_staged_revision(item.revision_iri)
        except DoxaBaseError:
            return False
        for patch in staged.patches:
            if patch.target_graph != "map":
                continue
            try:
                patch_graph = self._parse_staged_patch_description(patch)
            except DoxaBaseError:
                continue
            if any(
                str(predicate) in query_repair_predicates
                for _, predicate, _ in patch_graph
            ):
                return True
        return False

    def _project_brief_pending_staged_profile_update_iris(
        self,
        dataset_iri: str,
        evidence_iri: str,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> list[str]:
        dataset_value = self.expand_iri(dataset_iri)
        evidence_value = self.expand_iri(evidence_iri)
        ignored_queues = {
            None,
            "informational",
            "inspect_already_applied",
        }
        return [
            item.revision_iri
            for item in staged_review.items
            if item.suggested_next_action is not None
            and item.queue not in ignored_queues
            and dataset_value in item.revision_anchor_iris
            and evidence_value in item.evidence_iris
            and self._project_brief_staged_item_is_profile_map_update(item)
        ]

    def _pending_staged_profile_update_iris(
        self,
        dataset_iri: str,
        evidence_iri: str,
    ) -> list[str]:
        dataset_value = self.expand_iri(dataset_iri)
        evidence_value = self.expand_iri(evidence_iri)
        listing = self.list_graph_revisions(
            current_staged_work_only=True,
            include_apply_checks=True,
            limit=200,
        )
        if listing.count > listing.returned_count:
            listing = self.list_graph_revisions(
                current_staged_work_only=True,
                include_apply_checks=True,
                limit=listing.count,
            )
        queue_by_row = {
            item.row_iri: item for item in listing.next_action_queue_items
        }
        ignored_queues = {
            None,
            "informational",
            "inspect_already_applied",
        }
        pending: list[str] = []
        for revision in listing.revisions:
            queue_item = queue_by_row.get(revision.iri)
            queue = (
                queue_item.queue
                if queue_item is not None
                else revision.next_action.queue
                if revision.next_action is not None
                else None
            )
            if queue in ignored_queues:
                continue
            if not revision.suggested_next_actions and queue_item is None:
                continue
            if dataset_value not in self._objects(
                ["history"],
                revision.iri,
                "rc:revisionAnchor",
            ):
                continue
            if evidence_value not in self._objects(
                ["history"],
                revision.iri,
                "rc:evidence",
            ):
                continue
            if not self._staged_revision_is_profile_map_update(revision.iri):
                continue
            pending.append(revision.iri)
        return pending

    def _project_brief_staged_item_is_profile_map_update(
        self,
        item: ProjectBriefStagedReviewItem,
    ) -> bool:
        return self._staged_revision_is_profile_map_update(item.revision_iri)

    def _staged_revision_is_profile_map_update(
        self,
        revision_iri: str,
    ) -> bool:
        review_note = self._first_object(
            self._expand_graphs(["history"]),
            revision_iri,
            "rc:reviewNote",
        )
        return bool(
            review_note
            and review_note.startswith("Generated by stage_profile_map_updates.")
        )

    def _project_brief_staged_tasks(
        self,
        staged_review: ProjectBriefStagedReviewSummary,
    ) -> list[ProjectBriefRecommendedTask]:
        tasks: list[ProjectBriefRecommendedTask] = []
        for item in staged_review.items:
            if item.suggested_next_action is None:
                continue
            tasks.append(
                ProjectBriefRecommendedTask(
                    priority=8,
                    task_type="staged_review",
                    source="list_graph_revisions",
                    resource=ResourceSummary(
                        iri=item.revision_iri,
                        label=item.summary,
                        description=None,
                    ),
                    reason=(
                        "Current staged work has a review, repair, restage, "
                        "or apply follow-up."
                    ),
                    suggested_next_action=item.suggested_next_action,
                    suggested_next_call=item.suggested_next_action.call,
                )
            )
        return tasks

    def _project_brief_draft_profile_action(
        self,
        dataset_iri: str,
        evidence_iri: str,
    ) -> SuggestedNextAction:
        arguments = {
            "dataset_iri": dataset_iri,
            "evidence_iri": evidence_iri,
        }
        return SuggestedNextAction(
            action_label="Review profile map updates",
            tool_name="draft_profile_map_updates",
            mcp_tool_name="doxabase.draft_profile_map_updates",
            arguments=arguments,
            reason="Review profile-derived map updates and advisory lanes.",
            call=self._suggested_call_string(
                "draft_profile_map_updates",
                arguments,
            ),
        )

    def list_entities(
        self,
        type: str | None = None,
        graph: str | None = "map",
        text: str | None = None,
        limit: int = 100,
        offset: int = 0,
    ) -> EntityList:
        graphs = self._expand_graphs([graph] if graph else None)
        params: list[Any] = []
        graph_filter = ""
        if graphs:
            graph_filter = f"AND q.graph IN ({','.join('?' for _ in graphs)})"
            params.extend(graphs)

        type_filter = ""
        if type:
            type_filter = """
                AND EXISTS (
                    SELECT 1
                    FROM quads qt
                    WHERE qt.graph = q.graph
                      AND qt.subject = q.subject
                      AND qt.predicate = ?
                      AND qt.object = ?
                )
            """
            params.extend([str(RDF.type), self.expand_iri(type)])

        text_filter = ""
        if text:
            text_filter = """
                AND (
                    lower(q.subject) LIKE ?
                    OR EXISTS (
                        SELECT 1
                        FROM quads ql
                        WHERE ql.graph = q.graph
                          AND ql.subject = q.subject
                          AND ql.object_kind IN ('literal', 'uri')
                          AND lower(ql.object) LIKE ?
                    )
                )
            """
            needle = f"%{text.lower()}%"
            params.extend([needle, needle])

        params.extend([limit, offset])
        rows = self._conn.execute(
            f"""
            SELECT q.graph, q.subject
            FROM quads q
            WHERE q.subject_kind IN ('uri', 'bnode')
              {graph_filter}
              {type_filter}
              {text_filter}
            GROUP BY q.graph, q.subject
            ORDER BY q.subject
            LIMIT ? OFFSET ?
            """,
            params,
        ).fetchall()

        entities = [
            EntityRow(
                iri=row["subject"],
                label=self._display_label_from_graphs(
                    self._lookup_graphs([row["graph"]]),
                    row["subject"],
                ),
                types=self._types(row["graph"], row["subject"]),
                graph=row["graph"],
            )
            for row in rows
        ]
        return EntityList(entities=entities, limit=limit, offset=offset)

    def describe_resource(
        self,
        iri: str,
        *,
        graph: str | None = None,
        include_incoming: bool = True,
        limit: int = 100,
        outgoing_offset: int = 0,
        incoming_offset: int = 0,
        include_blank_node_closure: bool = False,
        blank_node_depth: int = 2,
        blank_node_limit: int = 100,
    ) -> ResourceContext:
        if limit < 1:
            raise DoxaBaseError("Resource context limit must be at least 1")
        if outgoing_offset < 0:
            raise DoxaBaseError("outgoing_offset must be non-negative")
        if incoming_offset < 0:
            raise DoxaBaseError("incoming_offset must be non-negative")
        if blank_node_depth < 0:
            raise DoxaBaseError("blank_node_depth must be non-negative")
        if blank_node_limit < 1:
            raise DoxaBaseError("blank_node_limit must be at least 1")
        resource_iri = self.expand_iri(iri)
        graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(graphs)
        types = self._types_from_graphs(graphs, resource_iri)
        claim = (
            self._describe_claim(resource_iri, graphs, lookup_graphs)
            if self.expand_iri("rc:Claim") in types
            else None
        )
        outgoing_total_count = self._resource_triple_count(
            graphs,
            subject=resource_iri,
        )
        incoming_total_count = (
            self._resource_triple_count(
                graphs,
                object_value=resource_iri,
                object_kind="uri",
            )
            if include_incoming
            else 0
        )
        outgoing = self._resource_triples(
            graphs,
            subject=resource_iri,
            limit=limit,
            offset=outgoing_offset,
        )
        incoming = (
            self._resource_triples(
                graphs,
                object_value=resource_iri,
                object_kind="uri",
                limit=limit,
                offset=incoming_offset,
            )
            if include_incoming
            else []
        )
        blank_node_triples: list[ResourceTriple] = []
        blank_node_total_count = 0
        blank_node_depth_exhausted = False
        blank_node_unvisited_count = 0
        if include_blank_node_closure:
            (
                blank_node_triples,
                blank_node_total_count,
                blank_node_depth_exhausted,
                blank_node_unvisited_count,
            ) = self._resource_blank_node_closure(
                graphs,
                subject=resource_iri,
                max_depth=blank_node_depth,
                limit=blank_node_limit,
            )
        return ResourceContext(
            iri=resource_iri,
            graph=graph,
            label=self._display_label_from_graphs(lookup_graphs, resource_iri),
            description=self._description_from_graphs(lookup_graphs, resource_iri),
            types=types,
            claim=claim,
            outgoing=outgoing,
            incoming=incoming,
            blank_node_triples=blank_node_triples,
            limit=limit,
            outgoing_offset=outgoing_offset,
            incoming_offset=incoming_offset,
            outgoing_total_count=outgoing_total_count,
            outgoing_returned_count=len(outgoing),
            outgoing_omitted_count=max(
                outgoing_total_count - outgoing_offset - len(outgoing),
                0,
            ),
            incoming_total_count=incoming_total_count,
            incoming_returned_count=len(incoming),
            incoming_omitted_count=max(
                incoming_total_count - incoming_offset - len(incoming),
                0,
            ),
            include_blank_node_closure=include_blank_node_closure,
            blank_node_depth=blank_node_depth,
            blank_node_limit=blank_node_limit,
            blank_node_total_count=blank_node_total_count,
            blank_node_returned_count=len(blank_node_triples),
            blank_node_omitted_count=max(
                blank_node_total_count - len(blank_node_triples),
                0,
            ),
            blank_node_depth_exhausted=blank_node_depth_exhausted,
            blank_node_unvisited_count=blank_node_unvisited_count,
        )

    def describe_assertion_support(
        self,
        subject: str,
        predicate: str,
        object: str | None = None,
        *,
        graph: str | None = "map",
        object_kind: TypingLiteral["auto", "iri", "uri", "literal"] = "auto",
        object_datatype: str | None = None,
        object_lang: str | None = None,
        limit: int = 20,
    ) -> AssertionSupportDescription:
        if limit < 1:
            raise DoxaBaseError("Assertion support limit must be at least 1")
        subject_iri = self.expand_iri(subject)
        predicate_iri = self.expand_iri(predicate)
        graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(self._expand_graphs(["all"]))
        object_filter = self._assertion_object_filter(
            object,
            object_kind,
            object_datatype=object_datatype,
            object_lang=object_lang,
        )
        matching_triples = self._assertion_triples(
            graphs,
            subject=subject_iri,
            predicate=predicate_iri,
            object_filter=object_filter,
            limit=limit,
        )
        if object_filter is not None and not matching_triples:
            matching_triples = self._assertion_compatible_literal_triples(
                graphs,
                subject=subject_iri,
                predicate=predicate_iri,
                object_filter=object_filter,
                limit=limit,
            )
        same_subject_predicate_triples = (
            self._assertion_triples(
                graphs,
                subject=subject_iri,
                predicate=predicate_iri,
                object_filter=None,
                limit=limit,
            )
            if object_filter is not None
            else matching_triples
        )
        requested_object = (
            self._assertion_value_from_filter(lookup_graphs, object_filter)
            if object_filter is not None
            else None
        )
        target_iris = self._assertion_target_iris(
            subject_iri,
            same_subject_predicate_triples,
            requested_object,
        )
        related = self._staged_revision_related_lore(target_iris)
        related_routes = self._assertion_related_lore_routes(target_iris)
        related_route_summaries = self._assertion_related_route_summaries(
            related_routes,
            subject_iri=subject_iri,
        )
        nearby_caveat_links = self._assertion_nearby_caveat_links(
            target_iris,
            lookup_graphs,
        )
        nearby_caveats = self._caveats_from_links(nearby_caveat_links)
        target_resources = self._resource_summaries(lookup_graphs, target_iris)
        subject_summary = self._resource_summary(lookup_graphs, subject_iri)
        owner_dataset = (
            self._resource_summary(lookup_graphs, subject_summary.owning_dataset_iri)
            if subject_summary.owning_dataset_iri is not None
            else None
        )
        dataset_context_iris = self._assertion_dataset_context_iris(
            lookup_graphs,
            target_resources,
        )
        nearby_context_iris = [*target_iris, *dataset_context_iris]
        nearby_context_triples = self._assertion_nearby_context_triples(
            nearby_context_iris,
            lookup_graphs,
            limit=limit,
        )
        predicate_hints = (
            self._assertion_predicate_hints(
                subject_iri,
                predicate_iri,
                graphs,
                lookup_graphs,
                limit=min(limit, 8),
            )
            if not same_subject_predicate_triples
            else []
        )
        context_note = (
            "Assertion support is a retrieval aid, not proof. It gathers nearby "
            "observations, claims, patterns, evidence, revisions, and caveats linked "
            "to the assertion's subject, requested object, and current object "
            "resources for the same subject/predicate. It also surfaces selected "
            "direct layout/path context facts on those resources."
        )
        support_scope_note = (
            "Exact assertion and same-subject predicate triples are read from the "
            f"{graph or 'selected'} graph selection. Lore is gathered for the subject, "
            "the requested object when supplied, and any current object resources "
            "for the same subject/predicate. Column targets also pull caveats from "
            "their owning dataset, but owner-dataset observations, claims, patterns, "
            "evidence, and revisions only appear when directly linked through the "
            "gathered target resources. Nearby context triples are limited to direct "
            "layout/path predicates that often affect whether a map assertion is safe "
            "to use for executable planning."
        )
        if owner_dataset is not None:
            support_scope_note += (
                " The subject is a column with an owning dataset; inspect "
                "owner_dataset and the owner-seeded suggested actions for broader "
                "dataset lore."
            )
        elif dataset_context_iris:
            support_scope_note += (
                " Dataset-context suggested actions are seeded from dataset/table "
                "targets and owning datasets discovered around the assertion."
            )
        absence_note = self._assertion_absence_note(
            matching_triples,
            same_subject_predicate_triples,
            requested_object,
            predicate_hints,
        )
        has_related_lore = any(related.values())
        if not has_related_lore and (nearby_caveats or nearby_context_triples):
            context_note += (
                " No related observations, claims, patterns, evidence, or revisions "
                "were found in this scoped lookup; inspect nearby caveats/context "
                "and follow the suggested actions before treating that as a broad "
                "absence of project lore."
            )
        elif not has_related_lore:
            context_note += (
                " No linked lore, nearby caveats, or nearby layout/path context facts "
                "were found in this scoped lookup; follow the suggested actions before "
                "treating that as a broad absence of project lore."
            )
        suggested_next_actions = self._assertion_support_next_actions(
            subject_iri,
            predicate_iri,
            requested_object,
            graph=graph,
            dataset_context_iris=dataset_context_iris,
        )

        return AssertionSupportDescription(
            graph=graph,
            subject=subject_summary,
            owner_dataset=owner_dataset,
            predicate=predicate_iri,
            predicate_label=self._label_for_resource(predicate_iri),
            requested_object=requested_object,
            assertion_present=bool(matching_triples),
            matching_triples=matching_triples,
            same_subject_predicate_triples=same_subject_predicate_triples,
            target_resources=target_resources,
            nearby_caveats=nearby_caveats,
            nearby_caveat_links=nearby_caveat_links,
            nearby_context_triples=nearby_context_triples,
            related_observations=related["observations"],
            related_claims=related["claims"],
            related_patterns=related["patterns"],
            related_evidence=related["evidence"],
            related_revisions=related["revisions"],
            related_routes=related_routes,
            related_route_summaries=related_route_summaries,
            predicate_hints=predicate_hints,
            context_note=context_note,
            support_scope_note=support_scope_note,
            absence_note=absence_note,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _assertion_supporting_claim_targets_resource(
        self,
        summary: AssertionSupportRouteSummary,
        target_iris: set[str],
    ) -> bool:
        all_graphs = self._expand_graphs(["all"])
        for matched in summary.matched_resources:
            claim_targets = set(
                self._objects(all_graphs, matched.iri, "rc:claimTarget")
            )
            if claim_targets & target_iris:
                return True
        return False

    def _assertion_auto_supporting_pattern_iris(
        self,
        support: AssertionSupportDescription,
    ) -> list[str]:
        target_iris = {resource.iri for resource in support.target_resources}
        summary_by_iri = {
            summary.resource.iri: summary
            for summary in support.related_route_summaries
            if summary.resource_kind == "pattern"
        }
        direct_route_types = {"target_resource", "pattern_target", "map_implication"}
        selected: list[str] = []
        for pattern in support.related_patterns:
            summary = summary_by_iri.get(pattern.iri)
            if summary is None:
                continue
            route_types = set(summary.route_types)
            if route_types & direct_route_types:
                selected.append(pattern.iri)
                continue
            if (
                "supporting_claim" in route_types
                and self._assertion_supporting_claim_targets_resource(
                    summary,
                    target_iris,
                )
            ):
                selected.append(pattern.iri)
        return list(dict.fromkeys(selected))

    def _prepare_map_assertion_change(
        self,
        subject: str,
        predicate: str,
        object: str | None,
        rationale: str,
        *,
        change_kind: TypingLiteral["add", "remove", "replace"] = "replace",
        graph: TypingLiteral["map"] = "map",
        object_kind: TypingLiteral["auto", "iri", "uri", "literal"] = "auto",
        object_datatype: str | None = None,
        object_lang: str | None = None,
        summary: str | None = None,
        stance: str = "rc:CandidateRevision",
        revision_type: str = "rc:StagedRevision",
        included_graphs: Iterable[str] | str | None = None,
        revision_iri: str | None = None,
        created_at: datetime | str | None = None,
        created_by: str | None = None,
        supporting_observations: Iterable[str] | str | None = None,
        supporting_claims: Iterable[str] | str | None = None,
        supporting_patterns: Iterable[str] | str | None = None,
        revision_anchors: Iterable[str] | str | None = None,
        evidence: Iterable[str] | str | None = None,
        alternative_to: str | None = None,
        restages_revision: str | None = None,
        review_note: str | None = None,
        review_recommendation: str | None = None,
        validation_scope: TypingLiteral[
            "map",
            "ontology",
            "patterns",
            "shapes",
            "all",
        ] = "all",
        limit: int = 20,
    ) -> _MapAssertionChangePrepared:
        if graph != "map":
            raise DoxaBaseError("stage_map_assertion_change currently targets map only")
        kind = change_kind.strip().lower()
        if kind not in {"add", "remove", "replace"}:
            raise DoxaBaseError("change_kind must be one of 'add', 'remove', or 'replace'")
        rationale_value = rationale.strip()
        if not rationale_value:
            raise DoxaBaseError("rationale must not be empty")
        if kind in {"add", "replace"} and object is None:
            raise DoxaBaseError(f"change_kind '{kind}' requires an object")
        self._ensure_revision_stance(self.expand_iri(stance))
        new_revision_iri = (
            self._required_iri("revision_iri", revision_iri)
            if revision_iri is not None
            else "urn:doxabase:draft-map-assertion-change"
        )
        if restages_revision is not None:
            self._validated_restage_successor_source(
                restages_revision,
                new_revision_iri=new_revision_iri,
            )

        support = self.describe_assertion_support(
            subject,
            predicate,
            object,
            graph=graph,
            object_kind=object_kind,
            object_datatype=object_datatype,
            object_lang=object_lang,
            limit=limit,
        )
        subject_iri = support.subject.iri
        predicate_iri = support.predicate
        object_filter = self._assertion_object_filter(
            object,
            object_kind,
            object_datatype=object_datatype,
            object_lang=object_lang,
        )
        requested_node = (
            self._node_from_object_filter(object_filter)
            if object_filter is not None
            else None
        )

        addition_triples: list[tuple[Identifier, URIRef, Node]] = []
        removal_triples: list[ResourceTriple] = []
        if kind == "add":
            if support.assertion_present:
                raise DoxaBaseError(
                    "Exact assertion is already present; no add patch was staged"
                )
            if requested_node is None:
                raise DoxaBaseError("Internal assertion add missing object node")
            addition_triples.append((URIRef(subject_iri), URIRef(predicate_iri), requested_node))
        elif kind == "remove":
            removal_triples = (
                support.matching_triples
                if object_filter is not None
                else support.same_subject_predicate_triples
            )
            if not removal_triples:
                raise DoxaBaseError(
                    "No matching current assertion triples were found to remove"
                )
        else:
            removal_triples = [
                triple
                for triple in support.same_subject_predicate_triples
                if object_filter is None
                or not self._resource_triple_matches_filter(triple, object_filter)
            ]
            if requested_node is None:
                raise DoxaBaseError("Internal assertion replace missing object node")
            if not removal_triples and support.assertion_present:
                raise DoxaBaseError(
                    "Exact assertion is already the only current value; no replace patch was staged"
                )
            addition_triples.append((URIRef(subject_iri), URIRef(predicate_iri), requested_node))

        additions = (
            [
                {
                    "graph": graph,
                    "content": self._patch_content_from_triples(addition_triples),
                }
            ]
            if addition_triples
            else []
        )
        removals = (
            [
                {
                    "graph": graph,
                    "content": self._patch_content_from_resource_triples(removal_triples),
                }
            ]
            if removal_triples
            else []
        )
        summary_value = summary or self._map_assertion_change_summary(
            kind,
            support,
        )
        merged_review_note = self._map_assertion_change_review_note(
            support,
            change_kind=kind,
            user_review_note=review_note,
        )
        recommendation = review_recommendation or (
            "Review assertion support, caveat scopes, route summaries, and impact "
            "entries before applying this staged map assertion change."
        )
        anchors = self._merge_iri_values(
            revision_anchors,
            self._assertion_revision_anchors(support),
        )
        supporting_observation_values = self._merge_iri_values(
            supporting_observations,
            [item.iri for item in support.related_observations],
        )
        supporting_claim_values = self._merge_iri_values(
            supporting_claims,
            [item.iri for item in support.related_claims],
        )
        supporting_pattern_values = self._merge_iri_values(
            supporting_patterns,
            self._assertion_auto_supporting_pattern_iris(support),
        )
        evidence_values = self._merge_iri_values(
            evidence,
            [item.iri for item in support.related_evidence],
        )
        object_value = (
            support.requested_object.value
            if support.requested_object is not None
            else None
        )
        resolved_object_kind = (
            support.requested_object.value_kind
            if support.requested_object is not None
            else object_kind
        )
        resolved_object_datatype = (
            support.requested_object.datatype
            if support.requested_object is not None
            else None
        )
        resolved_object_lang = (
            support.requested_object.lang
            if support.requested_object is not None
            else None
        )
        stage_arguments = self._map_assertion_change_stage_arguments(
            subject=subject_iri,
            predicate=predicate_iri,
            object_value=object_value,
            rationale=rationale_value,
            change_kind=kind,
            graph=graph,
            object_kind=object_kind,
            object_datatype=resolved_object_datatype,
            object_lang=resolved_object_lang,
            summary=summary_value,
            stance=stance,
            revision_type=revision_type,
            included_graphs=included_graphs,
            revision_iri=revision_iri,
            created_at=created_at,
            created_by=created_by,
            supporting_observations=supporting_observation_values,
            supporting_claims=supporting_claim_values,
            supporting_patterns=supporting_pattern_values,
            revision_anchors=anchors,
            evidence=evidence_values,
            alternative_to=alternative_to,
            restages_revision=restages_revision,
            review_note=review_note,
            review_recommendation=review_recommendation,
            validation_scope=validation_scope,
            limit=limit,
        )

        return _MapAssertionChangePrepared(
            change_kind=kind,
            graph=graph,
            subject=subject_iri,
            predicate=predicate_iri,
            object_value=object_value,
            object_kind=resolved_object_kind,
            object_datatype=resolved_object_datatype,
            object_lang=resolved_object_lang,
            rationale=rationale_value,
            additions=additions,
            removals=removals,
            summary=summary_value,
            review_note=merged_review_note,
            review_recommendation=recommendation,
            assertion_support=support,
            assertion_present_before=support.assertion_present,
            current_values_before=support.same_subject_predicate_triples,
            supporting_observations=supporting_observation_values,
            supporting_claims=supporting_claim_values,
            supporting_patterns=supporting_pattern_values,
            revision_anchors=anchors,
            evidence=evidence_values,
            stage_arguments=stage_arguments,
        )

    def _map_assertion_change_stage_arguments(
        self,
        *,
        subject: str,
        predicate: str,
        object_value: str | None,
        rationale: str,
        change_kind: str,
        graph: str,
        object_kind: str,
        object_datatype: str | None,
        object_lang: str | None,
        summary: str,
        stance: str,
        revision_type: str,
        included_graphs: Iterable[str] | str | None,
        revision_iri: str | None,
        created_at: datetime | str | None,
        created_by: str | None,
        supporting_observations: list[str],
        supporting_claims: list[str],
        supporting_patterns: list[str],
        revision_anchors: list[str],
        evidence: list[str],
        alternative_to: str | None,
        restages_revision: str | None,
        review_note: str | None,
        review_recommendation: str | None,
        validation_scope: str,
        limit: int,
    ) -> dict[str, Any]:
        arguments: dict[str, Any] = {
            "subject": subject,
            "predicate": predicate,
            "object": object_value,
            "rationale": rationale,
            "change_kind": change_kind,
            "graph": graph,
            "object_kind": object_kind,
            "summary": summary,
            "validation_scope": validation_scope,
        }
        if object_datatype is not None:
            arguments["object_datatype"] = object_datatype
        if object_lang is not None:
            arguments["object_lang"] = object_lang
        if stance != "rc:CandidateRevision":
            arguments["stance"] = stance
        if revision_type != "rc:StagedRevision":
            arguments["revision_type"] = revision_type
        if included_graphs is not None:
            arguments["included_graphs"] = self._string_values(
                "included_graphs",
                included_graphs,
            )
        if revision_iri is not None:
            arguments["revision_iri"] = revision_iri
        if created_at is not None:
            arguments["created_at"] = (
                created_at.isoformat() if isinstance(created_at, datetime) else created_at
            )
        if created_by is not None:
            arguments["created_by"] = created_by
        if supporting_observations:
            arguments["supporting_observations"] = supporting_observations
        if supporting_claims:
            arguments["supporting_claims"] = supporting_claims
        if supporting_patterns:
            arguments["supporting_patterns"] = supporting_patterns
        if revision_anchors:
            arguments["revision_anchors"] = revision_anchors
        if evidence:
            arguments["evidence"] = evidence
        if alternative_to is not None:
            arguments["alternative_to"] = alternative_to
        if restages_revision is not None:
            arguments["restages_revision"] = restages_revision
        if review_note is not None:
            arguments["review_note"] = review_note
        if review_recommendation is not None:
            arguments["review_recommendation"] = review_recommendation
        if limit != 20:
            arguments["limit"] = limit
        return arguments

    def draft_map_assertion_change(
        self,
        subject: str,
        predicate: str,
        object: str | None,
        rationale: str,
        *,
        change_kind: TypingLiteral["add", "remove", "replace"] = "replace",
        graph: TypingLiteral["map"] = "map",
        object_kind: TypingLiteral["auto", "iri", "uri", "literal"] = "auto",
        object_datatype: str | None = None,
        object_lang: str | None = None,
        summary: str | None = None,
        stance: str = "rc:CandidateRevision",
        revision_type: str = "rc:StagedRevision",
        included_graphs: Iterable[str] | str | None = None,
        revision_iri: str | None = None,
        created_at: datetime | str | None = None,
        created_by: str | None = None,
        supporting_observations: Iterable[str] | str | None = None,
        supporting_claims: Iterable[str] | str | None = None,
        supporting_patterns: Iterable[str] | str | None = None,
        revision_anchors: Iterable[str] | str | None = None,
        evidence: Iterable[str] | str | None = None,
        alternative_to: str | None = None,
        restages_revision: str | None = None,
        review_note: str | None = None,
        review_recommendation: str | None = None,
        validation_scope: TypingLiteral[
            "map",
            "ontology",
            "patterns",
            "shapes",
            "all",
        ] = "all",
        limit: int = 20,
    ) -> DraftMapAssertionChangeRecord:
        prepared = self._prepare_map_assertion_change(
            subject=subject,
            predicate=predicate,
            object=object,
            rationale=rationale,
            change_kind=change_kind,
            graph=graph,
            object_kind=object_kind,
            object_datatype=object_datatype,
            object_lang=object_lang,
            summary=summary,
            stance=stance,
            revision_type=revision_type,
            included_graphs=included_graphs,
            revision_iri=revision_iri,
            created_at=created_at,
            created_by=created_by,
            supporting_observations=supporting_observations,
            supporting_claims=supporting_claims,
            supporting_patterns=supporting_patterns,
            revision_anchors=revision_anchors,
            evidence=evidence,
            alternative_to=alternative_to,
            restages_revision=restages_revision,
            review_note=review_note,
            review_recommendation=review_recommendation,
            validation_scope=validation_scope,
            limit=limit,
        )
        parsed_patches = self._parse_staged_patch_specs(
            additions=prepared.additions,
            removals=prepared.removals,
        )
        preview = self._preview_staged_graph_patches(
            parsed_patches,
            validation_scope=validation_scope,
            revision_has_support_metadata=bool(
                prepared.supporting_observations
                or prepared.supporting_claims
                or prepared.supporting_patterns
                or prepared.evidence
            ),
        )
        impacts = self._staged_revision_impacts(
            revision_iri="urn:doxabase:draft-map-assertion-change",
            patches=preview.patch_descriptions,
            lookup_graphs=self._lookup_graphs(self._expand_graphs(["all"])),
        )
        judgement_panel = self._map_assertion_change_judgement_panel(
            prepared.assertion_support,
            change_kind=prepared.change_kind,
            recommendation=prepared.review_recommendation,
            impacts=impacts,
        )
        suggested_next_actions = self._draft_map_assertion_change_next_actions(
            prepared,
            judgement_panel,
            limit=limit,
        )
        return DraftMapAssertionChangeRecord(
            result_kind="draft_map_assertion_change",
            change_kind=prepared.change_kind,
            graph=prepared.graph,
            subject=prepared.subject,
            predicate=prepared.predicate,
            object_value=prepared.object_value,
            object_kind=prepared.object_kind,
            object_datatype=prepared.object_datatype,
            object_lang=prepared.object_lang,
            assertion_present_before=prepared.assertion_present_before,
            current_values_before=prepared.current_values_before,
            additions=prepared.additions,
            removals=prepared.removals,
            changed_graphs=preview.changed_graphs,
            patches=preview.patch_descriptions,
            impacts=impacts,
            validation_scope=preview.validation.scope,
            validation_conforms=preview.validation.conforms,
            validation_result_count=preview.validation.result_count,
            validation_results=preview.validation.results,
            validation_report_text=preview.validation.report_text,
            assertion_support=prepared.assertion_support,
            judgement_panel=judgement_panel,
            review_note=prepared.review_note,
            review_recommendation=prepared.review_recommendation,
            stage_arguments=prepared.stage_arguments,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[action.call for action in suggested_next_actions],
        )

    def _draft_map_assertion_change_next_actions(
        self,
        prepared: _MapAssertionChangePrepared,
        judgement_panel: MapAssertionJudgementPanel,
        *,
        limit: int,
    ) -> list[SuggestedNextAction]:
        stage_action = SuggestedNextAction(
            action_label="Stage map assertion change",
            tool_name="stage_map_assertion_change",
            mcp_tool_name="doxabase.stage_map_assertion_change",
            arguments=prepared.stage_arguments,
            reason=(
                "Stage this reviewed map assertion change only after the draft "
                "support, impacts, validation preview, and judgement panel still "
                "justify the write."
            ),
            call=self._suggested_call_string(
                "stage_map_assertion_change",
                prepared.stage_arguments,
            ),
        )
        if not self._draft_map_assertion_change_requires_support_review(
            judgement_panel
        ):
            return [stage_action]

        review_arguments = self._draft_assertion_support_review_arguments(
            prepared,
            limit=limit,
        )
        review_action = SuggestedNextAction(
            action_label="Review assertion support before staging",
            tool_name="describe_assertion_support",
            mcp_tool_name="doxabase.describe_assertion_support",
            arguments=review_arguments,
            reason=(
                "This draft is high-risk or marked do-not-stage; inspect support "
                "routes, caveat scopes, and current-value rationale before any "
                "write. Mechanical validation means the patch can replay, not that "
                "the semantic change is good."
            ),
            call=self._suggested_call_string(
                "describe_assertion_support",
                review_arguments,
            ),
        )
        override_stage_action = replace(
            stage_action,
            action_label="Stage map assertion change after explicit override",
            reason=(
                "Override the draft review warning only after explicitly deciding "
                "the high-risk or do-not-stage judgement is outweighed by current "
                "project evidence."
            ),
        )
        return [review_action, override_stage_action]

    @staticmethod
    def _draft_map_assertion_change_requires_support_review(
        judgement_panel: MapAssertionJudgementPanel,
    ) -> bool:
        recommendation = (judgement_panel.recommendation or "").strip().lower()
        return judgement_panel.semantic_risk_level == "high" or recommendation in {
            "do_not_stage",
            "do-not-stage",
            "do not stage",
        }

    def _draft_assertion_support_review_arguments(
        self,
        prepared: _MapAssertionChangePrepared,
        *,
        limit: int,
    ) -> dict[str, Any]:
        arguments: dict[str, Any] = {
            "subject": prepared.subject,
            "predicate": prepared.predicate,
            "graph": prepared.graph,
        }
        if prepared.object_value is not None:
            arguments["object"] = prepared.object_value
            arguments["object_kind"] = prepared.stage_arguments.get(
                "object_kind",
                "auto",
            )
            if prepared.object_datatype is not None:
                arguments["object_datatype"] = prepared.object_datatype
            if prepared.object_lang is not None:
                arguments["object_lang"] = prepared.object_lang
        if limit != 20:
            arguments["limit"] = limit
        return arguments

    def stage_map_assertion_change(
        self,
        subject: str,
        predicate: str,
        object: str | None,
        rationale: str,
        *,
        change_kind: TypingLiteral["add", "remove", "replace"] = "replace",
        graph: TypingLiteral["map"] = "map",
        object_kind: TypingLiteral["auto", "iri", "uri", "literal"] = "auto",
        object_datatype: str | None = None,
        object_lang: str | None = None,
        summary: str | None = None,
        stance: str = "rc:CandidateRevision",
        revision_type: str = "rc:StagedRevision",
        included_graphs: Iterable[str] | str | None = None,
        revision_iri: str | None = None,
        created_at: datetime | str | None = None,
        created_by: str | None = None,
        supporting_observations: Iterable[str] | str | None = None,
        supporting_claims: Iterable[str] | str | None = None,
        supporting_patterns: Iterable[str] | str | None = None,
        revision_anchors: Iterable[str] | str | None = None,
        evidence: Iterable[str] | str | None = None,
        alternative_to: str | None = None,
        restages_revision: str | None = None,
        review_note: str | None = None,
        review_recommendation: str | None = None,
        profile_route_sources: Iterable[Mapping[str, Any]]
        | Mapping[str, Any]
        | None = None,
        validation_scope: TypingLiteral[
            "map",
            "ontology",
            "patterns",
            "shapes",
            "all",
        ] = "all",
        limit: int = 20,
    ) -> StagedMapAssertionChangeRecord:
        profile_route_source_values = self._explicit_profile_route_sources(
            profile_route_sources
        )
        prepared = self._prepare_map_assertion_change(
            subject=subject,
            predicate=predicate,
            object=object,
            rationale=rationale,
            change_kind=change_kind,
            graph=graph,
            object_kind=object_kind,
            object_datatype=object_datatype,
            object_lang=object_lang,
            summary=summary,
            stance=stance,
            revision_type=revision_type,
            included_graphs=included_graphs,
            revision_iri=revision_iri,
            created_at=created_at,
            created_by=created_by,
            supporting_observations=supporting_observations,
            supporting_claims=supporting_claims,
            supporting_patterns=supporting_patterns,
            revision_anchors=revision_anchors,
            evidence=evidence,
            alternative_to=alternative_to,
            restages_revision=restages_revision,
            review_note=review_note,
            review_recommendation=review_recommendation,
            validation_scope=validation_scope,
            limit=limit,
        )
        staged = self.stage_graph_revision(
            summary=prepared.summary,
            rationale=prepared.rationale,
            additions=prepared.additions,
            removals=prepared.removals,
            stance=stance,
            revision_type=revision_type,
            included_graphs=included_graphs,
            revision_iri=revision_iri,
            created_at=created_at,
            created_by=created_by,
            supporting_observations=prepared.supporting_observations,
            supporting_claims=prepared.supporting_claims,
            supporting_patterns=prepared.supporting_patterns,
            revision_anchors=prepared.revision_anchors,
            evidence=prepared.evidence,
            alternative_to=alternative_to,
            restages_revision=restages_revision,
            review_note=prepared.review_note,
            review_recommendation=prepared.review_recommendation,
            validation_scope=validation_scope,
        )
        extra_route_source_triples = self._record_profile_insight_route_sources(
            staged.revision_iri,
            profile_route_source_values,
        )
        if extra_route_source_triples:
            staged = replace(
                staged,
                triples=staged.triples + extra_route_source_triples,
            )
        staged_description = self.describe_staged_revision(staged.revision_iri)
        judgement_panel = self._map_assertion_change_judgement_panel(
            prepared.assertion_support,
            change_kind=prepared.change_kind,
            recommendation=prepared.review_recommendation,
            impacts=staged_description.impacts,
        )
        return StagedMapAssertionChangeRecord(
            revision_iri=staged.revision_iri,
            change_kind=prepared.change_kind,
            graph=prepared.graph,
            subject=prepared.subject,
            predicate=prepared.predicate,
            object_value=prepared.object_value,
            object_kind=prepared.object_kind,
            object_datatype=prepared.object_datatype,
            object_lang=prepared.object_lang,
            assertion_present_before=prepared.assertion_present_before,
            current_values_before=prepared.current_values_before,
            additions=prepared.additions,
            removals=prepared.removals,
            assertion_support=prepared.assertion_support,
            staged_revision=staged,
            judgement_panel=judgement_panel,
            review_note=prepared.review_note,
            review_recommendation=prepared.review_recommendation,
            profile_route_source_count=len(profile_route_source_values),
        )

    def describe_graph_revision(
        self,
        iri: str,
        *,
        graph: str | None = "history",
    ) -> GraphRevisionDescription:
        revision_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(data_graphs)
        if not self._subject_exists(revision_iri, data_graphs):
            graph_label = graph if graph is not None else "all graphs"
            hint = self._missing_revision_snapshot_storage_hint(revision_iri)
            raise DoxaBaseError(
                f"Graph revision '{iri}' was not found in {graph_label}{hint}"
            )
        if self.expand_iri("rc:GraphRevision") not in self._types_from_graphs(
            data_graphs,
            revision_iri,
        ):
            raise DoxaBaseError(f"Resource '{iri}' is not an rc:GraphRevision")

        revision_type = self._first_object(data_graphs, revision_iri, "rc:revisionType")
        all_lookup_graphs = self._lookup_graphs(self._expand_graphs(["all"]))
        snapshots = self._graph_revision_snapshots(revision_iri, data_graphs)
        included_graphs = self._objects(data_graphs, revision_iri, "rc:includedGraph")
        if not included_graphs:
            included_graphs = [snapshot.graph_role for snapshot in snapshots]
        applies_staged_revision = self._first_object(
            data_graphs,
            revision_iri,
            "rc:appliesStagedRevision",
        )
        resolves_staged_revision = self._first_object(
            data_graphs,
            revision_iri,
            "rc:resolvesStagedRevision",
        )
        staged_review_decision = self._first_object(
            data_graphs,
            revision_iri,
            "rc:stagedRevisionReviewDecision",
        )
        patch_iris = self._objects(data_graphs, revision_iri, "rc:hasGraphPatch")
        patches = [
            self._describe_staged_graph_patch(patch_iri, data_graphs)
            for patch_iri in patch_iris
        ]
        patches.sort(key=self._staged_patch_sort_key)
        record_kind = self._graph_revision_record_kind(
            revision_type,
            has_patch_payload=bool(patch_iris),
            applies_staged_revision=applies_staged_revision,
        )
        snapshot_evidence = self._revision_snapshot_evidence_status(
            revision_iri,
            data_graphs,
        )
        suggested_next_actions = (
            self._applied_revision_event_suggested_actions(revision_iri)
            if applies_staged_revision is not None
            else []
        )
        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            suggested_next_actions,
            snapshot_evidence,
        )

        return GraphRevisionDescription(
            iri=revision_iri,
            graph=graph,
            label=self._display_label_from_graphs(lookup_graphs, revision_iri),
            summary=self._first_object(data_graphs, revision_iri, "rc:summary"),
            record_kind=record_kind,
            revision_type=revision_type,
            revision_type_label=(
                self._label_from_graphs(self._expand_graphs(["ontology"]), revision_type)
                if revision_type is not None
                else None
            ),
            rationale=self._first_object(data_graphs, revision_iri, "rc:revisionRationale"),
            changed_graphs=self._objects(data_graphs, revision_iri, "rc:changedGraph"),
            included_graphs=included_graphs,
            created_at=self._first_object(data_graphs, revision_iri, "rc:createdAt"),
            created_by=self._first_object(data_graphs, revision_iri, "rc:createdBy"),
            export_path=self._first_object(data_graphs, revision_iri, "rc:exportPath"),
            applies_staged_revision=applies_staged_revision,
            resolves_staged_revision=resolves_staged_revision,
            staged_review_decision=staged_review_decision,
            staged_review_decision_label=self._label_for_resource(
                staged_review_decision
            ),
            applied_source=(
                self._applied_staged_revision_source_summary(
                    applies_staged_revision
                )
                if applies_staged_revision is not None
                else None
            ),
            validation_scope=self._first_object(
                data_graphs,
                revision_iri,
                "rc:validationScope",
            ),
            validation_conforms=self._bool_object(
                data_graphs,
                revision_iri,
                "rc:validationConforms",
            ),
            validation_result_count=self._int_object(
                data_graphs,
                revision_iri,
                "rc:validationResultCount",
            ),
            validation_results=self._graph_revision_validation_results(
                revision_iri,
                data_graphs,
                patches=patches,
            ),
            graph_snapshots=snapshots,
            snapshot_evidence=snapshot_evidence,
            supporting_observations=self._resource_summaries(
                all_lookup_graphs,
                self._objects(
                    data_graphs,
                    revision_iri,
                    "rc:revisionSupportingObservation",
                ),
            ),
            supporting_claims=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionSupportingClaim"),
            ),
            supporting_patterns=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionSupportingPattern"),
            ),
            revision_anchors=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionAnchor"),
            ),
            evidence=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:evidence"),
            ),
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def describe_revision_snapshot_evidence(
        self,
        iri: str,
        *,
        graph: str | None = "history",
    ) -> RevisionSnapshotEvidenceStatus:
        revision_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        return self._revision_snapshot_evidence_status(revision_iri, data_graphs)

    def describe_revision_graph_snapshot(
        self,
        iri: str,
        graph_role: str,
        *,
        graph: str | None = "history",
        include_triples: bool = False,
        max_triples: int = 500,
    ) -> RevisionGraphSnapshotDescription:
        if max_triples < 1:
            raise DoxaBaseError("max_triples must be at least 1")
        if graph_role not in self._known_graph_names():
            raise DoxaBaseError(f"Unknown graph role: {graph_role}")

        revision_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        snapshot_evidence = self._revision_snapshot_evidence_status(
            revision_iri,
            data_graphs,
        )
        rdf_snapshots = {
            snapshot.graph_role: snapshot
            for snapshot in self._graph_revision_snapshots(revision_iri, data_graphs)
        }
        rdf_snapshot = rdf_snapshots.get(graph_role)
        stored_metadata = self._graph_snapshot_storage_metadata(
            revision_iri,
            graph_role,
        )

        triples: list[GraphTripleDescription] = []
        triples_included = False
        triples_truncated = False
        stored_at: str | None = None
        if stored_metadata is not None:
            triple_count = int(stored_metadata["triple_count"])
            content_digest = stored_metadata["content_digest"]
            stored_at = stored_metadata["stored_at"]
            count_basis = "stored_snapshot_rows"
            exact_snapshot_available = True
            if include_triples:
                rows = self._graph_snapshot_storage_rows(revision_iri, graph_role)
                triples_included = True
                triples_truncated = len(rows) > max_triples
                triples = [
                    self._graph_triple_description(row)
                    for row in rows[:max_triples]
                ]
                if triples_truncated:
                    note = (
                        "Exact stored snapshot rows are included up to "
                        "max_triples for this revision and graph role."
                    )
                else:
                    note = (
                        "Exact stored snapshot rows are included for this "
                        "revision and graph role."
                    )
            else:
                note = (
                    "Exact stored snapshot rows are available for this revision "
                    "and graph role; pass include_triples=True to include them."
                )
        elif rdf_snapshot is not None:
            triple_count = rdf_snapshot.triple_count
            content_digest = rdf_snapshot.content_digest
            count_basis = "rdf_history_graph_snapshot"
            exact_snapshot_available = False
            note = (
                "RDF history count/digest metadata is present for this revision "
                "and graph role, but exact stored snapshot rows are absent. "
                "Import a companion revision snapshot JSON bundle before relying "
                "on exact snapshot triples."
            )
        else:
            triple_count = None
            content_digest = None
            count_basis = "unavailable"
            exact_snapshot_available = False
            note = (
                "No RDF graph snapshot metadata or stored snapshot rows were "
                "found for this revision and graph role."
            )

        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            [],
            snapshot_evidence,
        )
        return RevisionGraphSnapshotDescription(
            revision_iri=revision_iri,
            graph_role=graph_role,
            snapshot_evidence=snapshot_evidence,
            triple_count=triple_count,
            content_digest=content_digest,
            count_basis=count_basis,
            stored_at=stored_at,
            exact_snapshot_available=exact_snapshot_available,
            include_triples=include_triples,
            triples_included=triples_included,
            triples_truncated=triples_truncated,
            max_triples=max_triples,
            triples=triples,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
            note=note,
        )

    def _revision_snapshot_evidence_status(
        self,
        revision_iri: str,
        graphs: list[str],
    ) -> RevisionSnapshotEvidenceStatus:
        history_revision_found = (
            self._subject_exists(revision_iri, graphs)
            and self.expand_iri("rc:GraphRevision")
            in self._types_from_graphs(graphs, revision_iri)
        )
        rdf_snapshot_graph_roles = [
            snapshot.graph_role
            for snapshot in self._graph_revision_snapshots(revision_iri, graphs)
        ]
        stored_snapshot_graph_roles = self._graph_snapshot_storage_graph_roles(
            revision_iri
        )
        stored_role_set = set(stored_snapshot_graph_roles)
        rdf_role_set = set(rdf_snapshot_graph_roles)
        exact_snapshot_graph_roles = [
            role for role in rdf_snapshot_graph_roles if role in stored_role_set
        ]
        missing_snapshot_row_graph_roles = [
            role for role in rdf_snapshot_graph_roles if role not in stored_role_set
        ]
        orphan_snapshot_row_graph_roles = [
            role for role in stored_snapshot_graph_roles if role not in rdf_role_set
        ]
        missing_current_graph_roles = (
            self._revision_snapshot_missing_current_graph_roles(
                revision_iri,
                exact_snapshot_graph_roles,
            )
        )

        if not history_revision_found:
            if stored_snapshot_graph_roles:
                status = "snapshot_rows_without_history"
                note = (
                    "SQLite snapshot rows exist for this revision IRI, but the "
                    "RDF history revision record is missing. Import the project "
                    "or history RDF bundle before using normal revision helpers; "
                    "workflow RDF exports do not include history."
                )
            else:
                status = "history_missing"
                note = (
                    "No RDF history revision record or SQLite snapshot rows were "
                    "found for this revision IRI."
                )
        elif not stored_snapshot_graph_roles:
            status = "history_only_count_digest"
            note = (
                "RDF history metadata and count/digest graph snapshots are "
                "present, but SQLite snapshot rows for exact changed-triple "
                "inspection are absent. Import a companion revision snapshot "
                "JSON bundle when exact applied diffs or stale drift triples are "
                "needed."
            )
        else:
            status = "history_plus_snapshot_rows"
            note = (
                "RDF history metadata and SQLite snapshot rows are present. "
                "Exact changed-triple inspection is available for graph roles "
                "listed in exact_snapshot_graph_roles."
            )
            if missing_snapshot_row_graph_roles:
                note = (
                    f"{note} Some RDF snapshot graph roles lack stored rows: "
                    f"{', '.join(missing_snapshot_row_graph_roles)}."
                )
            if orphan_snapshot_row_graph_roles:
                note = (
                    f"{note} Some stored snapshot rows have no matching RDF "
                    "snapshot metadata in the selected history graph: "
                    f"{', '.join(orphan_snapshot_row_graph_roles)}."
                )
            if missing_current_graph_roles:
                note = (
                    f"{note} Current project graph role(s) appear empty even "
                    "though imported snapshot rows for those roles are non-empty: "
                    f"{', '.join(missing_current_graph_roles)}. Import the "
                    "complete project RDF bundle before mutation recovery."
                )

        suggested_next_actions = self._revision_snapshot_evidence_next_actions(
            status=status,
            revision_iri=revision_iri,
            missing_snapshot_row_graph_roles=missing_snapshot_row_graph_roles,
            orphan_snapshot_row_graph_roles=orphan_snapshot_row_graph_roles,
            missing_current_graph_roles=missing_current_graph_roles,
        )
        return RevisionSnapshotEvidenceStatus(
            revision_iri=revision_iri,
            status=status,
            history_revision_found=history_revision_found,
            rdf_snapshot_graph_roles=rdf_snapshot_graph_roles,
            stored_snapshot_graph_roles=stored_snapshot_graph_roles,
            exact_snapshot_graph_roles=exact_snapshot_graph_roles,
            missing_snapshot_row_graph_roles=missing_snapshot_row_graph_roles,
            orphan_snapshot_row_graph_roles=orphan_snapshot_row_graph_roles,
            missing_current_graph_roles=missing_current_graph_roles,
            note=note,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _revision_snapshot_missing_current_graph_roles(
        self,
        revision_iri: str,
        exact_snapshot_graph_roles: Iterable[str],
    ) -> list[str]:
        missing_roles: list[str] = []
        for role in exact_snapshot_graph_roles:
            metadata = self._graph_snapshot_storage_metadata(revision_iri, role)
            if metadata is None or int(metadata["triple_count"]) <= 0:
                continue
            if self.triple_count(role) == 0:
                missing_roles.append(role)
        return missing_roles

    def _revision_snapshot_evidence_next_actions(
        self,
        *,
        status: str,
        revision_iri: str,
        missing_snapshot_row_graph_roles: list[str],
        orphan_snapshot_row_graph_roles: list[str],
        missing_current_graph_roles: list[str],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []

        def add_action(
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
            *,
            action_label: str,
        ) -> None:
            actions.append(
                SuggestedNextAction(
                    action_label=action_label,
                    tool_name=tool_name,
                    mcp_tool_name=f"doxabase.{tool_name}",
                    arguments=arguments,
                    reason=reason,
                    call=self._suggested_call_string(tool_name, arguments),
                )
            )

        if status == "history_only_count_digest" or missing_snapshot_row_graph_roles:
            add_action(
                "import_revision_snapshots",
                {
                    "path": "/tmp/revision-snapshots.json",
                    "path_is_placeholder": True,
                },
                (
                    "RDF history metadata is present for "
                    f"'{revision_iri}', but exact snapshot rows are missing for "
                    "one or more graph roles. Import the companion snapshot JSON "
                    "bundle at its real handoff path before relying on exact "
                    "applied-diff or stale-drift triple inspection. If the "
                    "snapshot JSON is not available, request a "
                    "recovery-complete export_handoff_bundle from the source "
                    "capsule."
                ),
                action_label="Import snapshot bundle if available",
            )
        if status == "snapshot_rows_without_history" or (
            orphan_snapshot_row_graph_roles and status != "history_plus_snapshot_rows"
        ):
            add_action(
                "import_trig",
                {"path": "/tmp/project.trig", "path_is_placeholder": True},
                (
                    "Snapshot rows exist for this revision, but the RDF history "
                    "record is missing. Import the project/history RDF bundle at "
                    "its real handoff path before using normal revision helpers."
                ),
                action_label="Import project/history RDF bundle",
            )
        if missing_current_graph_roles:
            add_action(
                "import_trig",
                {"path": "/tmp/project.trig", "path_is_placeholder": True},
                (
                    "RDF history metadata and exact snapshot rows are present "
                    f"for '{revision_iri}', but current project graph role(s) "
                    "appear empty despite non-empty stored snapshot rows: "
                    f"{', '.join(missing_current_graph_roles)}. Import the "
                    "complete project RDF bundle at its real handoff path before "
                    "planning apply, restage, or repair mutations."
                ),
                action_label="Import complete project RDF bundle",
            )
        return actions

    @staticmethod
    def _with_revision_snapshot_evidence_actions(
        actions: list[SuggestedNextAction],
        *snapshot_evidence_items: RevisionSnapshotEvidenceStatus | None,
    ) -> list[SuggestedNextAction]:
        promoted_actions: list[SuggestedNextAction] = []
        for evidence in snapshot_evidence_items:
            if evidence is None:
                continue
            promoted_actions.extend(evidence.suggested_next_actions)
        if not promoted_actions:
            return actions
        combined: list[SuggestedNextAction] = []
        seen: set[tuple[str, str | None]] = set()
        for action in [*promoted_actions, *actions]:
            key = (action.tool_name, action.call)
            if key in seen:
                continue
            seen.add(key)
            combined.append(action)
        return combined

    @staticmethod
    def _snapshot_evidence_completion_next_action(
        actions: Iterable[SuggestedNextAction],
    ) -> RevisionNextAction | None:
        for action in actions:
            if action.tool_name not in {
                "import_revision_snapshots",
                "import_trig",
            }:
                continue
            return RevisionNextAction(
                action_type="complete_handoff_import",
                queue="complete_handoff_import",
                action_label=action.action_label,
                tool_name=action.tool_name,
                mcp_tool_name=action.mcp_tool_name,
                arguments=action.arguments,
                reason=action.reason,
                call=action.call,
                source="snapshot_evidence",
            )
        return None

    def _missing_revision_snapshot_storage_hint(self, revision_iri: str) -> str:
        stored_graph_roles = self._graph_snapshot_storage_graph_roles(revision_iri)
        if not stored_graph_roles:
            return ""
        return (
            ". Snapshot rows exist for this revision IRI in graph roles "
            f"{stored_graph_roles}, but the RDF history record is missing. "
            "Import the project/history RDF bundle before using normal revision "
            "helpers; workflow RDF exports do not include history."
        )

    def describe_applied_revision_diff(
        self,
        iri: str,
        *,
        graph: str | None = "history",
        include_triples: bool = False,
        max_triples: int = 500,
    ) -> AppliedRevisionDiffDescription:
        if max_triples < 1:
            raise DoxaBaseError("max_triples must be at least 1")
        data_graphs = self._expand_graphs([graph] if graph else None)
        applied = self.describe_graph_revision(iri, graph=graph)
        staged_revision_iri = applied.applies_staged_revision
        if staged_revision_iri is None:
            raise DoxaBaseError(
                f"Graph revision '{iri}' is not an applied staged revision"
            )
        staged = self.describe_staged_revision(staged_revision_iri, graph=graph)
        before_snapshots = {
            snapshot.graph_role: snapshot for snapshot in staged.graph_snapshots
        }
        after_snapshots = {
            snapshot.graph_role: snapshot for snapshot in applied.graph_snapshots
        }
        graph_roles = list(dict.fromkeys(applied.changed_graphs))
        if not graph_roles:
            graph_roles = sorted(set(before_snapshots) | set(after_snapshots))
        snapshot_evidence = self._revision_snapshot_evidence_status(
            applied.iri,
            data_graphs,
        )
        source_snapshot_evidence = self._revision_snapshot_evidence_status(
            staged_revision_iri,
            data_graphs,
        )
        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            [],
            snapshot_evidence,
            source_snapshot_evidence,
        )

        return AppliedRevisionDiffDescription(
            applied_revision_iri=applied.iri,
            staged_revision_iri=staged_revision_iri,
            snapshot_evidence=snapshot_evidence,
            source_snapshot_evidence=source_snapshot_evidence,
            changed_graphs=graph_roles,
            include_triples=include_triples,
            max_triples=max_triples,
            graph_diffs=[
                self._applied_revision_graph_snapshot_diff(
                    graph_role=graph_role,
                    before_revision_iri=staged_revision_iri,
                    after_revision_iri=applied.iri,
                    before_snapshot=before_snapshots.get(graph_role),
                    after_snapshot=after_snapshots.get(graph_role),
                    include_triples=include_triples,
                    max_triples=max_triples,
                )
                for graph_role in graph_roles
            ],
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _applied_revision_graph_snapshot_diff(
        self,
        *,
        graph_role: str,
        before_revision_iri: str,
        after_revision_iri: str,
        before_snapshot: GraphSnapshotDescription | None,
        after_snapshot: GraphSnapshotDescription | None,
        include_triples: bool,
        max_triples: int,
    ) -> AppliedRevisionGraphSnapshotDiff:
        exact_available = self._graph_snapshot_storage_exists(
            before_revision_iri,
            graph_role,
        ) and self._graph_snapshot_storage_exists(after_revision_iri, graph_role)
        triples_added: list[GraphTripleDescription] = []
        triples_removed: list[GraphTripleDescription] = []
        triples_added_count: int | None = None
        triples_removed_count: int | None = None
        triples_added_truncated = False
        triples_removed_truncated = False
        exact_included = False
        if exact_available:
            before_rows = set(
                self._graph_snapshot_storage_rows(before_revision_iri, graph_role)
            )
            after_rows = set(
                self._graph_snapshot_storage_rows(after_revision_iri, graph_role)
            )
            added_rows = self._sort_graph_storage_rows(after_rows - before_rows)
            removed_rows = self._sort_graph_storage_rows(before_rows - after_rows)
            triples_added_count = len(added_rows)
            triples_removed_count = len(removed_rows)
            if include_triples:
                exact_included = True
                triples_added_truncated = triples_added_count > max_triples
                triples_removed_truncated = triples_removed_count > max_triples
                triples_added = [
                    self._graph_triple_description(row)
                    for row in added_rows[:max_triples]
                ]
                triples_removed = [
                    self._graph_triple_description(row)
                    for row in removed_rows[:max_triples]
                ]
                if triples_added_truncated or triples_removed_truncated:
                    note = (
                        "Exact before/after snapshot triples are available and "
                        "included up to max_triples per added/removed array."
                    )
                else:
                    note = (
                        "Exact before/after snapshot triples are included from "
                        "stored revision snapshot rows."
                    )
            else:
                triples_added_truncated = triples_added_count > 0
                triples_removed_truncated = triples_removed_count > 0
                note = (
                    "Exact before/after snapshot triples are available but "
                    "omitted; call describe_applied_revision_diff(..., "
                    "include_triples=True) to include arrays."
                )
        else:
            note = self._missing_applied_snapshot_rows_note(
                before_snapshot=before_snapshot,
                after_snapshot=after_snapshot,
            )

        return AppliedRevisionGraphSnapshotDiff(
            graph_role=graph_role,
            count_basis="target_graph_only",
            before_revision_iri=before_revision_iri,
            after_revision_iri=after_revision_iri,
            before_triple_count=(
                before_snapshot.triple_count if before_snapshot is not None else None
            ),
            after_triple_count=(
                after_snapshot.triple_count if after_snapshot is not None else None
            ),
            before_content_digest=(
                before_snapshot.content_digest if before_snapshot is not None else None
            ),
            after_content_digest=(
                after_snapshot.content_digest if after_snapshot is not None else None
            ),
            exact_changed_triples_available=exact_available,
            exact_changed_triples_included=exact_included,
            triples_added_count=triples_added_count,
            triples_removed_count=triples_removed_count,
            triples_added_truncated=triples_added_truncated,
            triples_removed_truncated=triples_removed_truncated,
            max_triples=max_triples,
            triples_added=triples_added,
            triples_removed=triples_removed,
            note=note,
        )

    @staticmethod
    def _missing_applied_snapshot_rows_note(
        *,
        before_snapshot: GraphSnapshotDescription | None,
        after_snapshot: GraphSnapshotDescription | None,
    ) -> str:
        note = (
            "Exact before/after snapshot triples are unavailable because "
            "one or both revision snapshots lack stored rows."
        )
        if before_snapshot is not None or after_snapshot is not None:
            note += (
                " If this capsule was populated from an RDF project/history "
                "handoff, import the companion JSON bundle with "
                "import_revision_snapshots(...) after import_trig(...)."
            )
        return note

    def _applied_staged_revision_source_summary(
        self,
        staged_revision_iri: str,
    ) -> AppliedStagedRevisionSourceSummary:
        source = self.describe_staged_revision(staged_revision_iri)
        return AppliedStagedRevisionSourceSummary(
            iri=source.iri,
            summary=source.summary,
            revision_type=source.revision_type,
            revision_type_label=source.revision_type_label,
            revision_stance=source.revision_stance,
            revision_stance_label=source.revision_stance_label,
            review_note=source.review_note,
            review_recommendation=source.review_recommendation,
            alternative_to=(
                source.alternative_to.iri
                if source.alternative_to is not None
                else None
            ),
            restaged_from=(
                source.restaged_from.iri
                if source.restaged_from is not None
                else None
            ),
            restaged_by=(
                source.restaged_by.iri if source.restaged_by is not None else None
            ),
            current_restaged_by=(
                source.current_restaged_by.iri
                if source.current_restaged_by is not None
                else None
            ),
            restage_reason=source.restage_reason,
            created_at=source.created_at,
            created_by=source.created_by,
            validation_scope=source.validation_scope,
            validation_conforms=source.validation_conforms,
            validation_result_count=source.validation_result_count,
            changed_graphs=source.changed_graphs,
            included_graphs=source.included_graphs,
            graph_snapshots=source.graph_snapshots,
            patch_count=len(source.patches),
            patches=[
                AppliedStagedRevisionSourcePatchSummary(
                    operation=patch.operation,
                    operation_label=patch.operation_label,
                    target_graph=patch.target_graph,
                    count_basis=patch.count_basis,
                    patch_role=patch.patch_role,
                    patch_role_label=patch.patch_role_label,
                    sequence_index=patch.sequence_index,
                    triple_count=patch.triple_count,
                    before_triple_count=patch.before_triple_count,
                    after_triple_count=patch.after_triple_count,
                )
                for patch in source.patches
            ],
            supporting_observation_count=len(source.supporting_observations),
            supporting_claim_count=len(source.supporting_claims),
            supporting_pattern_count=len(source.supporting_patterns),
            evidence_count=len(source.evidence),
            revision_anchor_count=len(source.revision_anchors),
        )

    def list_graph_revisions(
        self,
        *,
        revision_type: str | None = None,
        graph: str | None = "history",
        include_apply_checks: bool = False,
        drift_detail: TypingLiteral["summary", "exact"] = "summary",
        record_kind: str | None = None,
        application_status: str | None = None,
        staged_validation_status: str | None = None,
        stale_resolution_state: str | None = None,
        current_staged_work_only: bool = False,
        limit: int = 50,
        offset: int = 0,
    ) -> GraphRevisionList:
        if drift_detail not in {"summary", "exact"}:
            raise DoxaBaseError("drift_detail must be 'summary' or 'exact'")
        self._ensure_non_negative("limit", limit)
        self._ensure_non_negative("offset", offset)
        record_kind_filter = record_kind
        application_status_filter = application_status
        staged_validation_status_filter = staged_validation_status
        if staged_validation_status_filter not in {
            None,
            "conforms",
            "failed",
            "not_recorded",
        }:
            raise DoxaBaseError(
                "staged_validation_status must be 'conforms', 'failed', or "
                "'not_recorded'"
            )
        stale_resolution_state_filter = stale_resolution_state
        include_apply_checks = include_apply_checks or (
            application_status_filter is not None
            or stale_resolution_state_filter is not None
            or current_staged_work_only
        )
        data_graphs = self._expand_graphs([graph] if graph else None)
        ontology_graphs = self._expand_graphs(["ontology"])
        revision_type_filter = (
            self.expand_iri(revision_type) if revision_type is not None else None
        )
        revision_iris = self._subjects(
            data_graphs,
            str(RDF.type),
            self.expand_iri("rc:GraphRevision"),
        )
        items: list[GraphRevisionListItem] = []
        for revision_iri in revision_iris:
            item_revision_type = self._first_object(
                data_graphs,
                revision_iri,
                "rc:revisionType",
            )
            if (
                revision_type_filter is not None
                and item_revision_type != revision_type_filter
            ):
                continue
            revision_stance = self._first_object(
                data_graphs,
                revision_iri,
                "rc:revisionStance",
            )
            application_status: str | None = None
            application_decision: str | None = None
            application_can_apply: bool | None = None
            application_summary: str | None = None
            application_recommended_resolution: str | None = None
            application_validation_skipped_reason: str | None = None
            application_blocking_reasons: list[str] = []
            application_count_drifts: list[StagedGraphCountDrift] = []
            application_snapshot_drifts: list[StagedGraphSnapshotDrift] = []
            application_semantic_risk_level: str | None = None
            application_semantic_risk_reasons: list[str] = []
            suggested_next_actions: list[SuggestedNextAction] = []
            patch_iris = self._objects(
                data_graphs,
                revision_iri,
                "rc:hasGraphPatch",
            )
            if include_apply_checks and patch_iris:
                try:
                    check = self.check_staged_revision_apply(revision_iri)
                except DoxaBaseError:
                    application_status = "not_available"
                    application_decision = "inspect_staged_revision"
                    application_can_apply = None
                else:
                    application_status = check.status
                    application_decision = check.decision
                    application_can_apply = check.can_apply
                    application_summary = check.summary
                    application_recommended_resolution = check.recommended_resolution
                    application_validation_skipped_reason = (
                        check.validation_skipped_reason
                    )
                    application_blocking_reasons = check.blocking_reasons
                    application_count_drifts = check.count_drifts
                    application_semantic_risk_level = check.semantic_risk_level
                    application_semantic_risk_reasons = check.semantic_risk_reasons
                    if drift_detail == "exact":
                        application_snapshot_drifts = check.snapshot_drifts
                    else:
                        application_snapshot_drifts = (
                            self._summary_snapshot_drifts(check.snapshot_drifts)
                        )
                    suggested_next_actions = check.suggested_next_actions

            applies_staged_revision = self._first_object(
                data_graphs,
                revision_iri,
                "rc:appliesStagedRevision",
            )
            if application_status is None and applies_staged_revision is not None:
                application_status = "applied_event"

            alternative_to = self._first_object(
                data_graphs,
                revision_iri,
                "rc:alternativeTo",
            )
            restaged_from = self._first_object(
                data_graphs,
                revision_iri,
                "rc:restagesRevision",
            )
            restaged_by = self._first_subject(
                data_graphs,
                "rc:restagesRevision",
                revision_iri,
            )
            current_restaged_by = self._current_restage_successor_iri(
                revision_iri,
                graphs=data_graphs,
            )
            review_resolution = (
                self._staged_review_resolution_for_staged_iri(
                    revision_iri,
                    graphs=data_graphs,
                )
                if patch_iris
                else None
            )

            item_record_kind = self._graph_revision_record_kind(
                item_revision_type,
                has_patch_payload=bool(patch_iris),
                applies_staged_revision=applies_staged_revision,
            )
            if item_record_kind == "applied_event":
                suggested_next_actions = (
                    self._applied_revision_event_suggested_actions(revision_iri)
                )
            applied_by = self._first_subject(
                data_graphs,
                "rc:appliesStagedRevision",
                revision_iri,
            )
            is_current_staged_work = (
                item_record_kind == "staged_patch"
                and applied_by is None
                and current_restaged_by is None
                and review_resolution is None
            )
            not_current_staged_work_reason = (
                self._not_current_staged_work_reason(
                    record_kind=item_record_kind,
                    applied_by=applied_by,
                    current_restaged_by=current_restaged_by,
                    review_resolution=review_resolution,
                )
                if not is_current_staged_work
                else None
            )
            item_stale_resolution_state = self._stale_resolution_state(
                status=application_status,
                has_patch_payload=bool(patch_iris),
                restaged_from=restaged_from,
                restaged_by=restaged_by,
            )
            if (
                record_kind_filter is not None
                and item_record_kind != record_kind_filter
            ):
                continue
            if (
                application_status_filter is not None
                and application_status != application_status_filter
            ):
                continue
            staged_validation_conforms = self._bool_object(
                data_graphs,
                revision_iri,
                "rc:validationConforms",
            )
            staged_validation_result_count = self._int_object(
                data_graphs,
                revision_iri,
                "rc:validationResultCount",
            )
            item_staged_validation_status = self._staged_validation_status(
                conforms=staged_validation_conforms,
                result_count=staged_validation_result_count,
            )
            if (
                staged_validation_status_filter is not None
                and item_staged_validation_status != staged_validation_status_filter
            ):
                continue
            if (
                stale_resolution_state_filter is not None
                and item_stale_resolution_state != stale_resolution_state_filter
            ):
                continue
            if current_staged_work_only and not is_current_staged_work:
                continue

            snapshot_evidence = self._revision_snapshot_evidence_status(
                revision_iri,
                data_graphs,
            )
            suggested_next_actions = self._with_revision_snapshot_evidence_actions(
                suggested_next_actions,
                snapshot_evidence,
            )
            next_action = self._revision_next_action(
                revision_iri,
                apply_status=application_status,
                apply_decision=application_decision,
                stale_resolution_state=item_stale_resolution_state,
                suggested_next_actions=suggested_next_actions,
                restaged_by=restaged_by,
                current_restaged_by=current_restaged_by,
                record_kind=item_record_kind,
                staged_validation_status=item_staged_validation_status,
            )
            alternative_gate = self._staged_revision_alternative_gate(
                alternative_to,
                graphs=data_graphs,
            )
            items.append(
                GraphRevisionListItem(
                    iri=revision_iri,
                    record_kind=item_record_kind,
                    is_current_staged_work=is_current_staged_work,
                    not_current_staged_work_reason=(
                        not_current_staged_work_reason
                    ),
                    summary=self._first_object(data_graphs, revision_iri, "rc:summary"),
                    revision_type=item_revision_type,
                    revision_type_label=(
                        self._label_from_graphs(ontology_graphs, item_revision_type)
                        if item_revision_type is not None
                        else None
                    ),
                    revision_stance=revision_stance,
                    revision_stance_label=self._label_for_resource(revision_stance),
                    created_at=self._first_object(
                        data_graphs,
                        revision_iri,
                        "rc:createdAt",
                    ),
                    changed_graphs=self._objects(
                        data_graphs,
                        revision_iri,
                        "rc:changedGraph",
                    ),
                    validation_scope=self._first_object(
                        data_graphs,
                        revision_iri,
                        "rc:validationScope",
                    ),
                    validation_conforms=staged_validation_conforms,
                    validation_result_count=staged_validation_result_count,
                    staged_validation_status=item_staged_validation_status,
                    has_patch_payload=bool(patch_iris),
                    patch_count=len(patch_iris),
                    applied_by=applied_by,
                    applies_staged_revision=applies_staged_revision,
                    alternative_to=alternative_to,
                    current_alternative_to=alternative_gate.current_alternative_to,
                    alternative_gate=alternative_gate,
                    restaged_from=restaged_from,
                    restaged_by=restaged_by,
                    current_restaged_by=current_restaged_by,
                    review_resolution=review_resolution,
                    stale_resolution_state=item_stale_resolution_state,
                    application_status=application_status,
                    application_decision=application_decision,
                    application_can_apply=application_can_apply,
                    application_summary=application_summary,
                    application_recommended_resolution=(
                        application_recommended_resolution
                    ),
                    application_validation_skipped_reason=(
                        application_validation_skipped_reason
                    ),
                    application_blocking_reasons=application_blocking_reasons,
                    application_count_drifts=application_count_drifts,
                    application_snapshot_drifts=application_snapshot_drifts,
                    application_semantic_risk_level=(
                        application_semantic_risk_level
                    ),
                    application_semantic_risk_reasons=(
                        application_semantic_risk_reasons
                    ),
                    snapshot_evidence=snapshot_evidence,
                    next_action=next_action,
                    suggested_next_actions=suggested_next_actions,
                    suggested_next_calls=[
                        action.call for action in suggested_next_actions
                    ],
                )
            )

        items.sort(
            key=lambda item: (
                item.created_at or "",
                item.summary or "",
                item.iri,
            ),
            reverse=True,
        )
        sliced_items = items[offset : offset + limit]
        returned_current_staged_work_items = [
            item for item in sliced_items if item.is_current_staged_work
        ]
        next_action_queue_items: list[RevisionNextActionQueueItem] = []
        for item in sliced_items:
            queue_item = self._revision_next_action_queue_item(
                row_iri=item.iri,
                next_action=item.next_action,
                record_kind=item.record_kind,
                application_status=item.application_status,
                application_decision=item.application_decision,
                stale_resolution_state=item.stale_resolution_state,
                staged_validation_status=item.staged_validation_status,
                semantic_risk_level=item.application_semantic_risk_level,
                semantic_risk_reasons=item.application_semantic_risk_reasons,
                alternative_gate=item.alternative_gate,
            )
            if queue_item is not None:
                next_action_queue_items.append(queue_item)
        next_action_queue_items = (
            self._revision_next_action_queue_items_with_alternative_sets(
                next_action_queue_items,
                (
                    (item.iri, item.alternative_to, item.current_alternative_to)
                    for item in sliced_items
                ),
            )
        )
        return GraphRevisionList(
            revisions=sliced_items,
            count=len(items),
            returned_count=len(sliced_items),
            total_count=len(items),
            limit=limit,
            offset=offset,
            revision_type=revision_type_filter,
            record_kind=record_kind_filter,
            application_status=application_status_filter,
            staged_validation_status=staged_validation_status_filter,
            stale_resolution_state=stale_resolution_state_filter,
            current_staged_work_only=current_staged_work_only,
            returned_application_status_counts=self._graph_revision_list_counts(
                sliced_items,
                "application_status",
            ),
            returned_current_staged_work_application_status_counts=(
                self._graph_revision_list_counts(
                    returned_current_staged_work_items,
                    "application_status",
                )
            ),
            returned_stale_resolution_state_counts=self._graph_revision_list_counts(
                sliced_items,
                "stale_resolution_state",
            ),
            returned_staged_validation_status_counts=self._graph_revision_list_counts(
                sliced_items,
                "staged_validation_status",
            ),
            next_action_queue=self._revision_next_action_queue(
                (item.iri, item.next_action) for item in sliced_items
            ),
            next_action_queue_items=next_action_queue_items,
            next_action_queue_item_counts=(
                self._revision_next_action_queue_item_counts(
                    next_action_queue_items
                )
            ),
            semantic_review_required_queue_counts=(
                self._semantic_review_required_queue_counts(
                    next_action_queue_items
                )
            ),
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
        )

    def list_graph_versions(
        self,
        graph_role: str,
        *,
        graph: str | None = "history",
        exact_only: bool = False,
        include_current: bool = True,
        record_kind: str | None = None,
        limit: int = 50,
        offset: int = 0,
    ) -> GraphVersionList:
        if graph_role not in self._known_graph_names():
            raise DoxaBaseError(f"Unknown graph role: {graph_role}")
        self._ensure_non_negative("limit", limit)
        self._ensure_non_negative("offset", offset)

        revisions = self.list_graph_revisions(
            graph=graph,
            record_kind=record_kind,
            include_apply_checks=False,
            limit=1_000_000,
        ).revisions
        versions: list[GraphVersionListItem] = []
        for revision in revisions:
            snapshot = self._graph_version_snapshot_for_revision(
                revision,
                graph_role,
                graph=graph,
            )
            if snapshot is None:
                continue
            if exact_only and not snapshot.exact_snapshot_available:
                continue
            versions.append(snapshot)

        versions.sort(
            key=lambda item: (
                item.created_at or "",
                item.stored_at or "",
                item.summary or "",
                item.revision_iri,
            ),
            reverse=True,
        )
        sliced_versions = versions[offset : offset + limit]
        current_graph = (
            GraphSnapshotDescription(
                graph_role=graph_role,
                triple_count=self.triple_count(graph_role),
                content_digest=self._graph_content_digest(graph_role),
            )
            if include_current
            else None
        )
        return GraphVersionList(
            graph_role=graph_role,
            graph=graph,
            exact_only=exact_only,
            include_current=include_current,
            record_kind=record_kind,
            limit=limit,
            offset=offset,
            count=len(versions),
            total_count=len(versions),
            returned_count=len(sliced_versions),
            current_graph=current_graph,
            snapshot_evidence_status_counts=self._graph_version_status_counts(
                versions,
            ),
            exact_snapshot_available_count=sum(
                1 for version in versions if version.exact_snapshot_available
            ),
            versions=sliced_versions,
            note=(
                "Graph versions are stored revision snapshots, not a temporal "
                "checkout engine. Staged revision snapshots are before-states; "
                "applied revision snapshots are after-states."
            ),
        )

    def describe_graph_version_diff(
        self,
        graph_role: str,
        before_revision_iri: str,
        *,
        after_revision_iri: str | None = None,
        compare_to_current: bool = True,
        graph: str | None = "history",
        include_triples: bool = False,
        max_triples: int = 500,
    ) -> GraphVersionDiffDescription:
        if graph_role not in self._known_graph_names():
            raise DoxaBaseError(f"Unknown graph role: {graph_role}")
        if max_triples < 1:
            raise DoxaBaseError("max_triples must be at least 1")
        effective_compare_to_current = after_revision_iri is None and compare_to_current
        if after_revision_iri is None and not effective_compare_to_current:
            raise DoxaBaseError(
                "after_revision_iri is required when compare_to_current is False"
            )

        before_snapshot = self.describe_revision_graph_snapshot(
            before_revision_iri,
            graph_role,
            graph=graph,
            include_triples=False,
        )
        before_rows: set[GraphStorageRow] | None = None
        after_rows: set[GraphStorageRow] | None = None
        after_snapshot: RevisionGraphSnapshotDescription | None = None
        current_graph: GraphSnapshotDescription | None = None
        after_triple_count: int | None
        after_content_digest: str | None
        after_target_kind: str

        if before_snapshot.exact_snapshot_available:
            before_rows = set(
                self._graph_snapshot_storage_rows(
                    before_snapshot.revision_iri,
                    graph_role,
                )
            )

        if after_revision_iri is None:
            after_target_kind = "current_graph"
            current_graph = GraphSnapshotDescription(
                graph_role=graph_role,
                triple_count=self.triple_count(graph_role),
                content_digest=self._graph_content_digest(graph_role),
            )
            after_triple_count = current_graph.triple_count
            after_content_digest = current_graph.content_digest
            after_rows = set(self._graph_storage_rows(graph_role))
        else:
            after_target_kind = "stored_revision_snapshot"
            after_snapshot = self.describe_revision_graph_snapshot(
                after_revision_iri,
                graph_role,
                graph=graph,
                include_triples=False,
            )
            after_triple_count = after_snapshot.triple_count
            after_content_digest = after_snapshot.content_digest
            if after_snapshot.exact_snapshot_available:
                after_rows = set(
                    self._graph_snapshot_storage_rows(
                        after_snapshot.revision_iri,
                        graph_role,
                    )
                )

        exact_available = before_rows is not None and after_rows is not None
        triples_added: list[GraphTripleDescription] = []
        triples_removed: list[GraphTripleDescription] = []
        triples_added_count: int | None = None
        triples_removed_count: int | None = None
        triples_added_truncated = False
        triples_removed_truncated = False
        exact_included = False

        if exact_available:
            added_rows = self._sort_graph_storage_rows(after_rows - before_rows)
            removed_rows = self._sort_graph_storage_rows(before_rows - after_rows)
            triples_added_count = len(added_rows)
            triples_removed_count = len(removed_rows)
            if include_triples:
                exact_included = True
                triples_added_truncated = triples_added_count > max_triples
                triples_removed_truncated = triples_removed_count > max_triples
                triples_added = [
                    self._graph_triple_description(row)
                    for row in added_rows[:max_triples]
                ]
                triples_removed = [
                    self._graph_triple_description(row)
                    for row in removed_rows[:max_triples]
                ]
                note = (
                    "Exact graph-version changed triples are included from "
                    "stored snapshot rows and the selected after target."
                )
                if triples_added_truncated or triples_removed_truncated:
                    note = (
                        "Exact graph-version changed triples are available and "
                        "included up to max_triples per added/removed array."
                    )
            else:
                triples_added_truncated = triples_added_count > 0
                triples_removed_truncated = triples_removed_count > 0
                note = (
                    "Exact graph-version changed triples are available but "
                    "omitted; call describe_graph_version_diff(..., "
                    "include_triples=True) to include arrays."
                )
        else:
            note = (
                "Exact graph-version changed triples are unavailable because "
                "one or both comparison points lack stored snapshot rows."
            )
            if after_target_kind == "current_graph":
                note = (
                    "Exact graph-version changed triples are unavailable "
                    "because the before revision lacks stored snapshot rows."
                )

        count_delta = (
            after_triple_count - before_snapshot.triple_count
            if after_triple_count is not None
            and before_snapshot.triple_count is not None
            else None
        )
        digest_changed = (
            after_content_digest != before_snapshot.content_digest
            if after_content_digest is not None
            and before_snapshot.content_digest is not None
            else None
        )
        revision_items = self.list_graph_revisions(
            graph=graph,
            include_apply_checks=True,
            drift_detail="summary",
            limit=1_000_000,
        ).revisions
        revision_by_iri = {item.iri: item for item in revision_items}
        before_revision_context = self._graph_version_revision_context(
            revision_by_iri.get(before_snapshot.revision_iri)
        )
        after_revision_context = (
            self._graph_version_revision_context(
                revision_by_iri.get(after_snapshot.revision_iri)
            )
            if after_snapshot is not None
            else None
        )
        related_revision_iris = self._graph_version_diff_related_revision_iris(
            before_revision_context,
            after_revision_context,
        )
        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            self._graph_version_diff_suggested_actions(
                graph_role=graph_role,
                before_revision_iri=before_snapshot.revision_iri,
                after_revision_iri=(
                    after_snapshot.revision_iri
                    if after_snapshot is not None
                    else None
                ),
                compare_to_current=effective_compare_to_current,
                exact_available=exact_available,
                include_triples=include_triples,
                has_changes=bool(triples_added_count or triples_removed_count),
                before_revision_context=before_revision_context,
                after_revision_context=after_revision_context,
            ),
            before_snapshot.snapshot_evidence,
            after_snapshot.snapshot_evidence if after_snapshot is not None else None,
        )
        return GraphVersionDiffDescription(
            graph_role=graph_role,
            graph=graph,
            before_revision_iri=before_snapshot.revision_iri,
            after_revision_iri=(
                after_snapshot.revision_iri if after_snapshot is not None else None
            ),
            compare_to_current=effective_compare_to_current,
            after_target_kind=after_target_kind,
            before_revision_context=before_revision_context,
            after_revision_context=after_revision_context,
            related_revision_iris=related_revision_iris,
            before_snapshot=before_snapshot,
            after_snapshot=after_snapshot,
            current_graph=current_graph,
            count_basis="target_graph_only",
            before_triple_count=before_snapshot.triple_count,
            after_triple_count=after_triple_count,
            count_delta=count_delta,
            before_content_digest=before_snapshot.content_digest,
            after_content_digest=after_content_digest,
            digest_changed=digest_changed,
            exact_changed_triples_available=exact_available,
            exact_changed_triples_included=exact_included,
            triples_added_count=triples_added_count,
            triples_removed_count=triples_removed_count,
            triples_added_truncated=triples_added_truncated,
            triples_removed_truncated=triples_removed_truncated,
            max_triples=max_triples,
            triples_added=triples_added,
            triples_removed=triples_removed,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
            note=note,
        )

    def _graph_version_snapshot_for_revision(
        self,
        revision: GraphRevisionListItem,
        graph_role: str,
        *,
        graph: str | None,
    ) -> GraphVersionListItem | None:
        snapshot = self.describe_revision_graph_snapshot(
            revision.iri,
            graph_role,
            graph=graph,
            include_triples=False,
        )
        if snapshot.triple_count is None:
            return None
        suggested_next_actions = [
            SuggestedNextAction(
                action_label="Inspect graph version snapshot",
                tool_name="describe_revision_graph_snapshot",
                mcp_tool_name="doxabase.describe_revision_graph_snapshot",
                arguments={
                    "iri": revision.iri,
                    "graph_role": graph_role,
                },
                reason=(
                    "Inspect this stored graph snapshot; pass "
                    "include_triples=True only when exact historical triples "
                    "are needed and safe to review."
                ),
                call=self._suggested_call_string(
                    "describe_revision_graph_snapshot",
                    {
                        "iri": revision.iri,
                        "graph_role": graph_role,
                    },
                ),
            )
        ]
        if snapshot.exact_snapshot_available:
            suggested_next_actions.append(
                SuggestedNextAction(
                    action_label="Compare graph version to current",
                    tool_name="describe_graph_version_diff",
                    mcp_tool_name="doxabase.describe_graph_version_diff",
                    arguments={
                        "graph_role": graph_role,
                        "before_revision_iri": revision.iri,
                        "compare_to_current": True,
                    },
                    reason=(
                        "Compare this stored graph version with the current "
                        "live graph, including exact changed triples when "
                        "include_triples=True is safe and useful."
                    ),
                    call=self._suggested_call_string(
                        "describe_graph_version_diff",
                        {
                            "graph_role": graph_role,
                            "before_revision_iri": revision.iri,
                            "compare_to_current": True,
                        },
                    ),
                )
            )
        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            suggested_next_actions,
            snapshot.snapshot_evidence,
        )
        return GraphVersionListItem(
            revision_iri=revision.iri,
            graph_role=graph_role,
            record_kind=revision.record_kind,
            snapshot_semantics=self._graph_version_snapshot_semantics(revision),
            summary=revision.summary,
            revision_type=revision.revision_type,
            revision_type_label=revision.revision_type_label,
            created_at=revision.created_at,
            changed_graphs=revision.changed_graphs,
            included_graphs=self._graph_version_included_graphs(revision),
            applies_staged_revision=revision.applies_staged_revision,
            applied_by=revision.applied_by,
            restaged_from=revision.restaged_from,
            restaged_by=revision.restaged_by,
            current_restaged_by=revision.current_restaged_by,
            triple_count=snapshot.triple_count,
            content_digest=snapshot.content_digest,
            count_basis=snapshot.count_basis,
            stored_at=snapshot.stored_at,
            exact_snapshot_available=snapshot.exact_snapshot_available,
            snapshot_evidence_status=snapshot.snapshot_evidence.status,
            snapshot_evidence=snapshot.snapshot_evidence,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    @staticmethod
    def _graph_version_snapshot_semantics(
        revision: GraphRevisionListItem,
    ) -> str:
        if revision.record_kind == "staged_patch":
            return "staged_before_graph"
        if revision.record_kind == "applied_event":
            return "applied_after_graph"
        return "recorded_graph_snapshot"

    @staticmethod
    def _graph_version_included_graphs(
        revision: GraphRevisionListItem,
    ) -> list[str]:
        return list(
            dict.fromkeys(
                [
                    *revision.changed_graphs,
                    *revision.snapshot_evidence.rdf_snapshot_graph_roles,
                    *revision.snapshot_evidence.stored_snapshot_graph_roles,
                ]
            )
        )

    @staticmethod
    def _graph_version_status_counts(
        versions: Iterable[GraphVersionListItem],
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for version in versions:
            status = version.snapshot_evidence_status
            counts[status] = counts.get(status, 0) + 1
        return counts

    def _graph_version_revision_context(
        self,
        revision: GraphRevisionListItem | None,
    ) -> GraphVersionRevisionContext | None:
        if revision is None:
            return None
        related_revision_iris = list(
            dict.fromkeys(
                iri
                for iri in (
                    revision.applies_staged_revision,
                    revision.applied_by,
                    revision.restaged_from,
                    revision.restaged_by,
                    revision.current_restaged_by,
                )
                if iri is not None
            )
        )
        return GraphVersionRevisionContext(
            revision_iri=revision.iri,
            record_kind=revision.record_kind,
            snapshot_semantics=self._graph_version_snapshot_semantics(revision),
            summary=revision.summary,
            application_status=revision.application_status,
            application_decision=revision.application_decision,
            staged_validation_status=revision.staged_validation_status,
            is_current_staged_work=revision.is_current_staged_work,
            applies_staged_revision=revision.applies_staged_revision,
            applied_by=revision.applied_by,
            restaged_from=revision.restaged_from,
            restaged_by=revision.restaged_by,
            current_restaged_by=revision.current_restaged_by,
            related_revision_iris=related_revision_iris,
        )

    @staticmethod
    def _graph_version_diff_related_revision_iris(
        before_revision_context: GraphVersionRevisionContext | None,
        after_revision_context: GraphVersionRevisionContext | None,
    ) -> list[str]:
        values: list[str] = []
        for context in (before_revision_context, after_revision_context):
            if context is None:
                continue
            values.extend(context.related_revision_iris)
        return list(dict.fromkeys(values))

    def _graph_version_diff_suggested_actions(
        self,
        *,
        graph_role: str,
        before_revision_iri: str,
        after_revision_iri: str | None,
        compare_to_current: bool,
        exact_available: bool,
        include_triples: bool,
        has_changes: bool,
        before_revision_context: GraphVersionRevisionContext | None,
        after_revision_context: GraphVersionRevisionContext | None,
    ) -> list[SuggestedNextAction]:
        actions = [
            SuggestedNextAction(
                action_label="Inspect before snapshot",
                tool_name="describe_revision_graph_snapshot",
                mcp_tool_name="doxabase.describe_revision_graph_snapshot",
                arguments={
                    "iri": before_revision_iri,
                    "graph_role": graph_role,
                },
                reason=(
                    "Inspect the stored before snapshot metadata or exact "
                    "triples for this graph role."
                ),
                call=self._suggested_call_string(
                    "describe_revision_graph_snapshot",
                    {
                        "iri": before_revision_iri,
                        "graph_role": graph_role,
                    },
                ),
            )
        ]
        if after_revision_iri is not None:
            actions.append(
                SuggestedNextAction(
                    action_label="Inspect after snapshot",
                    tool_name="describe_revision_graph_snapshot",
                    mcp_tool_name="doxabase.describe_revision_graph_snapshot",
                    arguments={
                        "iri": after_revision_iri,
                        "graph_role": graph_role,
                    },
                    reason=(
                        "Inspect the stored after snapshot metadata or exact "
                        "triples for this graph role."
                    ),
                    call=self._suggested_call_string(
                        "describe_revision_graph_snapshot",
                        {
                            "iri": after_revision_iri,
                            "graph_role": graph_role,
                        },
                    ),
                )
            )
        contexts = [
            ("before", before_revision_context),
            ("after", after_revision_context),
        ]
        seen_lineage_iris: set[str] = set()
        for label, context in contexts:
            if context is None or context.revision_iri in seen_lineage_iris:
                continue
            seen_lineage_iris.add(context.revision_iri)
            actions.append(
                SuggestedNextAction(
                    action_label=f"Trace {label} revision lineage",
                    tool_name="describe_revision_lineage",
                    mcp_tool_name="doxabase.describe_revision_lineage",
                    arguments={"iri": context.revision_iri},
                    reason=(
                        "Inspect staged/applied/restaged lineage before "
                        "using this graph-version diff as recovery context."
                    ),
                    call=self._suggested_call_string(
                        "describe_revision_lineage",
                        {"iri": context.revision_iri},
                    ),
                )
            )
        seen_applied_diff_iris: set[str] = set()
        for label, context in contexts:
            if (
                context is None
                or context.record_kind != "applied_event"
                or context.revision_iri in seen_applied_diff_iris
            ):
                continue
            seen_applied_diff_iris.add(context.revision_iri)
            actions.append(
                SuggestedNextAction(
                    action_label=f"Inspect {label} applied diff",
                    tool_name="describe_applied_revision_diff",
                    mcp_tool_name="doxabase.describe_applied_revision_diff",
                    arguments={"iri": context.revision_iri},
                    reason=(
                        "This comparison point is an applied revision event; "
                        "inspect its stored before/after diff to recover the "
                        "revision story behind the graph-version delta."
                    ),
                    call=self._suggested_call_string(
                        "describe_applied_revision_diff",
                        {"iri": context.revision_iri},
                    ),
                )
            )
        if exact_available and has_changes and not include_triples:
            arguments: dict[str, Any] = {
                "graph_role": graph_role,
                "before_revision_iri": before_revision_iri,
                "include_triples": True,
            }
            if after_revision_iri is not None:
                arguments["after_revision_iri"] = after_revision_iri
            elif compare_to_current:
                arguments["compare_to_current"] = True
            actions.append(
                SuggestedNextAction(
                    action_label="Include changed triples",
                    tool_name="describe_graph_version_diff",
                    mcp_tool_name="doxabase.describe_graph_version_diff",
                    arguments=arguments,
                    reason=(
                        "Exact changed triples are available; include them "
                        "when the diff content is safe and useful to inspect."
                    ),
                    call=self._suggested_call_string(
                        "describe_graph_version_diff",
                        arguments,
                    ),
                )
            )
        return actions

    @staticmethod
    def _graph_revision_list_counts(
        items: Iterable[GraphRevisionListItem],
        field_name: str,
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for item in items:
            value = getattr(item, field_name)
            if value is None:
                continue
            counts[value] = counts.get(value, 0) + 1
        return counts

    def _applied_revision_event_suggested_actions(
        self,
        revision_iri: str,
    ) -> list[SuggestedNextAction]:
        return [
            SuggestedNextAction(
                action_label="Inspect applied event",
                tool_name="describe_graph_revision",
                mcp_tool_name="doxabase.describe_graph_revision",
                arguments={"iri": revision_iri},
                reason=(
                    "Inspect the applied revision event for durable history "
                    "context."
                ),
                call=self._suggested_call_string(
                    "describe_graph_revision",
                    {"iri": revision_iri},
                ),
            ),
            SuggestedNextAction(
                action_label="Inspect applied diff",
                tool_name="describe_applied_revision_diff",
                mcp_tool_name="doxabase.describe_applied_revision_diff",
                arguments={"iri": revision_iri},
                reason=(
                    "Inspect stored before/after graph snapshot counts and, "
                    "when needed, exact changed triples for the applied event."
                ),
                call=self._suggested_call_string(
                    "describe_applied_revision_diff",
                    {"iri": revision_iri},
                ),
            ),
        ]

    def describe_revision_lineage(
        self,
        iri: str,
        *,
        graph: str | None = "history",
        include_apply_checks: bool = True,
        drift_detail: TypingLiteral["summary", "exact"] = "summary",
    ) -> RevisionLineageDescription:
        revision_iri = self._required_iri("iri", iri)
        listing = self.list_graph_revisions(
            graph=graph,
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
            limit=1_000_000,
        )
        by_iri = {item.iri: item for item in listing.revisions}
        selected = by_iri.get(revision_iri)
        if selected is None:
            raise DoxaBaseError(
                f"Graph revision '{iri}' was not found in "
                f"{graph if graph is not None else 'all graphs'}"
                f"{self._missing_revision_snapshot_storage_hint(revision_iri)}"
            )

        seed: GraphRevisionListItem | None = selected
        warnings: list[str] = []
        if selected.record_kind == "applied_event":
            if selected.applies_staged_revision is None:
                seed = None
                warnings.append(
                    f"Applied revision event '{selected.iri}' does not name a "
                    "staged source revision."
                )
            elif selected.applies_staged_revision in by_iri:
                seed = by_iri[selected.applies_staged_revision]
            else:
                seed = None
                warnings.append(
                    f"Applied revision event '{selected.iri}' points to "
                    "missing staged source "
                    f"'{selected.applies_staged_revision}'."
                )

        if selected.applied_by is not None and selected.applied_by not in by_iri:
            warnings.append(
                f"Staged revision '{selected.iri}' points to missing applied "
                f"event '{selected.applied_by}'."
            )

        restage_chain: list[GraphRevisionListItem] = []
        if seed is not None:
            restage_chain, chain_warnings = self._revision_lineage_restage_chain(
                seed,
                by_iri,
            )
            warnings.extend(chain_warnings)
        current_staged_revision = next(
            (
                item
                for item in reversed(restage_chain)
                if item.is_current_staged_work
            ),
            None,
        )
        direct_applied_revision, direct_staged_revision = (
            self._revision_lineage_direct_pair(selected, by_iri)
        )
        chain_applied_source = self._revision_lineage_applied_source(
            selected,
            restage_chain,
        )
        chain_applied_revision = (
            by_iri.get(chain_applied_source.applied_by)
            if chain_applied_source is not None
            and chain_applied_source.applied_by is not None
            else None
        )
        applied_revision = (
            direct_applied_revision
            or chain_applied_revision
            or (selected if selected.record_kind == "applied_event" else None)
        )
        staged_revision = direct_staged_revision or (
            seed if seed is not None and seed.record_kind == "staged_patch" else None
        )
        paired_revision = None
        if selected.record_kind == "applied_event":
            paired_revision = direct_staged_revision
        elif selected.applied_by is not None:
            paired_revision = direct_applied_revision

        if applied_revision is not None:
            latest_revision = applied_revision
        elif current_staged_revision is not None:
            latest_revision = current_staged_revision
        else:
            latest_revision = restage_chain[-1] if restage_chain else selected
        next_action = latest_revision.next_action
        suggested_next_actions = list(latest_revision.suggested_next_actions)
        if not suggested_next_actions:
            derived_action = self._suggested_action_from_revision_next_action(
                next_action,
            )
            if derived_action is not None:
                suggested_next_actions = [derived_action]
        if (
            chain_applied_source is not None
            and chain_applied_source.iri != selected.iri
        ):
            arguments = {"iri": chain_applied_source.iri}
            if not any(
                action.tool_name == "describe_staged_revision"
                and action.arguments == arguments
                for action in suggested_next_actions
            ):
                suggested_next_actions.append(
                    SuggestedNextAction(
                        action_label="Inspect applied staged source",
                        tool_name="describe_staged_revision",
                        mcp_tool_name="doxabase.describe_staged_revision",
                        arguments=arguments,
                        reason=(
                            "Inspect the staged successor that was actually "
                            "applied for this lineage, rather than inferring it "
                            "from the restage chain."
                        ),
                        call=self._suggested_call_string(
                            "describe_staged_revision",
                            arguments,
                        ),
                    )
                )
        suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            suggested_next_actions,
            selected.snapshot_evidence,
            paired_revision.snapshot_evidence if paired_revision is not None else None,
            latest_revision.snapshot_evidence,
            (
                current_staged_revision.snapshot_evidence
                if current_staged_revision is not None
                else None
            ),
            *(item.snapshot_evidence for item in restage_chain),
        )
        snapshot_next_action = self._snapshot_evidence_completion_next_action(
            suggested_next_actions
        )
        if snapshot_next_action is not None:
            next_action = snapshot_next_action
        next_action_queue_item = self._revision_next_action_queue_item(
            row_iri=selected.iri,
            next_action=next_action,
            record_kind=selected.record_kind,
            application_status=selected.application_status,
            application_decision=selected.application_decision,
            stale_resolution_state=selected.stale_resolution_state,
            staged_validation_status=selected.staged_validation_status,
            semantic_risk_level=selected.application_semantic_risk_level,
            semantic_risk_reasons=selected.application_semantic_risk_reasons,
            alternative_gate=selected.alternative_gate,
        )
        if next_action_queue_item is not None:
            next_action_queue_item = (
                self._revision_next_action_queue_items_with_alternative_sets(
                    [next_action_queue_item],
                    (
                        (
                            item.iri,
                            item.alternative_to,
                            item.current_alternative_to,
                        )
                        for item in listing.revisions
                    ),
                )[0]
            )
        alternative_revision_iris = self._revision_lineage_alternative_revision_iris(
            selected=selected,
            restage_chain=restage_chain,
            by_iri=by_iri,
        )
        warnings.extend(
            self._revision_lineage_snapshot_warnings(
                selected=selected,
                paired=paired_revision,
                latest=latest_revision,
                current_staged_revision=current_staged_revision,
                restage_chain=restage_chain,
            )
        )
        return RevisionLineageDescription(
            selected_revision=selected,
            selected_revision_iri=selected.iri,
            selected_role=self._revision_lineage_role(selected),
            paired_revision=paired_revision,
            paired_revision_iri=(
                paired_revision.iri if paired_revision is not None else None
            ),
            paired_role=(
                self._revision_lineage_role(paired_revision)
                if paired_revision is not None
                else None
            ),
            applied_revision_iri=(
                applied_revision.iri if applied_revision is not None else None
            ),
            staged_revision_iri=(
                staged_revision.iri if staged_revision is not None else None
            ),
            applied_source_revision_iri=(
                chain_applied_source.iri
                if chain_applied_source is not None
                else None
            ),
            current_staged_revision_iri=(
                current_staged_revision.iri
                if current_staged_revision is not None
                else None
            ),
            current_revision_iri=(
                current_staged_revision.iri
                if current_staged_revision is not None
                else None
            ),
            latest_revision_iri=latest_revision.iri,
            latest_role=self._revision_lineage_role(latest_revision),
            restage_chain=restage_chain,
            restage_chain_iris=[item.iri for item in restage_chain],
            alternative_revision_iris=alternative_revision_iris,
            related_revision_iris=self._revision_lineage_related_revision_iris(
                selected=selected,
                paired=paired_revision,
                restage_chain=restage_chain,
                current_staged_revision=current_staged_revision,
                applied_revision=applied_revision,
                staged_revision=staged_revision,
                latest_revision=latest_revision,
                alternative_revision_iris=alternative_revision_iris,
                alternative_revisions=[
                    by_iri[iri]
                    for iri in alternative_revision_iris
                    if iri in by_iri
                ],
                by_iri=by_iri,
            ),
            next_action=next_action,
            next_action_queue_item=next_action_queue_item,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
            warnings=warnings,
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
        )

    def _revision_lineage_restage_chain(
        self,
        seed: GraphRevisionListItem,
        by_iri: dict[str, GraphRevisionListItem],
    ) -> tuple[list[GraphRevisionListItem], list[str]]:
        ancestors: list[GraphRevisionListItem] = []
        seen = {seed.iri}
        warnings: list[str] = []
        current = seed
        while current.restaged_from is not None:
            if current.restaged_from not in by_iri:
                warnings.append(
                    "Restage lineage points to missing source "
                    f"'{current.restaged_from}'."
                )
                break
            if current.restaged_from in seen:
                warnings.append(
                    "Restage lineage cycle detected at "
                    f"'{current.restaged_from}'."
                )
                break
            current = by_iri[current.restaged_from]
            ancestors.append(current)
            seen.add(current.iri)
        chain = list(reversed(ancestors)) + [seed]
        current = seed
        while current.restaged_by is not None:
            if current.restaged_by not in by_iri:
                warnings.append(
                    "Restage lineage points to missing successor "
                    f"'{current.restaged_by}'."
                )
                break
            if current.restaged_by in seen:
                warnings.append(
                    "Restage lineage cycle detected at "
                    f"'{current.restaged_by}'."
                )
                break
            current = by_iri[current.restaged_by]
            chain.append(current)
            seen.add(current.iri)
        for item in chain:
            if item.record_kind != "staged_patch":
                warnings.append(
                    "Restage lineage includes non-staged revision "
                    f"'{item.iri}' with record_kind='{item.record_kind}'."
                )
            successors = self._revision_lineage_visible_restage_successors(
                item,
                by_iri,
            )
            if len(successors) > 1:
                followed = item.restaged_by or successors[0].iri
                warnings.append(
                    "Restage lineage has multiple visible successors for "
                    f"'{item.iri}': "
                    f"{', '.join(successor.iri for successor in successors)}. "
                    f"The current route follows '{followed}'."
                )
        return chain, warnings

    @staticmethod
    def _revision_lineage_direct_pair(
        selected: GraphRevisionListItem,
        by_iri: dict[str, GraphRevisionListItem],
    ) -> tuple[GraphRevisionListItem | None, GraphRevisionListItem | None]:
        if selected.record_kind == "applied_event":
            staged = (
                by_iri.get(selected.applies_staged_revision)
                if selected.applies_staged_revision is not None
                else None
            )
            return selected, staged
        if selected.applied_by is not None:
            return by_iri.get(selected.applied_by), selected
        if selected.record_kind == "staged_patch":
            return None, selected
        return None, None

    @staticmethod
    def _revision_lineage_applied_source(
        selected: GraphRevisionListItem,
        restage_chain: list[GraphRevisionListItem],
    ) -> GraphRevisionListItem | None:
        if selected.record_kind == "applied_event":
            for item in restage_chain:
                if item.iri == selected.applies_staged_revision:
                    return item
            return None
        for item in reversed(restage_chain):
            if item.applied_by is not None:
                return item
        return selected if selected.applied_by is not None else None

    @staticmethod
    def _revision_lineage_role(item: GraphRevisionListItem) -> str:
        if item.record_kind == "applied_event":
            return "applied_event"
        if item.applied_by is not None:
            return "applied_source"
        if item.current_restaged_by is not None:
            return "restaged_source"
        if item.is_current_staged_work:
            return "current_staged_revision"
        if item.record_kind == "staged_patch":
            return "staged_revision"
        return item.record_kind

    @staticmethod
    def _revision_lineage_related_revision_iris(
        *,
        selected: GraphRevisionListItem,
        paired: GraphRevisionListItem | None,
        restage_chain: list[GraphRevisionListItem],
        current_staged_revision: GraphRevisionListItem | None,
        applied_revision: GraphRevisionListItem | None,
        staged_revision: GraphRevisionListItem | None,
        latest_revision: GraphRevisionListItem,
        alternative_revision_iris: list[str],
        alternative_revisions: list[GraphRevisionListItem],
        by_iri: dict[str, GraphRevisionListItem],
    ) -> list[str]:
        values: list[str | None] = [
            selected.iri,
            paired.iri if paired is not None else None,
            *(item.iri for item in restage_chain),
            current_staged_revision.iri
            if current_staged_revision is not None
            else None,
            applied_revision.iri if applied_revision is not None else None,
            staged_revision.iri if staged_revision is not None else None,
            latest_revision.iri,
            *alternative_revision_iris,
        ]
        for item in [selected, *restage_chain]:
            values.extend(
                [
                    item.applied_by,
                    item.applies_staged_revision,
                    item.restaged_from,
                    item.restaged_by,
                    item.current_restaged_by,
                    item.alternative_to,
                    item.current_alternative_to,
                ]
            )
        for item in alternative_revisions:
            values.extend(
                [
                    item.applied_by,
                    item.applies_staged_revision,
                    item.restaged_from,
                    item.restaged_by,
                    item.current_restaged_by,
                    item.alternative_to,
                    item.current_alternative_to,
                ]
            )
        for item in [selected, *restage_chain, *alternative_revisions]:
            for successor in DoxaBase._revision_lineage_visible_restage_successors(
                    item,
                    by_iri,
            ):
                values.extend(
                    [
                        successor.iri,
                        successor.applied_by,
                        successor.applies_staged_revision,
                        successor.restaged_from,
                        successor.restaged_by,
                        successor.current_restaged_by,
                        successor.alternative_to,
                        successor.current_alternative_to,
                    ]
                )
        return [value for value in dict.fromkeys(values) if value is not None]

    @staticmethod
    def _revision_lineage_visible_restage_successors(
        source: GraphRevisionListItem,
        by_iri: dict[str, GraphRevisionListItem],
    ) -> list[GraphRevisionListItem]:
        return sorted(
            (
                item
                for item in by_iri.values()
                if item.restaged_from == source.iri
            ),
            key=lambda item: item.iri,
        )

    @staticmethod
    def _revision_lineage_alternative_revision_iris(
        *,
        selected: GraphRevisionListItem,
        restage_chain: list[GraphRevisionListItem],
        by_iri: dict[str, GraphRevisionListItem],
    ) -> list[str]:
        seed_iris = {selected.iri, *(item.iri for item in restage_chain)}
        values: list[str | None] = []
        for item in [selected, *restage_chain]:
            values.extend([item.alternative_to, item.current_alternative_to])
        for item in by_iri.values():
            if item.iri in seed_iris:
                continue
            if (
                item.alternative_to in seed_iris
                or item.current_alternative_to in seed_iris
            ):
                values.append(item.iri)
        return [value for value in dict.fromkeys(values) if value is not None]

    @staticmethod
    def _suggested_action_from_revision_next_action(
        next_action: RevisionNextAction | None,
    ) -> SuggestedNextAction | None:
        if (
            next_action is None
            or next_action.tool_name is None
            or next_action.mcp_tool_name is None
            or next_action.call is None
        ):
            return None
        return SuggestedNextAction(
            action_label=next_action.action_label,
            tool_name=next_action.tool_name,
            mcp_tool_name=next_action.mcp_tool_name,
            arguments=next_action.arguments,
            reason=next_action.reason,
            call=next_action.call,
        )

    @staticmethod
    def _revision_lineage_snapshot_warnings(
        *,
        selected: GraphRevisionListItem,
        paired: GraphRevisionListItem | None,
        latest: GraphRevisionListItem,
        current_staged_revision: GraphRevisionListItem | None,
        restage_chain: list[GraphRevisionListItem] | None = None,
    ) -> list[str]:
        rows = [
            ("selected", selected),
            ("paired", paired),
            ("latest", latest),
            ("current", current_staged_revision),
            *(
                (f"restage-chain ancestor {index}", item)
                for index, item in enumerate(restage_chain or [], start=1)
            ),
        ]
        warnings: list[str] = []
        seen: set[tuple[str, str]] = set()
        for role, row in rows:
            if row is None:
                continue
            status = row.snapshot_evidence.status
            if status == "history_plus_snapshot_rows":
                continue
            key = (row.iri, status)
            if key in seen:
                continue
            seen.add(key)
            if status == "history_only_count_digest":
                evidence_label = (
                    "RDF count/digest snapshot metadata"
                    if row.snapshot_evidence.rdf_snapshot_graph_roles
                    else "RDF history metadata"
                )
                warnings.append(
                    f"{role} revision '{row.iri}' has {evidence_label} but "
                    "no stored snapshot rows; import a "
                    "companion revision snapshot JSON bundle before expecting "
                    "exact applied diffs or stale drift triples."
                )
            elif status == "snapshot_rows_without_history":
                warnings.append(
                    f"{role} revision '{row.iri}' has stored snapshot rows but "
                    "no visible RDF history record; import the project/history "
                    "RDF bundle before using normal revision helpers."
                )
            elif status == "history_missing":
                warnings.append(
                    f"{role} revision '{row.iri}' has no visible RDF history "
                    "record or stored snapshot rows."
                )
        return warnings

    def list_resource_revisions(
        self,
        resource_iri: str,
        *,
        graph: str | None = "history",
        include_patch_mentions: bool = True,
        include_apply_checks: bool = True,
        drift_detail: TypingLiteral["summary", "exact"] = "summary",
        current_staged_work_only: bool = False,
        limit: int = 50,
        offset: int = 0,
    ) -> ResourceRevisionList:
        if drift_detail not in {"summary", "exact"}:
            raise DoxaBaseError("drift_detail must be 'summary' or 'exact'")
        self._ensure_non_negative("limit", limit)
        self._ensure_non_negative("offset", offset)
        include_apply_checks = include_apply_checks or current_staged_work_only
        resource_value = self._required_iri("resource_iri", resource_iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(self._expand_graphs(["all"]))

        all_revisions = self.list_graph_revisions(
            graph=graph,
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
            current_staged_work_only=current_staged_work_only,
            limit=1_000_000,
        )
        matched: list[ResourceRevisionListItem] = []
        staged_cache: dict[str, StagedGraphRevisionDescription | None] = {}
        unreadable_patch_iris: set[str] = set()
        unreadable_revision_iris: set[str] = set()
        omitted_match_risk = False
        for item in all_revisions.revisions:
            match_types: list[str] = []
            revision_anchor_match = resource_value in self._objects(
                data_graphs,
                item.iri,
                "rc:revisionAnchor",
            )
            if revision_anchor_match:
                match_types.append("revision_anchor")

            patch_mentions: list[ResourceRevisionPatchMention] = []
            patch_mentions_unreadable_count = 0
            if include_patch_mentions and item.has_patch_payload:
                staged = self._cached_staged_revision(
                    item.iri,
                    graph=graph,
                    cache=staged_cache,
                )
                if staged is not None:
                    patch_scan = self._resource_revision_patch_mentions(
                        staged,
                        resource_value,
                    )
                    patch_mentions = patch_scan.mentions
                    patch_mentions_unreadable_count = (
                        patch_scan.unreadable_patch_count
                    )
                    if patch_scan.unreadable_patch_iris:
                        unreadable_patch_iris.update(
                            patch_scan.unreadable_patch_iris
                        )
                        unreadable_revision_iris.add(item.iri)
                    match_types.extend(
                        self._resource_revision_patch_match_types(
                            patch_mentions,
                            prefix="patch",
                        )
                    )

            applied_source_revision_iri = item.applies_staged_revision
            applied_source_patch_mentions: list[ResourceRevisionPatchMention] = []
            applied_source_patch_mentions_unreadable_count = 0
            applied_source_match = False
            if applied_source_revision_iri is not None:
                staged = self._cached_staged_revision(
                    applied_source_revision_iri,
                    graph=graph,
                    cache=staged_cache,
                )
                if staged is not None:
                    source_anchor_match = resource_value in {
                        anchor.iri for anchor in staged.revision_anchors
                    }
                    if include_patch_mentions:
                        applied_source_scan = self._resource_revision_patch_mentions(
                            staged,
                            resource_value,
                        )
                        applied_source_patch_mentions = (
                            applied_source_scan.mentions
                        )
                        applied_source_patch_mentions_unreadable_count = (
                            applied_source_scan.unreadable_patch_count
                        )
                        if applied_source_scan.unreadable_patch_iris:
                            unreadable_patch_iris.update(
                                applied_source_scan.unreadable_patch_iris
                            )
                            unreadable_revision_iris.add(applied_source_revision_iri)
                        if applied_source_patch_mentions:
                            applied_source_match = True
                            match_types.extend(
                                self._resource_revision_patch_match_types(
                                    applied_source_patch_mentions,
                                    prefix="applied_source_patch",
                                )
                            )
                else:
                    source_anchor_match = resource_value in self._objects(
                        data_graphs,
                        applied_source_revision_iri,
                        "rc:revisionAnchor",
                    )
                if source_anchor_match:
                    applied_source_match = True
                    match_types.append("applied_source_revision_anchor")

            match_types = list(dict.fromkeys(match_types))
            patch_mention_match = bool(patch_mentions)
            if (
                not revision_anchor_match
                and not patch_mention_match
                and not applied_source_match
            ):
                if (
                    patch_mentions_unreadable_count > 0
                    or applied_source_patch_mentions_unreadable_count > 0
                ):
                    omitted_match_risk = True
                continue
            matched.append(
                ResourceRevisionListItem(
                    revision=item,
                    revision_iri=item.iri,
                    match_types=match_types,
                    revision_anchor_match=revision_anchor_match,
                    patch_mention_match=patch_mention_match,
                    applied_source_match=applied_source_match,
                    applied_source_revision_iri=applied_source_revision_iri,
                    patch_mentions=patch_mentions,
                    patch_mentions_incomplete=patch_mentions_unreadable_count > 0,
                    patch_mentions_unreadable_count=patch_mentions_unreadable_count,
                    applied_source_patch_mentions=applied_source_patch_mentions,
                    applied_source_patch_mentions_incomplete=(
                        applied_source_patch_mentions_unreadable_count > 0
                    ),
                    applied_source_patch_mentions_unreadable_count=(
                        applied_source_patch_mentions_unreadable_count
                    ),
                )
            )

        sliced = matched[offset : offset + limit]
        next_action_queue_items: list[RevisionNextActionQueueItem] = []
        for item in sliced:
            queue_item = self._revision_next_action_queue_item(
                row_iri=item.revision.iri,
                next_action=item.revision.next_action,
                record_kind=item.revision.record_kind,
                application_status=item.revision.application_status,
                application_decision=item.revision.application_decision,
                stale_resolution_state=item.revision.stale_resolution_state,
                staged_validation_status=item.revision.staged_validation_status,
                semantic_risk_level=item.revision.application_semantic_risk_level,
                semantic_risk_reasons=item.revision.application_semantic_risk_reasons,
                alternative_gate=item.revision.alternative_gate,
            )
            if queue_item is not None:
                next_action_queue_items.append(queue_item)
        next_action_queue_items = (
            self._revision_next_action_queue_items_with_alternative_sets(
                next_action_queue_items,
                (
                    (
                        item.revision.iri,
                        item.revision.alternative_to,
                        item.revision.current_alternative_to,
                    )
                    for item in sliced
                ),
            )
        )
        timeline = self._resource_revision_timeline_events(
            sliced,
            next_action_queue_items=next_action_queue_items,
        )
        return ResourceRevisionList(
            resource=self._resource_summary(lookup_graphs, resource_value),
            revisions=sliced,
            timeline=timeline,
            timeline_note=(
                "Timeline events summarize the returned page in chronological "
                "order. Increase limit or paginate when total_count is greater "
                "than returned_count."
            ),
            count=len(matched),
            returned_count=len(sliced),
            total_count=len(matched),
            limit=limit,
            offset=offset,
            current_staged_work_only=current_staged_work_only,
            include_patch_mentions=include_patch_mentions,
            patch_mention_scan=ResourceRevisionPatchMentionScanSummary(
                status=(
                    "not_requested"
                    if not include_patch_mentions
                    else "incomplete"
                    if unreadable_patch_iris
                    else "complete"
                ),
                unreadable_patch_count=(
                    len(unreadable_patch_iris) if include_patch_mentions else 0
                ),
                unreadable_revision_count=(
                    len(unreadable_revision_iris) if include_patch_mentions else 0
                ),
                omitted_match_risk=(
                    omitted_match_risk if include_patch_mentions else False
                ),
            ),
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
            next_action_queue=self._revision_next_action_queue(
                (item.revision.iri, item.revision.next_action) for item in sliced
            ),
            next_action_queue_items=next_action_queue_items,
            next_action_queue_item_counts=(
                self._revision_next_action_queue_item_counts(
                    next_action_queue_items
                )
            ),
            semantic_review_required_queue_counts=(
                self._semantic_review_required_queue_counts(
                    next_action_queue_items
                )
            ),
        )

    def _resource_revision_timeline_events(
        self,
        items: list[ResourceRevisionListItem],
        *,
        next_action_queue_items: list[RevisionNextActionQueueItem],
    ) -> list[ResourceRevisionTimelineEvent]:
        queue_by_row = {item.row_iri: item for item in next_action_queue_items}
        ordered = sorted(
            items,
            key=lambda item: (
                item.revision.created_at or "",
                item.revision.summary or "",
                item.revision.iri,
            ),
        )
        events: list[ResourceRevisionTimelineEvent] = []
        for event_index, item in enumerate(ordered, start=1):
            applied_revision_iri, staged_revision_iri = (
                self._resource_revision_applied_pair(item)
            )
            queue_item = queue_by_row.get(item.revision_iri)
            next_action = item.revision.next_action
            events.append(
                ResourceRevisionTimelineEvent(
                    event_index=event_index,
                    revision_iri=item.revision_iri,
                    record_kind=item.revision.record_kind,
                    timeline_role=self._resource_revision_lineage_role(item),
                    summary=item.revision.summary,
                    created_at=item.revision.created_at,
                    changed_graphs=item.revision.changed_graphs,
                    match_types=item.match_types,
                    application_status=item.revision.application_status,
                    stale_resolution_state=item.revision.stale_resolution_state,
                    not_current_staged_work_reason=(
                        item.revision.not_current_staged_work_reason
                    ),
                    applied_revision_iri=applied_revision_iri,
                    staged_revision_iri=staged_revision_iri,
                    applied_by=item.revision.applied_by,
                    applied_source_revision_iri=item.applied_source_revision_iri,
                    restaged_from=item.revision.restaged_from,
                    current_restaged_by=item.revision.current_restaged_by,
                    queue=(
                        queue_item.queue
                        if queue_item is not None
                        else next_action.queue
                        if next_action is not None
                        else None
                    ),
                    action_type=(
                        queue_item.action_type
                        if queue_item is not None
                        else next_action.action_type
                        if next_action is not None
                        else None
                    ),
                    resolved_target_iri=(
                        queue_item.resolved_target_iri
                        if queue_item is not None
                        else None
                    ),
                    resolved_target_record_kind=(
                        queue_item.resolved_target_record_kind
                        if queue_item is not None
                        else None
                    ),
                    row_is_target=(
                        queue_item.row_is_target if queue_item is not None else None
                    ),
                    next_action_call=(
                        queue_item.call
                        if queue_item is not None
                        else next_action.call
                        if next_action is not None
                        else None
                    ),
                )
            )
        return events

    def describe_resource_revision_lineage(
        self,
        resource_iri: str,
        revision_iri: str,
        *,
        graph: str | None = "history",
        include_patch_mentions: bool = True,
        include_apply_checks: bool = True,
        drift_detail: TypingLiteral["summary", "exact"] = "summary",
        include_applied_diff: bool = True,
        include_triples: bool = False,
        max_triples: int = 100,
    ) -> ResourceRevisionLineageDescription:
        if max_triples < 1:
            raise DoxaBaseError("max_triples must be at least 1")
        resource_value = self._required_iri("resource_iri", resource_iri)
        revision_value = self._required_iri("revision_iri", revision_iri)
        lineage = self.list_resource_revisions(
            resource_value,
            graph=graph,
            include_patch_mentions=include_patch_mentions,
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
            limit=1_000_000,
        )
        by_iri = {item.revision.iri: item for item in lineage.revisions}
        selected = by_iri.get(revision_value)
        if selected is None:
            scan = lineage.patch_mention_scan
            scan_note = ""
            if scan.status == "incomplete" or scan.omitted_match_risk:
                scan_note = (
                    " Resource patch mention scan was "
                    f"{scan.status}; unreadable_patch_count="
                    f"{scan.unreadable_patch_count}; "
                    "unreadable_revision_count="
                    f"{scan.unreadable_revision_count}; "
                    f"omitted_match_risk={scan.omitted_match_risk}."
                )
            try:
                self.describe_graph_revision(revision_value, graph=graph)
            except DoxaBaseError:
                history_hint = self._missing_revision_snapshot_storage_hint(
                    revision_value
                )
            else:
                if include_patch_mentions:
                    history_hint = (
                        " Revision exists in history, but it is not linked to "
                        "this resource through revision anchors, patch "
                        "payloads, or applied-source patch context"
                    )
                else:
                    history_hint = (
                        " Revision exists in history, but patch payload "
                        "scanning was disabled for this lineage request. "
                        "Rerun with include_patch_mentions=True before "
                        "concluding that the revision is not linked through "
                        "patch payloads or applied-source patch context"
                    )
            raise DoxaBaseError(
                f"Revision '{revision_iri}' was not found in resource lineage "
                f"for '{resource_iri}'"
                f"{history_hint}."
                f"{scan_note}"
            )

        applied_revision_iri, staged_revision_iri = (
            self._resource_revision_applied_pair(selected)
        )
        paired_iri = (
            staged_revision_iri
            if selected.revision.iri == applied_revision_iri
            else applied_revision_iri
        )
        paired = by_iri.get(paired_iri) if paired_iri is not None else None
        current_staged_revision_iri = self._resource_lineage_current_staged_iri(
            selected,
            by_iri,
        )
        current_successor = (
            by_iri.get(selected.revision.current_restaged_by)
            if selected.revision.current_restaged_by is not None
            else None
        )
        current_successor_applied_revision_iri = (
            current_successor.revision.applied_by
            if current_successor is not None
            else None
        )
        graph_lineage = self.describe_revision_lineage(
            revision_value,
            graph=graph,
            include_apply_checks=include_apply_checks,
            drift_detail=drift_detail,
        )
        lineage_applied_revision_iri = applied_revision_iri
        lineage_staged_revision_iri = staged_revision_iri
        applied_diff_item = (
            selected if selected.revision.iri == applied_revision_iri else paired
        )
        if (
            lineage_applied_revision_iri is None
            and graph_lineage.latest_role == "applied_event"
            and graph_lineage.applied_revision_iri is not None
        ):
            lineage_applied_revision_iri = graph_lineage.applied_revision_iri
            if graph_lineage.restage_chain_iris:
                lineage_staged_revision_iri = graph_lineage.restage_chain_iris[-1]
            applied_diff_item = by_iri.get(lineage_applied_revision_iri)
        related_revision_iris = self._resource_lineage_related_revision_iris(
            selected,
            paired,
            applied_revision_iri=lineage_applied_revision_iri,
            staged_revision_iri=lineage_staged_revision_iri,
            current_staged_revision_iri=current_staged_revision_iri,
            current_successor_applied_revision_iri=(
                current_successor_applied_revision_iri
            ),
            graph_lineage_related_revision_iris=(
                graph_lineage.related_revision_iris
            ),
        )
        lineage_next_action, lineage_suggested_next_actions = (
            self._resource_lineage_next_actions(
                selected,
                current_successor_applied_revision_iri=(
                    current_successor_applied_revision_iri
                ),
            )
        )

        applied_diff_status = "not_applicable"
        applied_diff_note: str | None = (
            "No applied staged-revision event is linked to this resource revision."
        )
        applied_diff: ResourceAppliedRevisionDiffSummary | None = None
        if (
            lineage_applied_revision_iri is not None
            and lineage_staged_revision_iri is not None
        ):
            if include_applied_diff:
                applied_diff = self._resource_applied_revision_diff_summary(
                    resource_iri=resource_value,
                    applied_revision_iri=lineage_applied_revision_iri,
                    staged_revision_iri=lineage_staged_revision_iri,
                    graph=graph,
                    include_triples=include_triples,
                    max_triples=max_triples,
                    applied_item=applied_diff_item,
                )
                applied_diff_status = (
                    "available"
                    if any(
                        diff.exact_changed_triples_available
                        for diff in applied_diff.graph_diffs
                    )
                    else "unavailable"
                )
                applied_diff_note = (
                    "Resource-filtered applied diff summary is available."
                    if applied_diff_status == "available"
                    else (
                        "Applied event is linked, but exact before/after "
                        "snapshot rows are unavailable for the changed graphs."
                    )
                )
            else:
                applied_diff_status = "omitted"
                applied_diff_note = (
                    "Applied event is linked, but applied diff summary was "
                    "omitted by request."
                )
        lineage_suggested_next_actions = self._with_revision_snapshot_evidence_actions(
            lineage_suggested_next_actions,
            selected.revision.snapshot_evidence,
            paired.revision.snapshot_evidence if paired is not None else None,
            graph_lineage.selected_revision.snapshot_evidence,
            (
                graph_lineage.paired_revision.snapshot_evidence
                if graph_lineage.paired_revision is not None
                else None
            ),
            applied_diff.snapshot_evidence if applied_diff is not None else None,
            (
                applied_diff.source_snapshot_evidence
                if applied_diff is not None
                else None
            ),
        )
        snapshot_next_action = self._snapshot_evidence_completion_next_action(
            lineage_suggested_next_actions
        )
        if snapshot_next_action is not None:
            lineage_next_action = snapshot_next_action
        lineage_next_action_queue_item = self._revision_next_action_queue_item(
            row_iri=selected.revision.iri,
            next_action=lineage_next_action,
            record_kind=selected.revision.record_kind,
            application_status=selected.revision.application_status,
            application_decision=selected.revision.application_decision,
            stale_resolution_state=selected.revision.stale_resolution_state,
            staged_validation_status=selected.revision.staged_validation_status,
            semantic_risk_level=selected.revision.application_semantic_risk_level,
            semantic_risk_reasons=(
                selected.revision.application_semantic_risk_reasons
            ),
            alternative_gate=selected.revision.alternative_gate,
        )
        if lineage_next_action_queue_item is not None:
            lineage_next_action_queue_item = (
                self._revision_next_action_queue_items_with_alternative_sets(
                    [lineage_next_action_queue_item],
                    (
                        (
                            item.revision.iri,
                            item.revision.alternative_to,
                            item.revision.current_alternative_to,
                        )
                        for item in lineage.revisions
                    ),
                )[0]
            )

        return ResourceRevisionLineageDescription(
            resource=lineage.resource,
            selected_revision=selected,
            selected_revision_iri=selected.revision.iri,
            selected_role=self._resource_revision_lineage_role(selected),
            paired_revision=paired,
            paired_revision_iri=(
                paired.revision.iri if paired is not None else None
            ),
            paired_role=(
                self._resource_revision_lineage_role(paired)
                if paired is not None
                else None
            ),
            applied_revision_iri=lineage_applied_revision_iri,
            staged_revision_iri=lineage_staged_revision_iri,
            applied_source_revision_iri=(
                lineage_staged_revision_iri
                if lineage_applied_revision_iri is not None
                else None
            ),
            current_staged_revision_iri=current_staged_revision_iri,
            current_revision_iri=current_staged_revision_iri,
            latest_revision_iri=graph_lineage.latest_revision_iri,
            latest_role=graph_lineage.latest_role,
            restage_chain_iris=graph_lineage.restage_chain_iris,
            alternative_revision_iris=graph_lineage.alternative_revision_iris,
            related_revision_iris=related_revision_iris,
            warnings=graph_lineage.warnings,
            patch_mention_scan=lineage.patch_mention_scan,
            next_action=lineage_next_action,
            next_action_queue_item=lineage_next_action_queue_item,
            suggested_next_actions=lineage_suggested_next_actions,
            suggested_next_calls=[
                action.call for action in lineage_suggested_next_actions
            ],
            applied_diff_status=applied_diff_status,
            applied_diff_note=applied_diff_note,
            applied_diff=applied_diff,
        )

    def _resource_lineage_next_actions(
        self,
        selected: ResourceRevisionListItem,
        *,
        current_successor_applied_revision_iri: str | None,
    ) -> tuple[RevisionNextAction | None, list[SuggestedNextAction]]:
        if (
            selected.revision.current_restaged_by is None
            or current_successor_applied_revision_iri is None
        ):
            suggested_next_actions = list(selected.revision.suggested_next_actions)
            if not suggested_next_actions:
                derived_action = self._suggested_action_from_revision_next_action(
                    selected.revision.next_action,
                )
                if derived_action is not None:
                    suggested_next_actions = [derived_action]
            return (
                selected.revision.next_action,
                suggested_next_actions,
            )

        def action(
            *,
            action_label: str,
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
        ) -> SuggestedNextAction:
            return SuggestedNextAction(
                action_label=action_label,
                tool_name=tool_name,
                mcp_tool_name=f"doxabase.{tool_name}",
                arguments=arguments,
                reason=reason,
                call=self._suggested_call_string(tool_name, arguments),
            )

        preferred_actions = [
            action(
                action_label="Inspect applied event",
                tool_name="describe_graph_revision",
                arguments={"iri": current_successor_applied_revision_iri},
                reason=(
                    "The refreshed successor has already been applied; inspect "
                    "the applied event before following the stale source or "
                    "successor hop."
                ),
            ),
            action(
                action_label="Inspect applied diff",
                tool_name="describe_applied_revision_diff",
                arguments={"iri": current_successor_applied_revision_iri},
                reason=(
                    "Inspect stored before/after graph snapshot counts and, "
                    "when needed, exact changed triples for the applied event."
                ),
            ),
        ]
        combined_actions: list[SuggestedNextAction] = []
        seen: set[tuple[str, str]] = set()
        for candidate in [
            *preferred_actions,
            *selected.revision.suggested_next_actions,
        ]:
            key = (candidate.tool_name, candidate.call)
            if key in seen:
                continue
            seen.add(key)
            combined_actions.append(candidate)
        first = preferred_actions[0]
        return (
            RevisionNextAction(
                action_type="inspect_applied_event",
                queue="inspect_already_applied",
                action_label=first.action_label,
                tool_name=first.tool_name,
                mcp_tool_name=first.mcp_tool_name,
                arguments=first.arguments,
                reason=first.reason,
                call=first.call,
                source="suggested_next_actions",
            ),
            combined_actions,
        )

    @staticmethod
    def _resource_lineage_current_staged_iri(
        selected: ResourceRevisionListItem,
        by_iri: dict[str, ResourceRevisionListItem],
    ) -> str | None:
        if selected.revision.is_current_staged_work:
            return selected.revision.iri
        successor_iri = selected.revision.current_restaged_by
        if successor_iri is None:
            return None
        successor = by_iri.get(successor_iri)
        if successor is not None and successor.revision.is_current_staged_work:
            return successor_iri
        return None

    @staticmethod
    def _resource_revision_applied_pair(
        item: ResourceRevisionListItem,
    ) -> tuple[str | None, str | None]:
        if item.revision.record_kind == "applied_event":
            return item.revision.iri, item.applied_source_revision_iri
        if item.revision.applied_by is not None:
            return item.revision.applied_by, item.revision.iri
        if item.revision.record_kind == "staged_patch":
            return None, item.revision.iri
        return None, None

    @staticmethod
    def _resource_revision_lineage_role(item: ResourceRevisionListItem) -> str:
        if item.revision.record_kind == "applied_event":
            return "applied_event"
        if item.revision.applied_by is not None:
            return "applied_source"
        if item.revision.current_restaged_by is not None:
            return "restaged_source"
        if item.revision.is_current_staged_work:
            return "current_staged_revision"
        if item.revision.record_kind == "staged_patch":
            return "staged_revision"
        return "history_record"

    @staticmethod
    def _resource_lineage_related_revision_iris(
        selected: ResourceRevisionListItem,
        paired: ResourceRevisionListItem | None,
        *,
        applied_revision_iri: str | None,
        staged_revision_iri: str | None,
        current_staged_revision_iri: str | None,
        current_successor_applied_revision_iri: str | None,
        graph_lineage_related_revision_iris: list[str],
    ) -> list[str]:
        values = [
            selected.revision.iri,
            paired.revision.iri if paired is not None else None,
            applied_revision_iri,
            staged_revision_iri,
            current_staged_revision_iri,
            current_successor_applied_revision_iri,
            selected.revision.restaged_from,
            selected.revision.restaged_by,
            selected.revision.current_restaged_by,
            paired.revision.restaged_from if paired is not None else None,
            paired.revision.restaged_by if paired is not None else None,
            paired.revision.current_restaged_by if paired is not None else None,
            *graph_lineage_related_revision_iris,
        ]
        return [value for value in dict.fromkeys(values) if value is not None]

    def _resource_applied_revision_diff_summary(
        self,
        *,
        resource_iri: str,
        applied_revision_iri: str,
        staged_revision_iri: str,
        graph: str | None,
        include_triples: bool,
        max_triples: int,
        applied_item: ResourceRevisionListItem | None,
    ) -> ResourceAppliedRevisionDiffSummary:
        data_graphs = self._expand_graphs([graph] if graph else None)
        before_snapshots = {
            snapshot.graph_role: snapshot
            for snapshot in self._graph_revision_snapshots(
                staged_revision_iri,
                data_graphs,
            )
        }
        after_snapshots = {
            snapshot.graph_role: snapshot
            for snapshot in self._graph_revision_snapshots(
                applied_revision_iri,
                data_graphs,
            )
        }
        changed_graphs = (
            list(applied_item.revision.changed_graphs)
            if applied_item is not None
            else self._objects(data_graphs, applied_revision_iri, "rc:changedGraph")
        )
        if not changed_graphs:
            changed_graphs = sorted(set(before_snapshots) | set(after_snapshots))
        return ResourceAppliedRevisionDiffSummary(
            applied_revision_iri=applied_revision_iri,
            staged_revision_iri=staged_revision_iri,
            snapshot_evidence=self._revision_snapshot_evidence_status(
                applied_revision_iri,
                data_graphs,
            ),
            source_snapshot_evidence=self._revision_snapshot_evidence_status(
                staged_revision_iri,
                data_graphs,
            ),
            changed_graphs=changed_graphs,
            include_triples=include_triples,
            max_triples=max_triples,
            graph_diffs=[
                self._resource_applied_revision_graph_diff_summary(
                    resource_iri=resource_iri,
                    graph_role=graph_role,
                    before_revision_iri=staged_revision_iri,
                    after_revision_iri=applied_revision_iri,
                    before_snapshot=before_snapshots.get(graph_role),
                    after_snapshot=after_snapshots.get(graph_role),
                    include_triples=include_triples,
                    max_triples=max_triples,
                )
                for graph_role in changed_graphs
            ],
        )

    def _resource_applied_revision_graph_diff_summary(
        self,
        *,
        resource_iri: str,
        graph_role: str,
        before_revision_iri: str,
        after_revision_iri: str,
        before_snapshot: GraphSnapshotDescription | None,
        after_snapshot: GraphSnapshotDescription | None,
        include_triples: bool,
        max_triples: int,
    ) -> ResourceAppliedRevisionGraphDiffSummary:
        exact_available = self._graph_snapshot_storage_exists(
            before_revision_iri,
            graph_role,
        ) and self._graph_snapshot_storage_exists(after_revision_iri, graph_role)
        resource_added_rows: list[GraphStorageRow] = []
        resource_removed_rows: list[GraphStorageRow] = []
        if exact_available:
            before_rows = set(
                self._graph_snapshot_storage_rows(before_revision_iri, graph_role)
            )
            after_rows = set(
                self._graph_snapshot_storage_rows(after_revision_iri, graph_role)
            )
            resource_added_rows = [
                row
                for row in self._sort_graph_storage_rows(after_rows - before_rows)
                if self._graph_storage_row_mentions_resource(row, resource_iri)
            ]
            resource_removed_rows = [
                row
                for row in self._sort_graph_storage_rows(before_rows - after_rows)
                if self._graph_storage_row_mentions_resource(row, resource_iri)
            ]

        added_count = len(resource_added_rows) if exact_available else None
        removed_count = len(resource_removed_rows) if exact_available else None
        added_truncated = bool(
            exact_available
            and added_count is not None
            and added_count > max_triples
        )
        removed_truncated = bool(
            exact_available
            and removed_count is not None
            and removed_count > max_triples
        )
        triples_included = exact_available and include_triples
        if exact_available:
            if include_triples:
                note = (
                    "Resource-filtered exact before/after snapshot triples are "
                    "included from stored revision snapshot rows."
                )
                if added_truncated or removed_truncated:
                    note = (
                        "Resource-filtered exact before/after snapshot triples "
                        "are included up to max_triples per added/removed array."
                    )
            else:
                note = (
                    "Resource-filtered exact before/after snapshot triple counts "
                    "are available; pass include_triples=True to include arrays."
                )
        else:
            note = self._missing_applied_snapshot_rows_note(
                before_snapshot=before_snapshot,
                after_snapshot=after_snapshot,
            )

        return ResourceAppliedRevisionGraphDiffSummary(
            graph_role=graph_role,
            count_basis="target_graph_only",
            before_revision_iri=before_revision_iri,
            after_revision_iri=after_revision_iri,
            before_triple_count=(
                before_snapshot.triple_count if before_snapshot is not None else None
            ),
            after_triple_count=(
                after_snapshot.triple_count if after_snapshot is not None else None
            ),
            before_content_digest=(
                before_snapshot.content_digest if before_snapshot is not None else None
            ),
            after_content_digest=(
                after_snapshot.content_digest if after_snapshot is not None else None
            ),
            exact_changed_triples_available=exact_available,
            exact_changed_triples_included=triples_included,
            resource_triples_added_count=added_count,
            resource_triples_removed_count=removed_count,
            resource_triples_added_truncated=added_truncated,
            resource_triples_removed_truncated=removed_truncated,
            max_triples=max_triples,
            resource_triples_added=(
                [
                    self._graph_triple_description(row)
                    for row in resource_added_rows[:max_triples]
                ]
                if triples_included
                else []
            ),
            resource_triples_removed=(
                [
                    self._graph_triple_description(row)
                    for row in resource_removed_rows[:max_triples]
                ]
                if triples_included
                else []
            ),
            note=note,
        )

    @staticmethod
    def _graph_storage_row_mentions_resource(
        row: GraphStorageRow,
        resource_iri: str,
    ) -> bool:
        return (
            row[0] == resource_iri
            or row[2] == resource_iri
            or (row[4] == "uri" and row[3] == resource_iri)
        )

    def _cached_staged_revision(
        self,
        iri: str,
        *,
        graph: str | None,
        cache: dict[str, StagedGraphRevisionDescription | None],
    ) -> StagedGraphRevisionDescription | None:
        if iri not in cache:
            try:
                cache[iri] = self.describe_staged_revision(iri, graph=graph)
            except DoxaBaseError:
                cache[iri] = None
        return cache[iri]

    def _resource_revision_patch_mentions(
        self,
        staged: StagedGraphRevisionDescription,
        resource_iri: str,
    ) -> _ResourceRevisionPatchMentionScan:
        mentions: list[ResourceRevisionPatchMention] = []
        unreadable_patch_iris: list[str] = []
        role_order = ("subject", "predicate", "object")
        for patch in staged.patches:
            if patch.content is None:
                unreadable_patch_iris.append(patch.iri)
                continue
            try:
                patch_graph = self._parse_staged_patch_description(patch)
            except DoxaBaseError:
                unreadable_patch_iris.append(patch.iri)
                continue
            matched_roles: set[str] = set()
            matched_triples = 0
            for subject, predicate, object_node in patch_graph:
                triple_matched = False
                if str(subject) == resource_iri:
                    matched_roles.add("subject")
                    triple_matched = True
                if str(predicate) == resource_iri:
                    matched_roles.add("predicate")
                    triple_matched = True
                if str(object_node) == resource_iri:
                    matched_roles.add("object")
                    triple_matched = True
                if triple_matched:
                    matched_triples += 1
            if matched_roles:
                mentions.append(
                    ResourceRevisionPatchMention(
                        patch_iri=patch.iri,
                        target_graph=patch.target_graph,
                        operation=patch.operation,
                        operation_label=patch.operation_label,
                        patch_role=patch.patch_role,
                        patch_role_label=patch.patch_role_label,
                        sequence_index=patch.sequence_index,
                        matched_term_roles=[
                            role for role in role_order if role in matched_roles
                        ],
                        matched_triples=matched_triples,
                        triple_count=patch.triple_count,
                    )
                )
        return _ResourceRevisionPatchMentionScan(
            mentions=mentions,
            unreadable_patch_count=len(unreadable_patch_iris),
            unreadable_patch_iris=unreadable_patch_iris,
        )

    @staticmethod
    def _resource_revision_patch_match_types(
        mentions: list[ResourceRevisionPatchMention],
        *,
        prefix: str,
    ) -> list[str]:
        return list(
            dict.fromkeys(
                f"{prefix}_{role}"
                for mention in mentions
                for role in mention.matched_term_roles
            )
        )

    def _current_alternative_to_iri(
        self,
        alternative_to: str | None,
        *,
        graphs: list[str] | None = None,
    ) -> str | None:
        if alternative_to is None:
            return None
        successor = self._current_restage_successor_iri(
            alternative_to,
            graphs=graphs,
        )
        return successor or alternative_to

    def _current_restage_successor_iri(
        self,
        iri: str,
        *,
        graphs: list[str] | None = None,
    ) -> str | None:
        lookup_graphs = graphs or self._expand_graphs(["history"])
        seen = {iri}
        current_iri = iri
        latest_successor: str | None = None
        while True:
            successor = self._first_subject(
                lookup_graphs,
                "rc:restagesRevision",
                current_iri,
            )
            if successor is None or successor in seen:
                return latest_successor
            latest_successor = successor
            current_iri = successor
            seen.add(successor)

    def _staged_revision_alternative_gate(
        self,
        alternative_to: str | None,
        *,
        graphs: list[str] | None = None,
    ) -> StagedRevisionAlternativeGate:
        if alternative_to is None:
            return StagedRevisionAlternativeGate(
                status="not_applicable",
                alternative_to=None,
                current_alternative_to=None,
                applied_source_iri=None,
                applied_revision_iri=None,
                semantic_review_required=False,
                note="This staged revision is not marked as an alternative.",
            )
        lookup_graphs = graphs or self._expand_graphs(["history"])
        current_alternative_to = (
            self._current_alternative_to_iri(alternative_to, graphs=lookup_graphs)
            or alternative_to
        )
        applied_revision_iri = self._first_subject(
            lookup_graphs,
            "rc:appliesStagedRevision",
            current_alternative_to,
        )
        if applied_revision_iri is None:
            return StagedRevisionAlternativeGate(
                status="alternative_to_unapplied_source",
                alternative_to=alternative_to,
                current_alternative_to=current_alternative_to,
                applied_source_iri=None,
                applied_revision_iri=None,
                semantic_review_required=False,
                note=(
                    "This staged revision is an alternative; compare related "
                    "alternatives before applying one framing."
                ),
            )
        return StagedRevisionAlternativeGate(
            status="alternative_to_applied_source",
            alternative_to=alternative_to,
            current_alternative_to=current_alternative_to,
            applied_source_iri=current_alternative_to,
            applied_revision_iri=applied_revision_iri,
            semantic_review_required=True,
            note=(
                "The current alternative target has already been applied. "
                "Mechanical readiness is not approval to make both alternatives "
                "durable; inspect the applied source before applying this row."
            ),
        )

    def _stale_resolution_state(
        self,
        *,
        status: str | None,
        has_patch_payload: bool,
        restaged_from: str | None,
        restaged_by: str | None,
    ) -> str | None:
        if not has_patch_payload:
            return None
        if restaged_by is not None:
            return "stale_handled_by_restage"
        if status == "conflict":
            if restaged_from is not None and restaged_by is None:
                return "restaged_successor_stale_unresolved"
            return (
                "stale_handled_by_restage"
                if restaged_by is not None
                else "stale_unresolved"
            )
        if status == "superseded_by_restage":
            return "stale_handled_by_restage"
        if restaged_from is not None:
            if status == "ready":
                return "restaged_successor_ready"
            if status == "noop":
                return "restaged_successor_noop"
            if status == "already_applied":
                return "restaged_successor_already_applied"
            return "restaged_successor_not_ready"
        if status in {
            "ready",
            "noop",
            "already_applied",
            "validation_failed",
            "not_ready",
            "not_available",
        }:
            return status
        return None

    @staticmethod
    def _staged_validation_status(
        *,
        conforms: bool | None,
        result_count: int | None,
    ) -> str:
        if conforms is True:
            return "conforms"
        if conforms is False:
            return "failed"
        if result_count is not None and result_count > 0:
            return "failed"
        return "not_recorded"

    @staticmethod
    def _not_current_staged_work_reason(
        *,
        record_kind: str,
        applied_by: str | None,
        current_restaged_by: str | None,
        review_resolution: StagedRevisionReviewResolutionSummary | None = None,
    ) -> str:
        if record_kind == "staged_patch":
            if applied_by is not None:
                return "already_applied_source"
            if current_restaged_by is not None:
                return "superseded_by_restage"
            if review_resolution is not None:
                return "review_resolved"
            return "not_current_staged_patch"
        if record_kind == "applied_event":
            return "applied_event_record"
        return record_kind

    def _summary_snapshot_drifts(
        self,
        drifts: Iterable[StagedGraphSnapshotDrift],
    ) -> list[StagedGraphSnapshotDrift]:
        summary_drifts: list[StagedGraphSnapshotDrift] = []
        for drift in drifts:
            if drift.exact_changed_triples_available:
                note = (
                    "The graph content digest changed since this revision was "
                    "staged. Exact changed triples are available but omitted "
                    "from this summary response; call "
                    "check_staged_revision_apply() or "
                    "list_graph_revisions(drift_detail='exact') for them."
                )
            else:
                note = drift.note
            summary_drifts.append(
                StagedGraphSnapshotDrift(
                    graph_role=drift.graph_role,
                    snapshot_triple_count=drift.snapshot_triple_count,
                    current_triple_count=drift.current_triple_count,
                    snapshot_content_digest=drift.snapshot_content_digest,
                    current_content_digest=drift.current_content_digest,
                    exact_changed_triples_available=(
                        drift.exact_changed_triples_available
                    ),
                    exact_changed_triples_included=False,
                    triples_added_since_snapshot_count=(
                        drift.triples_added_since_snapshot_count
                    ),
                    triples_removed_since_snapshot_count=(
                        drift.triples_removed_since_snapshot_count
                    ),
                    drift_relevance=drift.drift_relevance,
                    patch_overlap_subjects=drift.patch_overlap_subjects,
                    patch_overlap_predicates=drift.patch_overlap_predicates,
                    patch_overlap_objects=drift.patch_overlap_objects,
                    revision_anchor_overlap=drift.revision_anchor_overlap,
                    triples_added_since_snapshot=[],
                    triples_removed_since_snapshot=[],
                    note=note,
                )
            )
        return summary_drifts

    def _graph_revision_record_kind(
        self,
        revision_type: str | None,
        *,
        has_patch_payload: bool,
        applies_staged_revision: str | None,
    ) -> str:
        if applies_staged_revision is not None:
            return "applied_event"
        if has_patch_payload:
            return "staged_patch"
        if revision_type == self.expand_iri("rc:StagedRevisionReviewResolution"):
            return "staged_review_resolution"
        if revision_type == self.expand_iri("rc:ExportRevision"):
            return "export_record"
        if revision_type == self.expand_iri("rc:ImportRevision"):
            return "import_record"
        return "history_record"

    def _graph_revision_record_kind_for_iri(
        self,
        revision_iri: str | None,
    ) -> str | None:
        if revision_iri is None:
            return None
        data_graphs = self._expand_graphs(["history"])
        if self.expand_iri("rc:GraphRevision") not in self._types_from_graphs(
            data_graphs,
            revision_iri,
        ):
            return None
        revision_type = self._first_object(
            data_graphs,
            revision_iri,
            "rc:revisionType",
        )
        patch_iris = self._objects(data_graphs, revision_iri, "rc:hasGraphPatch")
        applies_staged_revision = self._first_object(
            data_graphs,
            revision_iri,
            "rc:appliesStagedRevision",
        )
        return self._graph_revision_record_kind(
            revision_type,
            has_patch_payload=bool(patch_iris),
            applies_staged_revision=applies_staged_revision,
        )

    def _staged_review_resolution_for_staged_iri(
        self,
        staged_revision_iri: str,
        *,
        graphs: list[str] | None = None,
    ) -> StagedRevisionReviewResolutionSummary | None:
        summaries = self._staged_review_resolution_summaries_for_staged_iri(
            staged_revision_iri,
            graphs=graphs,
        )
        return summaries[0] if summaries else None

    def _staged_review_resolution_summaries_for_staged_iri(
        self,
        staged_revision_iri: str,
        *,
        graphs: list[str] | None = None,
    ) -> list[StagedRevisionReviewResolutionSummary]:
        staged_revision_value = self.expand_iri(staged_revision_iri)
        data_graphs = graphs or self._expand_graphs(["history"])
        decision_by_iri = {
            self.expand_iri(value): key
            for key, value in STAGED_REVIEW_DECISIONS.items()
        }
        summaries: list[StagedRevisionReviewResolutionSummary] = []
        for resolution_iri in self._subjects(
            data_graphs,
            "rc:resolvesStagedRevision",
            staged_revision_value,
        ):
            decision_iri = self._first_object(
                data_graphs,
                resolution_iri,
                "rc:stagedRevisionReviewDecision",
            )
            summaries.append(
                StagedRevisionReviewResolutionSummary(
                    resolution_revision_iri=resolution_iri,
                    decision=(
                        decision_by_iri.get(decision_iri)
                        if decision_iri is not None
                        else None
                    )
                    or "unknown",
                    decision_iri=decision_iri,
                    decision_label=self._label_for_resource(decision_iri),
                    summary=self._first_object(
                        data_graphs,
                        resolution_iri,
                        "rc:summary",
                    ),
                    rationale=self._first_object(
                        data_graphs,
                        resolution_iri,
                        "rc:revisionRationale",
                    ),
                    created_at=self._first_object(
                        data_graphs,
                        resolution_iri,
                        "rc:createdAt",
                    ),
                    created_by=self._first_object(
                        data_graphs,
                        resolution_iri,
                        "rc:createdBy",
                    ),
                )
            )
        summaries.sort(
            key=lambda item: (
                item.created_at or "",
                item.resolution_revision_iri,
            ),
            reverse=True,
        )
        return summaries

    def describe_staged_revision(
        self,
        iri: str,
        *,
        graph: str | None = "history",
        include_current_apply_check: bool = False,
    ) -> StagedGraphRevisionDescription:
        revision_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(data_graphs)
        if not self._subject_exists(revision_iri, data_graphs):
            graph_label = graph if graph is not None else "all graphs"
            hint = self._missing_revision_snapshot_storage_hint(revision_iri)
            raise DoxaBaseError(
                f"Staged graph revision '{iri}' was not found in {graph_label}{hint}"
            )
        if self.expand_iri("rc:GraphRevision") not in self._types_from_graphs(
            data_graphs,
            revision_iri,
        ):
            raise DoxaBaseError(f"Resource '{iri}' is not an rc:GraphRevision")

        patch_iris = self._objects(data_graphs, revision_iri, "rc:hasGraphPatch")
        if not patch_iris:
            applies_staged_revision = self._first_object(
                data_graphs,
                revision_iri,
                "rc:appliesStagedRevision",
            )
            if applies_staged_revision is not None:
                raise DoxaBaseError(
                    f"Graph revision '{iri}' is an applied revision event, "
                    "not a staged patch revision. Inspect it with "
                    "describe_graph_revision or describe_applied_revision_diff, "
                    "or pass the applied event's staged source IRI "
                    f"'{applies_staged_revision}'."
                )
            raise DoxaBaseError(f"Graph revision '{iri}' has no staged patch entries")

        revision_type = self._first_object(data_graphs, revision_iri, "rc:revisionType")
        revision_stance = self._first_object(
            data_graphs,
            revision_iri,
            "rc:revisionStance",
        )
        alternative_to_iri = self._first_object(
            data_graphs,
            revision_iri,
            "rc:alternativeTo",
        )
        restaged_from_iri = self._first_object(
            data_graphs,
            revision_iri,
            "rc:restagesRevision",
        )
        all_lookup_graphs = self._lookup_graphs(self._expand_graphs(["all"]))
        restaged_from = (
            self._resource_summary(all_lookup_graphs, restaged_from_iri)
            if restaged_from_iri is not None
            else None
        )
        restaged_by_iri = self._first_subject(
            data_graphs,
            "rc:restagesRevision",
            revision_iri,
        )
        restaged_by = (
            self._resource_summary(all_lookup_graphs, restaged_by_iri)
            if restaged_by_iri is not None
            else None
        )
        current_restaged_by_iri = self._current_restage_successor_iri(
            revision_iri,
            graphs=data_graphs,
        )
        current_restaged_by = (
            self._resource_summary(all_lookup_graphs, current_restaged_by_iri)
            if current_restaged_by_iri is not None
            else None
        )
        applied_by_iri = self._first_subject(
            data_graphs,
            "rc:appliesStagedRevision",
            revision_iri,
        )
        applied_by = (
            self._resource_summary(all_lookup_graphs, applied_by_iri)
            if applied_by_iri is not None
            else None
        )
        rationale = self._first_object(
            data_graphs,
            revision_iri,
            "rc:revisionRationale",
        )
        snapshots = self._graph_revision_snapshots(revision_iri, data_graphs)
        included_graphs = self._objects(data_graphs, revision_iri, "rc:includedGraph")
        if not included_graphs:
            included_graphs = [snapshot.graph_role for snapshot in snapshots]
        patches = [
            self._describe_staged_graph_patch(patch_iri, data_graphs)
            for patch_iri in patch_iris
        ]
        patches.sort(key=self._staged_patch_sort_key)
        impacts = self._staged_revision_impacts(
            revision_iri=revision_iri,
            patches=patches,
            lookup_graphs=all_lookup_graphs,
        )
        profile_route_sources = self._stored_profile_insight_route_sources(
            revision_iri
        )

        description = StagedGraphRevisionDescription(
            iri=revision_iri,
            graph=graph,
            label=self._display_label_from_graphs(lookup_graphs, revision_iri),
            summary=self._first_object(data_graphs, revision_iri, "rc:summary"),
            revision_type=revision_type,
            revision_type_label=(
                self._label_from_graphs(self._expand_graphs(["ontology"]), revision_type)
                if revision_type is not None
                else None
            ),
            revision_stance=revision_stance,
            revision_stance_label=self._label_for_resource(revision_stance),
            rationale=rationale,
            review_note=self._first_object(data_graphs, revision_iri, "rc:reviewNote"),
            review_recommendation=self._first_object(
                data_graphs,
                revision_iri,
                "rc:reviewRecommendation",
            ),
            alternative_to=(
                self._resource_summary(all_lookup_graphs, alternative_to_iri)
                if alternative_to_iri is not None
                else None
            ),
            alternative_gate=self._staged_revision_alternative_gate(
                alternative_to_iri,
                graphs=all_lookup_graphs,
            ),
            restaged_from=restaged_from,
            restaged_by=restaged_by,
            current_restaged_by=current_restaged_by,
            applied_by=applied_by,
            review_resolution=self._staged_review_resolution_for_staged_iri(
                revision_iri,
                graphs=data_graphs,
            ),
            application_status="already_applied" if applied_by is not None else None,
            restage_reason=self._staged_revision_restage_reason(
                restaged_from=restaged_from,
                rationale=rationale,
            ),
            changed_graphs=self._objects(data_graphs, revision_iri, "rc:changedGraph"),
            included_graphs=included_graphs,
            created_at=self._first_object(data_graphs, revision_iri, "rc:createdAt"),
            created_by=self._first_object(data_graphs, revision_iri, "rc:createdBy"),
            validation_scope=self._first_object(
                data_graphs,
                revision_iri,
                "rc:validationScope",
            ),
            validation_conforms=self._bool_object(
                data_graphs,
                revision_iri,
                "rc:validationConforms",
            ),
            validation_result_count=self._int_object(
                data_graphs,
                revision_iri,
                "rc:validationResultCount",
            ),
            validation_results=self._graph_revision_validation_results(
                revision_iri,
                data_graphs,
                patches=patches,
            ),
            graph_snapshots=snapshots,
            patches=patches,
            impacts=impacts,
            supporting_observations=self._resource_summaries(
                all_lookup_graphs,
                self._objects(
                    data_graphs,
                    revision_iri,
                    "rc:revisionSupportingObservation",
                ),
            ),
            supporting_claims=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionSupportingClaim"),
            ),
            supporting_patterns=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionSupportingPattern"),
            ),
            revision_anchors=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:revisionAnchor"),
            ),
            evidence=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, revision_iri, "rc:evidence"),
            ),
            profile_route_sources=profile_route_sources,
            profile_route_keys=self._profile_route_keys_from_sources(
                profile_route_sources
            ),
            profile_route_groups=[],
        )
        if profile_route_sources:
            description = replace(
                description,
                profile_route_groups=self._stored_profile_route_groups(
                    profile_route_sources,
                    direct_review_lane=(
                        self._profile_insight_candidate_direct_review_lane(
                            description
                        )
                    ),
                ),
            )
        judgement_panel = self._staged_revision_judgement_panel(description)
        if judgement_panel is not None:
            description = replace(description, judgement_panel=judgement_panel)
        else:
            stored_review_context = self._staged_revision_stored_review_context(
                description
            )
            if stored_review_context is not None:
                description = replace(
                    description,
                    stored_review_context=stored_review_context,
                )
        if include_current_apply_check:
            description = replace(
                description,
                current_apply_check=self._staged_revision_apply_summary(
                    description,
                ),
            )
        return description

    def _staged_revision_apply_summary(
        self,
        staged: StagedGraphRevisionDescription,
    ) -> StagedRevisionApplySummary:
        try:
            check = self._preview_staged_revision_application(
                staged.iri,
                staged=staged,
            ).check
        except DoxaBaseError as exc:
            return StagedRevisionApplySummary(
                staged_revision_iri=staged.iri,
                status="not_available",
                decision="inspect_staged_revision",
                routing_decision="inspect_staged_revision",
                can_apply=None,
                summary=None,
                review_recommended=None,
                semantic_risk_level=None,
                semantic_risk_reasons=[],
                blocking_reasons=[],
                recommended_resolution=None,
                already_applied_by=None,
                restaged_by=(
                    staged.restaged_by.iri if staged.restaged_by is not None else None
                ),
                current_restaged_by=(
                    staged.current_restaged_by.iri
                    if staged.current_restaged_by is not None
                    else None
                ),
                stale_resolution_state=None,
                alternative_gate=staged.alternative_gate,
                changed_graphs=staged.changed_graphs,
                validation_scope=staged.validation_scope,
                validation_conforms=None,
                validation_skipped_reason=None,
                validation_result_count=None,
                patches_checked=None,
                triples_to_add=None,
                triples_to_remove=None,
                effective_delta_summary=None,
                count_drifts=[],
                snapshot_drifts=[],
                next_action=None,
                suggested_next_actions=[],
                suggested_next_calls=[],
                error=str(exc),
            )
        return StagedRevisionApplySummary(
            staged_revision_iri=check.staged_revision_iri,
            status=check.status,
            decision=check.decision,
            routing_decision=check.routing_decision,
            can_apply=check.can_apply,
            summary=check.summary,
            review_recommended=check.review_recommended,
            semantic_risk_level=check.semantic_risk_level,
            semantic_risk_reasons=check.semantic_risk_reasons,
            blocking_reasons=check.blocking_reasons,
            recommended_resolution=check.recommended_resolution,
            already_applied_by=check.already_applied_by,
            restaged_by=check.restaged_by,
            current_restaged_by=check.current_restaged_by,
            stale_resolution_state=check.stale_resolution_state,
            alternative_gate=check.alternative_gate,
            changed_graphs=check.changed_graphs,
            validation_scope=check.validation_scope,
            validation_conforms=check.validation_conforms,
            validation_skipped_reason=check.validation_skipped_reason,
            validation_result_count=check.validation_result_count,
            patches_checked=check.patches_checked,
            triples_to_add=check.triples_to_add,
            triples_to_remove=check.triples_to_remove,
            effective_delta_summary=check.effective_delta_summary,
            count_drifts=check.count_drifts,
            snapshot_drifts=self._summary_snapshot_drifts(check.snapshot_drifts),
            next_action=check.next_action,
            suggested_next_actions=check.suggested_next_actions,
            suggested_next_calls=check.suggested_next_calls,
            error=None,
        )

    def _staged_revision_restage_reason(
        self,
        *,
        restaged_from: ResourceSummary | None,
        rationale: str | None,
    ) -> str | None:
        if restaged_from is None:
            return None
        source_label = restaged_from.label or restaged_from.iri
        fallback = f"Restaged from {source_label}; see rationale for details."
        if not rationale:
            return fallback

        lines = [line.strip() for line in rationale.splitlines()]
        status = self._restage_rationale_field(lines, "- status:")
        decision = self._restage_rationale_field(lines, "- decision:")
        blockers = self._restage_rationale_field(lines, "- blocking reasons:")
        summary = self._restage_rationale_field(lines, "- summary:")

        if not any([status, decision, blockers, summary]):
            first_line = next((line for line in lines if line), None)
            if first_line:
                return self._compact_restage_reason(first_line)
            return fallback

        parts = [f"Restaged from {source_label}"]
        if status:
            parts.append(f"after prior status {status}")
        if decision:
            parts.append(f"decision {decision}")
        if blockers and blockers != "(none)":
            parts.append(f"blockers {blockers}")
        reason = "; ".join(parts) + "."
        if summary:
            reason = f"{reason} {summary}"
        return self._compact_restage_reason(reason)

    @staticmethod
    def _restage_rationale_field(lines: Iterable[str], prefix: str) -> str | None:
        for line in lines:
            if line.startswith(prefix):
                value = line[len(prefix) :].strip()
                return value or None
        return None

    @staticmethod
    def _compact_restage_reason(reason: str, *, limit: int = 420) -> str:
        compact = " ".join(reason.split())
        if len(compact) <= limit:
            return compact
        return compact[: limit - 3].rstrip() + "..."

    def describe_pattern(
        self,
        iri: str,
        *,
        graph: str | None = "patterns",
    ) -> PatternDescription:
        pattern_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(data_graphs)
        all_graphs = self._expand_graphs(["all"])
        all_lookup_graphs = self._lookup_graphs(all_graphs)
        if not self._subject_exists(pattern_iri, data_graphs):
            graph_label = graph if graph is not None else "all graphs"
            raise DoxaBaseError(f"Pattern '{iri}' was not found in {graph_label}")
        if self.expand_iri("rc:Pattern") not in self._types_from_graphs(
            data_graphs,
            pattern_iri,
        ):
            raise DoxaBaseError(f"Resource '{iri}' is not an rc:Pattern")

        confidence = self._first_object(data_graphs, pattern_iri, "rc:confidence")
        observation_status = self._first_object(
            data_graphs,
            pattern_iri,
            "rc:observationStatus",
        )
        pattern_stability = self._first_object(
            data_graphs,
            pattern_iri,
            "rc:patternStability",
        )

        return PatternDescription(
            iri=pattern_iri,
            graph=graph,
            label=self._display_label_from_graphs(lookup_graphs, pattern_iri),
            summary=self._first_object(data_graphs, pattern_iri, "rc:summary"),
            pattern_text=self._first_object(data_graphs, pattern_iri, "rc:patternText"),
            rationale=self._first_object(data_graphs, pattern_iri, "rc:rationale"),
            pattern_targets=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, pattern_iri, "rc:patternTarget"),
            ),
            supporting_observations=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, pattern_iri, "rc:supportingObservation"),
            ),
            supporting_claims=[
                self._describe_claim(claim_iri, all_graphs, all_lookup_graphs)
                for claim_iri in self._objects(
                    data_graphs,
                    pattern_iri,
                    "rc:supportingClaim",
                )
            ],
            evidence=[
                self._describe_evidence(evidence_iri, all_graphs, all_lookup_graphs)
                for evidence_iri in self._objects(data_graphs, pattern_iri, "rc:evidence")
            ],
            confidence=confidence,
            confidence_label=self._label_for_resource(confidence),
            observation_status=observation_status,
            observation_status_label=self._label_for_resource(observation_status),
            pattern_stability=pattern_stability,
            pattern_stability_label=self._label_for_resource(pattern_stability),
            map_implications=self._resource_summaries(
                all_lookup_graphs,
                self._objects(data_graphs, pattern_iri, "rc:mapImplication"),
            ),
        )

    def describe_context_slice(
        self,
        seed_iris: Iterable[str] | str,
        *,
        profile: TypingLiteral[
            "dataset_brief",
            "pattern_brief",
            "deep_lore",
            "resource_brief",
        ] = "dataset_brief",
        max_triples: int = 500,
        include_trig: bool = False,
        graph_iri_prefix: str = RCG_PREFIX,
        privacy_scan_limit: int = 20,
    ) -> ContextSlice:
        if max_triples < 1:
            raise DoxaBaseError("max_triples must be at least 1")
        if privacy_scan_limit < 1:
            raise DoxaBaseError("privacy_scan_limit must be at least 1")
        if profile not in {
            "dataset_brief",
            "pattern_brief",
            "deep_lore",
            "resource_brief",
        }:
            raise DoxaBaseError(
                "profile must be 'dataset_brief', 'pattern_brief', or "
                "'deep_lore', or 'resource_brief'; route explanations are "
                "returned as routes and route_legend on every valid profile, not as a "
                "'route_explained' profile"
            )

        seeds = [
            self.expand_iri(seed)
            for seed in self._string_values("seed_iris", seed_iris, required=True)
        ]
        all_graphs = self._expand_graphs(["all"])
        all_lookup_graphs = self._lookup_graphs(all_graphs)
        resources: dict[str, list[ContextSliceRoute]] = {}
        dataset_contexts: dict[str, DatasetDescription] = {}
        pattern_contexts: dict[str, PatternDescription] = {}
        seed_profile_observations: dict[str, ProfileObservationSummary] = {}
        described_datasets: set[str] = set()
        described_patterns: set[str] = set()
        described_claims: set[str] = set()
        described_observations: set[str] = set()
        described_evidence: set[str] = set()
        described_revisions: set[str] = set()
        warnings: list[str] = []
        resource_brief_recovery_actions: dict[tuple[str, str], SuggestedNextAction] = {}
        resource_brief_graphs = self._context_slice_graphs(profile="resource_brief")
        resource_brief_route_limit = 25
        dataset_observation_route_limit = 5

        def resource_brief_export_path(seed_iri: str, suffix: str) -> str:
            label = re.sub(r"[^A-Za-z0-9]+", "-", self._local_name(seed_iri))
            label = label.strip("-").lower() or "resource"
            digest = hashlib.sha256(seed_iri.encode("utf-8")).hexdigest()[:12]
            return f"/tmp/doxabase-resource-brief-{label[:40]}-{suffix}-{digest}.ttl"

        def add_resource_brief_recovery_action(
            key: tuple[str, str],
            *,
            action_label: str,
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
        ) -> None:
            if key in resource_brief_recovery_actions:
                return
            resource_brief_recovery_actions[key] = SuggestedNextAction(
                action_label=action_label,
                tool_name=tool_name,
                mcp_tool_name=f"doxabase.{tool_name}",
                arguments=arguments,
                reason=reason,
                call=self._suggested_call_string(tool_name, arguments),
            )

        def add_resource(
            iri: str | None,
            route: str,
            route_label: str,
            *,
            source_iri: str | None = None,
            depth: int = 0,
        ) -> None:
            if iri is None:
                return
            expanded_iri = self.expand_iri(iri)
            source_label = (
                self._display_label_from_graphs(all_lookup_graphs, source_iri)
                if source_iri is not None
                else None
            )
            route_record = ContextSliceRoute(
                route=route,
                route_label=route_label,
                source_iri=source_iri,
                source_label=source_label,
                depth=depth,
            )
            existing = resources.setdefault(expanded_iri, [])
            route_key = (
                route_record.route,
                route_record.source_iri,
                route_record.depth,
            )
            if not any(
                (item.route, item.source_iri, item.depth) == route_key
                for item in existing
            ):
                existing.append(route_record)

        def add_summary(
            summary: ResourceSummary | None,
            route: str,
            route_label: str,
            *,
            source_iri: str | None = None,
            depth: int = 0,
        ) -> None:
            if summary is not None:
                add_resource(
                    summary.iri,
                    route,
                    route_label,
                    source_iri=source_iri,
                    depth=depth,
                )

        def add_claim(claim_iri: str, source_iri: str | None, depth: int) -> None:
            if claim_iri in described_claims:
                add_resource(
                    claim_iri,
                    "supporting_claim",
                    "supporting claim",
                    source_iri=source_iri,
                    depth=depth,
                )
                return
            described_claims.add(claim_iri)
            add_resource(
                claim_iri,
                "supporting_claim",
                "supporting claim",
                source_iri=source_iri,
                depth=depth,
            )
            claim = self._describe_claim(claim_iri, all_graphs, all_lookup_graphs)
            for target in claim.claim_targets:
                add_summary(
                    target,
                    "claim_target",
                    "claim target",
                    source_iri=claim_iri,
                    depth=depth + 1,
                )
            for proposed in claim.proposed_assertions:
                add_summary(
                    proposed,
                    "proposed_assertion",
                    "proposed assertion",
                    source_iri=claim_iri,
                    depth=depth + 1,
                )
            for reconsideration in claim.outgoing_reconsiderations:
                add_resource(
                    reconsideration.iri,
                    "claim_reconsideration",
                    "claim reconsideration",
                    source_iri=claim_iri,
                    depth=depth + 1,
                )
                add_summary(
                    reconsideration.older_claim,
                    "reconsidered_claim",
                    "reconsidered claim",
                    source_iri=reconsideration.iri,
                    depth=depth + 2,
                )
                for evidence in reconsideration.evidence:
                    add_evidence(evidence.iri, reconsideration.iri, depth + 2)
            for reconsideration in claim.incoming_reconsiderations:
                add_resource(
                    reconsideration.iri,
                    "incoming_claim_reconsideration",
                    "incoming claim reconsideration",
                    source_iri=claim_iri,
                    depth=depth + 1,
                )
                add_summary(
                    reconsideration.newer_claim,
                    "reconsidering_claim",
                    "reconsidering claim",
                    source_iri=reconsideration.iri,
                    depth=depth + 2,
                )
                for evidence in reconsideration.evidence:
                    add_evidence(evidence.iri, reconsideration.iri, depth + 2)
            for observation_iri in self._subjects(
                all_graphs,
                "rc:hasClaim",
                claim_iri,
            ):
                add_observation(observation_iri, claim_iri, depth + 1)

        def add_evidence(
            evidence_iri: str,
            source_iri: str | None,
            depth: int,
            *,
            route: str = "evidence",
            route_label: str = "evidence",
        ) -> None:
            if evidence_iri in described_evidence:
                add_resource(
                    evidence_iri,
                    route,
                    route_label,
                    source_iri=source_iri,
                    depth=depth,
                )
                return
            described_evidence.add(evidence_iri)
            add_resource(
                evidence_iri,
                route,
                route_label,
                source_iri=source_iri,
                depth=depth,
            )
            for span_iri in self._objects(all_graphs, evidence_iri, "rc:sourceSpan"):
                add_resource(
                    span_iri,
                    "source_span",
                    "source span",
                    source_iri=evidence_iri,
                    depth=depth + 1,
                )

        def add_profile_metric(
            metric_iri: str,
            source_iri: str | None,
            depth: int,
            *,
            include_parent_observations: bool = True,
        ) -> None:
            add_resource(
                metric_iri,
                "observed_profile_metric",
                "observed profile metric",
                source_iri=source_iri,
                depth=depth,
            )
            for metric_kind_iri in self._objects(
                all_graphs,
                metric_iri,
                "rc:profileMetricKind",
            ):
                add_resource(
                    metric_kind_iri,
                    "profile_metric_kind",
                    "profile metric kind",
                    source_iri=metric_iri,
                    depth=depth + 1,
                )
            for metric_target_iri in self._objects(
                all_graphs,
                metric_iri,
                "rc:profileMetricTarget",
            ):
                add_resource(
                    metric_target_iri,
                    "profile_metric_target",
                    "profile metric target",
                    source_iri=metric_iri,
                    depth=depth + 1,
                )
            if include_parent_observations:
                for observation_iri in self._subjects(
                    all_graphs,
                    "rc:observedProfileMetric",
                    metric_iri,
                ):
                    add_observation(
                        observation_iri,
                        metric_iri,
                        depth + 1,
                        route="profile_metric_observation",
                        route_label="profile metric observation",
                        expand_observed_dataset=True,
                    )

        def add_observation(
            observation_iri: str,
            source_iri: str | None,
            depth: int,
            *,
            route: str = "supporting_observation",
            route_label: str = "supporting observation",
            expand_observed_dataset: bool = False,
        ) -> None:
            should_track_seed_profile = route in {
                "seed_profile_observation",
                "profile_metric_observation",
            }
            if observation_iri in described_observations:
                add_resource(
                    observation_iri,
                    route,
                    route_label,
                    source_iri=source_iri,
                    depth=depth,
                )
                if should_track_seed_profile:
                    seed_profile_observations.setdefault(
                        observation_iri,
                        self._profile_observation_summary(
                            observation_iri,
                            all_lookup_graphs,
                        ),
                    )
                return
            described_observations.add(observation_iri)
            add_resource(
                observation_iri,
                route,
                route_label,
                source_iri=source_iri,
                depth=depth,
            )
            if should_track_seed_profile:
                seed_profile_observations.setdefault(
                    observation_iri,
                    self._profile_observation_summary(
                        observation_iri,
                        all_lookup_graphs,
                    ),
                )
            for predicate, route, label in (
                ("rc:observedAsset", "observed_asset", "observed asset"),
                ("rc:observedColumn", "observed_column", "observed column"),
            ):
                for observed_iri in self._objects(all_graphs, observation_iri, predicate):
                    add_resource(
                        observed_iri,
                        route,
                        label,
                        source_iri=observation_iri,
                        depth=depth + 1,
                    )
                    if (
                        expand_observed_dataset
                        and predicate == "rc:observedAsset"
                    ):
                        observed_types = self._types_from_graphs(
                            all_graphs,
                            observed_iri,
                        )
                        if (
                            self.expand_iri("rc:Dataset") in observed_types
                            or self.expand_iri("rc:Table") in observed_types
                        ):
                            add_dataset(observed_iri, observation_iri, depth + 2)
            for claim_iri in self._objects(all_graphs, observation_iri, "rc:hasClaim"):
                add_claim(claim_iri, observation_iri, depth + 1)
            for evidence_iri in self._objects(all_graphs, observation_iri, "rc:evidence"):
                add_evidence(evidence_iri, observation_iri, depth + 1)
            for value_frequency_iri in self._objects(
                all_graphs,
                observation_iri,
                "rc:observedValueFrequency",
            ):
                add_resource(
                    value_frequency_iri,
                    "observed_value_frequency",
                    "observed value frequency",
                    source_iri=observation_iri,
                    depth=depth + 1,
                )
            for metric_iri in self._objects(
                all_graphs,
                observation_iri,
                "rc:observedProfileMetric",
            ):
                add_profile_metric(
                    metric_iri,
                    observation_iri,
                    depth + 1,
                    include_parent_observations=False,
                )

        def add_pattern(pattern_iri: str, source_iri: str | None, depth: int) -> None:
            if pattern_iri in described_patterns:
                add_resource(
                    pattern_iri,
                    "linked_pattern",
                    "linked pattern",
                    source_iri=source_iri,
                    depth=depth,
                )
                return
            described_patterns.add(pattern_iri)
            add_resource(
                pattern_iri,
                "linked_pattern",
                "linked pattern",
                source_iri=source_iri,
                depth=depth,
            )
            try:
                pattern = self.describe_pattern(pattern_iri, graph="patterns")
            except DoxaBaseError as exc:
                warnings.append(str(exc))
                return
            pattern_contexts[pattern.iri] = pattern
            for target in pattern.pattern_targets:
                add_summary(
                    target,
                    "pattern_target",
                    "pattern target",
                    source_iri=pattern_iri,
                    depth=depth + 1,
                )
                add_owner_dataset_for_column(target.iri, pattern_iri, depth + 2)
            for implication in pattern.map_implications:
                add_summary(
                    implication,
                    "map_implication",
                    "map implication",
                    source_iri=pattern_iri,
                    depth=depth + 1,
                )
            for observation in pattern.supporting_observations:
                add_observation(observation.iri, pattern_iri, depth + 1)
            for claim in pattern.supporting_claims:
                add_claim(claim.iri, pattern_iri, depth + 1)
            for evidence in pattern.evidence:
                add_evidence(evidence.iri, pattern_iri, depth + 1)

        def add_revision(
            revision_iri: str,
            source_iri: str | None,
            depth: int,
            *,
            route: str = "seed_revision",
            route_label: str = "seed revision",
        ) -> None:
            if revision_iri in described_revisions:
                add_resource(
                    revision_iri,
                    route,
                    route_label,
                    source_iri=source_iri,
                    depth=depth,
                )
                return
            described_revisions.add(revision_iri)
            add_resource(
                revision_iri,
                route,
                route_label,
                source_iri=source_iri,
                depth=depth,
            )
            for evidence_iri in self._objects(all_graphs, revision_iri, "rc:evidence"):
                add_evidence(
                    evidence_iri,
                    revision_iri,
                    depth + 1,
                    route="revision_evidence",
                    route_label="revision evidence",
                )
            for pattern_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:revisionSupportingPattern",
            ):
                add_pattern(pattern_iri, revision_iri, depth + 1)
            for claim_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:revisionSupportingClaim",
            ):
                add_claim(claim_iri, revision_iri, depth + 1)
            for observation_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:revisionSupportingObservation",
            ):
                add_observation(observation_iri, revision_iri, depth + 1)
            for anchor_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:revisionAnchor",
            ):
                add_resource(
                    anchor_iri,
                    "revision_anchor",
                    "revision anchor",
                    source_iri=revision_iri,
                    depth=depth + 1,
                )
                anchor_types = self._types_from_graphs(all_graphs, anchor_iri)
                if (
                    self.expand_iri("rc:Dataset") in anchor_types
                    or self.expand_iri("rc:Table") in anchor_types
                ):
                    add_dataset(anchor_iri, revision_iri, depth + 2)
                elif self.expand_iri("rc:Column") in anchor_types:
                    add_column(anchor_iri, revision_iri, depth + 2)
            for staged_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:appliesStagedRevision",
            ):
                add_revision(
                    staged_iri,
                    revision_iri,
                    depth + 1,
                    route="applies_staged_revision",
                    route_label="applies staged revision",
                )
            for applied_iri in self._subjects(
                all_graphs,
                "rc:appliesStagedRevision",
                revision_iri,
            ):
                add_revision(
                    applied_iri,
                    revision_iri,
                    depth + 1,
                    route="applied_revision",
                    route_label="applied revision",
                )
            for source_revision_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:restagesRevision",
            ):
                add_revision(
                    source_revision_iri,
                    revision_iri,
                    depth + 1,
                    route="restaged_from_revision",
                    route_label="restaged from revision",
                )
            for successor_revision_iri in self._subjects(
                all_graphs,
                "rc:restagesRevision",
                revision_iri,
            ):
                add_revision(
                    successor_revision_iri,
                    revision_iri,
                    depth + 1,
                    route="restaged_by_revision",
                    route_label="restaged by revision",
                )
            for alternative_iri in self._objects(
                all_graphs,
                revision_iri,
                "rc:alternativeTo",
            ):
                add_revision(
                    alternative_iri,
                    revision_iri,
                    depth + 1,
                    route="alternative_revision",
                    route_label="alternative revision",
                )
            for alternative_iri in self._subjects(
                all_graphs,
                "rc:alternativeTo",
                revision_iri,
            ):
                add_revision(
                    alternative_iri,
                    revision_iri,
                    depth + 1,
                    route="alternative_revision",
                    route_label="alternative revision",
                )

        def add_owner_dataset_for_column(
            iri: str,
            source_iri: str | None,
            depth: int,
        ) -> None:
            owner = self._first_owner_dataset_iri(all_graphs, iri)
            if owner is not None:
                add_resource(
                    owner,
                    "owning_dataset",
                    "owning dataset",
                    source_iri=source_iri,
                    depth=depth,
                )

        def add_column(column_iri: str, source_iri: str | None, depth: int) -> None:
            add_resource(
                column_iri,
                "seed_column" if source_iri is None else "related_column",
                "seed column" if source_iri is None else "related column",
                source_iri=source_iri,
                depth=depth,
            )
            owner = self._first_owner_dataset_iri(all_graphs, column_iri)
            if owner is not None:
                add_dataset(owner, column_iri, depth + 1)
            for pattern_iri in self._subjects(
                all_graphs,
                "rc:patternTarget",
                column_iri,
            ):
                add_pattern(pattern_iri, column_iri, depth + 1)
            for pattern_iri in self._subjects(
                all_graphs,
                "rc:mapImplication",
                column_iri,
            ):
                add_pattern(pattern_iri, column_iri, depth + 1)
            for claim_iri in self._subjects(all_graphs, "rc:claimTarget", column_iri):
                add_claim(claim_iri, column_iri, depth + 1)
            for observation_iri in self._subjects(
                all_graphs,
                "rc:observedColumn",
                column_iri,
            ):
                add_observation(observation_iri, column_iri, depth + 1)

        def add_relationship(relationship: RelationshipDescription, depth: int) -> None:
            add_resource(
                relationship.iri,
                "dataset_relationship",
                "dataset relationship",
                source_iri=relationship.iri,
                depth=depth,
            )
            for summary in (
                relationship.source_dataset,
                relationship.target_dataset,
                relationship.foreign_key_from,
                relationship.foreign_key_to,
                relationship.referential_integrity,
                relationship.derivation_function,
            ):
                add_summary(
                    summary,
                    "relationship_resource",
                    "relationship resource",
                    source_iri=relationship.iri,
                    depth=depth + 1,
                )
            for collection in (
                relationship.identifying_columns,
                relationship.source_columns,
                relationship.derived_columns,
                relationship.derivation_properties,
            ):
                for summary in collection:
                    add_summary(
                        summary,
                        "relationship_resource",
                        "relationship resource",
                        source_iri=relationship.iri,
                        depth=depth + 1,
                    )
            for endpoint in relationship.endpoints:
                add_resource(
                    endpoint.iri,
                    "relationship_endpoint",
                    "relationship endpoint",
                    source_iri=relationship.iri,
                    depth=depth + 1,
                )
                add_summary(
                    endpoint.dataset,
                    "relationship_endpoint_dataset",
                    "relationship endpoint dataset",
                    source_iri=endpoint.iri,
                    depth=depth + 2,
                )
            for condition in relationship.transform_conditions:
                add_resource(
                    condition.iri,
                    "transform_condition",
                    "transform condition",
                    source_iri=relationship.iri,
                    depth=depth + 1,
                )
                add_summary(
                    condition.condition_kind,
                    "transform_condition_kind",
                    "transform condition kind",
                    source_iri=condition.iri,
                    depth=depth + 2,
                )
                for summary in (
                    *condition.applies_to_datasets,
                    *condition.applies_to_endpoints,
                ):
                    add_summary(
                        summary,
                        "transform_condition_scope",
                        "transform condition scope",
                        source_iri=condition.iri,
                        depth=depth + 2,
                    )
            for output in relationship.transform_outputs:
                add_resource(
                    output.iri,
                    "transform_output",
                    "transform output",
                    source_iri=relationship.iri,
                    depth=depth + 1,
                )
                for summary in (output.target_dataset, output.function):
                    add_summary(
                        summary,
                        "transform_output_resource",
                        "transform output resource",
                        source_iri=output.iri,
                        depth=depth + 2,
                    )
                for condition in output.conditions:
                    add_resource(
                        condition.iri,
                        "transform_output_condition",
                        "transform output condition",
                        source_iri=output.iri,
                        depth=depth + 2,
                    )
                if output.tuple_grain is not None:
                    add_resource(
                        output.tuple_grain.iri,
                        "tuple_grain",
                        "tuple grain",
                        source_iri=output.iri,
                        depth=depth + 2,
                    )
                    for component in output.tuple_grain.components:
                        add_resource(
                            component.iri,
                            "grain_component",
                            "grain component",
                            source_iri=output.tuple_grain.iri,
                            depth=depth + 3,
                        )
                        for summary in (component.column, component.dataset):
                            add_summary(
                                summary,
                                "grain_component_resource",
                                "grain component resource",
                                source_iri=component.iri,
                                depth=depth + 4,
                            )

        def add_dataset(dataset_iri: str, source_iri: str | None, depth: int) -> None:
            add_resource(
                dataset_iri,
                "seed_dataset" if source_iri is None else "related_dataset",
                "seed dataset" if source_iri is None else "related dataset",
                source_iri=source_iri,
                depth=depth,
            )
            if dataset_iri in described_datasets:
                return
            described_datasets.add(dataset_iri)
            try:
                dataset = self.describe_dataset(dataset_iri, graph="map")
            except DoxaBaseError as exc:
                warnings.append(str(exc))
                return
            dataset_contexts[dataset.iri] = dataset
            for summary in (
                dataset.row_semantics,
                dataset.entity_key,
                dataset.snapshot_timestamp,
                dataset.schema_stability,
            ):
                add_summary(
                    summary,
                    "dataset_semantic_term",
                    "dataset semantic term",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
            add_summary(
                dataset.layout_verification_status,
                "layout_verification_status",
                "layout verification status",
                source_iri=dataset_iri,
                depth=depth + 1,
            )
            for column in dataset.columns:
                add_resource(
                    column.iri,
                    "dataset_column",
                    "dataset column",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                add_summary(
                    column.physical_type,
                    "column_type",
                    "column type",
                    source_iri=column.iri,
                    depth=depth + 2,
                )
                add_summary(
                    column.value_type,
                    "column_type",
                    "column type",
                    source_iri=column.iri,
                    depth=depth + 2,
                )
                for profile_observation in column.profile_observations:
                    add_observation(
                        profile_observation.iri,
                        column.iri,
                        depth + 2,
                        route="column_profile_observation",
                        route_label="column profile observation",
                    )
            for profile_observation in dataset.profile_observations:
                add_observation(
                    profile_observation.iri,
                    dataset_iri,
                    depth + 1,
                    route="dataset_profile_observation",
                    route_label="dataset profile observation",
                )
            for profile_observation in dataset.unmapped_column_profile_observations:
                add_observation(
                    profile_observation.iri,
                    dataset_iri,
                    depth + 1,
                    route="unmapped_column_profile_observation",
                    route_label="unmapped column profile observation",
                )
            dataset_observation_iris = self._ordinary_observation_iris_for_target(
                target_iri=dataset_iri,
                target_predicate="rc:observedAsset",
            )
            selected_dataset_observation_iris = dataset_observation_iris[
                :dataset_observation_route_limit
            ]
            omitted_dataset_observation_count = len(dataset_observation_iris) - len(
                selected_dataset_observation_iris
            )
            if omitted_dataset_observation_count > 0:
                warnings.append(
                    "Dataset "
                    f"'{dataset_iri}' has {len(dataset_observation_iris)} ordinary "
                    "observed-asset observation(s); included "
                    f"{len(selected_dataset_observation_iris)} and omitted "
                    f"{omitted_dataset_observation_count}. Seed a returned "
                    "observation or search the observations graph when older "
                    "query-result attempts matter."
                )
            for observation_iri in selected_dataset_observation_iris:
                add_observation(
                    observation_iri,
                    dataset_iri,
                    depth + 1,
                    route="dataset_observation",
                    route_label="dataset observation",
                )
            for layout in dataset.physical_layouts:
                add_resource(
                    layout.iri,
                    "physical_layout",
                    "physical layout",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                add_summary(
                    layout.file_format,
                    "layout_term",
                    "layout term",
                    source_iri=layout.iri,
                    depth=depth + 2,
                )
                add_summary(
                    layout.compression_codec,
                    "layout_term",
                    "layout term",
                    source_iri=layout.iri,
                    depth=depth + 2,
                )
                add_summary(
                    layout.layout_verification_status,
                    "layout_verification_status",
                    "layout verification status",
                    source_iri=layout.iri,
                    depth=depth + 2,
                )
            for access in dataset.storage_accesses:
                add_resource(
                    access.iri,
                    "storage_access",
                    "storage access",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                add_summary(
                    access.storage_protocol,
                    "storage_term",
                    "storage term",
                    source_iri=access.iri,
                    depth=depth + 2,
                )
                add_summary(
                    access.access_mode,
                    "storage_term",
                    "storage term",
                    source_iri=access.iri,
                    depth=depth + 2,
                )
                add_summary(
                    access.layout_verification_status,
                    "layout_verification_status",
                    "layout verification status",
                    source_iri=access.iri,
                    depth=depth + 2,
                )
            for partition in dataset.partition_schemes:
                add_resource(
                    partition.iri,
                    "partition_scheme",
                    "partition scheme",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                for partition_column in partition.partition_columns:
                    add_summary(
                        partition_column,
                        "partition_resource",
                        "partition resource",
                        source_iri=partition.iri,
                        depth=depth + 2,
                    )
                add_summary(
                    partition.granularity,
                    "partition_resource",
                    "partition resource",
                    source_iri=partition.iri,
                    depth=depth + 2,
                )
                add_summary(
                    partition.redundant_partition_key,
                    "partition_resource",
                    "partition resource",
                    source_iri=partition.iri,
                    depth=depth + 2,
                )
                add_summary(
                    partition.layout_verification_status,
                    "layout_verification_status",
                    "layout verification status",
                    source_iri=partition.iri,
                    depth=depth + 2,
                )
            for caveat in dataset.caveats:
                add_resource(
                    caveat.iri,
                    "known_caveat",
                    "known caveat",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                add_summary(
                    caveat.severity,
                    "caveat_severity",
                    "caveat severity",
                    source_iri=caveat.iri,
                    depth=depth + 2,
                )
            for provenance in dataset.provenance:
                add_summary(
                    provenance,
                    "provenance",
                    "provenance",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
            for transformation in dataset.transformations:
                add_resource(
                    transformation.iri,
                    "transformation",
                    "transformation",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
            for related in dataset.related_dataset_groups:
                add_resource(
                    related.iri,
                    "related_dataset",
                    "related dataset",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                for reason in related.reasons:
                    if reason.relationship_iri is not None:
                        add_resource(
                            reason.relationship_iri,
                            "related_dataset_reason",
                            "related dataset reason",
                            source_iri=related.iri,
                            depth=depth + 2,
                        )
                    for column in reason.columns:
                        add_summary(
                            column,
                            "related_dataset_column",
                            "related dataset column",
                            source_iri=related.iri,
                            depth=depth + 2,
                        )
            for relationship in dataset.relationships:
                add_relationship(relationship, depth + 1)
            for grain in dataset.tuple_grains:
                add_resource(
                    grain.iri,
                    "tuple_grain",
                    "tuple grain",
                    source_iri=dataset_iri,
                    depth=depth + 1,
                )
                for component in grain.components:
                    add_resource(
                        component.iri,
                        "grain_component",
                        "grain component",
                        source_iri=grain.iri,
                        depth=depth + 2,
                    )
                    for summary in (component.column, component.dataset):
                        add_summary(
                            summary,
                            "grain_component_resource",
                            "grain component resource",
                            source_iri=component.iri,
                            depth=depth + 3,
                        )
            for reason in dataset.linked_pattern_reasons:
                for group in reason.match_groups:
                    add_summary(
                        group.matched_resource,
                        f"linked_pattern_{group.relevance_tier}",
                        f"linked pattern {group.relevance_tier.replace('_', ' ')}",
                        source_iri=reason.iri,
                        depth=depth + 2,
                    )
            for linked_pattern in dataset.linked_patterns:
                add_pattern(linked_pattern.iri, dataset_iri, depth + 1)

        def add_resource_brief(seed_iri: str) -> None:
            for type_iri in self._types_from_graphs(resource_brief_graphs, seed_iri):
                add_resource(
                    type_iri,
                    "resource_type",
                    "resource type",
                    source_iri=seed_iri,
                    depth=1,
                )

            outgoing_refs, outgoing_total = self._resource_brief_outgoing_references(
                resource_brief_graphs,
                subject=seed_iri,
                limit=resource_brief_route_limit,
            )
            for resource_iri in outgoing_refs:
                add_resource(
                    resource_iri,
                    "outgoing_reference",
                    "outgoing reference",
                    source_iri=seed_iri,
                    depth=1,
                )
            if outgoing_total > len(outgoing_refs):
                warnings.append(
                    "resource_brief omitted "
                    f"{outgoing_total - len(outgoing_refs)} outgoing reference(s) "
                    f"for '{seed_iri}' after the route cap of "
                    f"{resource_brief_route_limit}. Raising max_triples does not "
                    "recover route-capped resources; page direct resource triples "
                    "with describe_resource when exact direct references matter."
                )
                add_resource_brief_recovery_action(
                    ("outgoing_reference", seed_iri),
                    action_label="Page outgoing resource references",
                    tool_name="describe_resource",
                    arguments={
                        "iri": seed_iri,
                        "include_incoming": False,
                        "limit": resource_brief_route_limit,
                        "outgoing_offset": len(outgoing_refs),
                    },
                    reason=(
                        "resource_brief capped outgoing references for this seed. "
                        "describe_resource supports offset paging over direct "
                        "resource triples; increasing context-slice max_triples "
                        "will not include omitted route-capped resources."
                    ),
                )

            (
                blank_node_refs,
                blank_node_total,
                blank_node_depth_exhausted,
            ) = self._resource_brief_blank_node_references(
                resource_brief_graphs,
                subject=seed_iri,
                limit=resource_brief_route_limit,
            )
            for resource_iri in blank_node_refs:
                add_resource(
                    resource_iri,
                    "blank_node_reference",
                    "blank-node reference",
                    source_iri=seed_iri,
                    depth=2,
                )
            if blank_node_total > len(blank_node_refs):
                warnings.append(
                    "resource_brief omitted "
                    f"{blank_node_total - len(blank_node_refs)} blank-node "
                    f"reference(s) for '{seed_iri}' after the route cap of "
                    f"{resource_brief_route_limit}. Raising max_triples does not "
                    "recover route-capped resources; inspect blank-node closure "
                    "with describe_resource when exact shape or nested RDF "
                    "details matter."
                )
                add_resource_brief_recovery_action(
                    ("blank_node_reference", seed_iri),
                    action_label="Inspect blank-node closure",
                    tool_name="describe_resource",
                    arguments={
                        "iri": seed_iri,
                        "include_blank_node_closure": True,
                        "blank_node_depth": 4,
                        "blank_node_limit": max(
                            blank_node_total,
                            resource_brief_route_limit * 4,
                        ),
                    },
                    reason=(
                        "resource_brief capped references found through blank "
                        "nodes. describe_resource with blank-node closure is the "
                        "direct recovery route for exact nested shape/RDF details."
                    ),
                )
            if blank_node_depth_exhausted:
                warnings.append(
                    "resource_brief blank-node expansion for "
                    f"'{seed_iri}' reached the bounded depth. Use "
                    "describe_resource(..., include_blank_node_closure=True) "
                    "with a larger blank_node_depth when exact shape closure "
                    "is needed."
                )
                add_resource_brief_recovery_action(
                    ("blank_node_depth", seed_iri),
                    action_label="Inspect deeper blank-node closure",
                    tool_name="describe_resource",
                    arguments={
                        "iri": seed_iri,
                        "include_blank_node_closure": True,
                        "blank_node_depth": 4,
                        "blank_node_limit": max(
                            blank_node_total,
                            resource_brief_route_limit * 4,
                        ),
                    },
                    reason=(
                        "resource_brief reached its bounded blank-node depth. "
                        "describe_resource exposes explicit blank_node_depth and "
                        "blank_node_limit controls."
                    ),
                )

            incoming_refs, incoming_total = self._resource_brief_incoming_subjects(
                resource_brief_graphs,
                object_iri=seed_iri,
                limit=resource_brief_route_limit,
            )
            for resource_iri in incoming_refs:
                add_resource(
                    resource_iri,
                    "incoming_reference",
                    "incoming reference",
                    source_iri=seed_iri,
                    depth=1,
                )
                resource_types = set(
                    self._types_from_graphs(resource_brief_graphs, resource_iri)
                )
                if resource_types & {
                    self.expand_iri("rc:Observation"),
                    self.expand_iri("rc:ProfileObservation"),
                }:
                    for observed_asset_iri in self._objects(
                        resource_brief_graphs,
                        resource_iri,
                        "rc:observedAsset",
                    ):
                        add_resource(
                            observed_asset_iri,
                            "observed_asset",
                            "observed asset",
                            source_iri=resource_iri,
                            depth=2,
                        )
            if incoming_total > len(incoming_refs):
                warnings.append(
                    "resource_brief omitted "
                    f"{incoming_total - len(incoming_refs)} incoming reference(s) "
                    f"for '{seed_iri}' after the route cap of "
                    f"{resource_brief_route_limit}. Raising max_triples does not "
                    "recover route-capped resources; page direct incoming triples "
                    "with describe_resource when exact inbound references matter."
                )
                add_resource_brief_recovery_action(
                    ("incoming_reference", seed_iri),
                    action_label="Page incoming resource references",
                    tool_name="describe_resource",
                    arguments={
                        "iri": seed_iri,
                        "limit": resource_brief_route_limit,
                        "incoming_offset": len(incoming_refs),
                    },
                    reason=(
                        "resource_brief capped incoming references for this seed. "
                        "describe_resource supports offset paging over direct "
                        "incoming triples; increasing context-slice max_triples "
                        "will not include omitted route-capped resources."
                    ),
                )

            (
                blank_node_owners,
                blank_node_owner_total,
            ) = self._resource_brief_incoming_blank_node_owners(
                resource_brief_graphs,
                object_iri=seed_iri,
                limit=resource_brief_route_limit,
            )
            for resource_iri in blank_node_owners:
                add_resource(
                    resource_iri,
                    "incoming_blank_node_owner",
                    "incoming blank-node owner",
                    source_iri=seed_iri,
                    depth=2,
                )
            if blank_node_owner_total > len(blank_node_owners):
                warnings.append(
                    "resource_brief omitted "
                    f"{blank_node_owner_total - len(blank_node_owners)} incoming "
                    f"blank-node owner(s) for '{seed_iri}' after the route cap of "
                    f"{resource_brief_route_limit}. There is no paged blank-node "
                    "owner browser yet; export or narrow the graph when exact "
                    "owner recovery matters."
                )
                add_resource_brief_recovery_action(
                    ("incoming_blank_node_owner", seed_iri),
                    action_label="Export graph for blank-node owner scan",
                    tool_name="export_graph",
                    arguments={
                        "path": resource_brief_export_path(
                            seed_iri,
                            "blank-node-owners",
                        ),
                        "graphs": "shapes",
                    },
                    reason=(
                        "resource_brief capped incoming blank-node owners. DoxaBase "
                        "does not yet expose paged blank-node owner browsing, so "
                        "export the likely shape graph or narrow from a known owner."
                    ),
                )
            if self._is_blank_node_subject(resource_brief_graphs, seed_iri):
                (
                    seed_blank_node_owners,
                    seed_blank_node_owner_total,
                    seed_blank_node_depth_exhausted,
                ) = self._resource_brief_blank_node_seed_owners(
                    resource_brief_graphs,
                    blank_node=seed_iri,
                    limit=resource_brief_route_limit,
                )
                for resource_iri in seed_blank_node_owners:
                    add_resource(
                        resource_iri,
                        "blank_node_seed_owner",
                        "blank-node seed owner",
                        source_iri=seed_iri,
                        depth=1,
                    )
                if seed_blank_node_owner_total > len(seed_blank_node_owners):
                    warnings.append(
                        "resource_brief omitted "
                        f"{seed_blank_node_owner_total - len(seed_blank_node_owners)} "
                        f"blank-node seed owner(s) for '{seed_iri}' after the "
                        f"route cap of {resource_brief_route_limit}. There is no "
                        "paged blank-node owner browser yet; export or narrow the "
                        "graph when exact owner recovery matters."
                    )
                    add_resource_brief_recovery_action(
                        ("blank_node_seed_owner", seed_iri),
                        action_label="Export graph for blank-node seed owner scan",
                        tool_name="export_graph",
                        arguments={
                            "path": resource_brief_export_path(
                                seed_iri,
                                "blank-node-seed-owners",
                            ),
                            "graphs": "shapes",
                        },
                        reason=(
                            "resource_brief capped owners for a blank-node seed. "
                            "DoxaBase does not yet expose paged blank-node owner "
                            "browsing, so export the likely shape graph or narrow "
                            "from a known owner."
                        ),
                    )
                if seed_blank_node_depth_exhausted:
                    warnings.append(
                        "resource_brief owner lookup for blank-node seed "
                        f"'{seed_iri}' reached the bounded depth. Use graph "
                        "export when exact nested blank-node ownership is needed."
                    )

            (
                predicate_users,
                predicate_user_total,
            ) = self._resource_brief_predicate_usage_subjects(
                resource_brief_graphs,
                predicate_iri=seed_iri,
                limit=resource_brief_route_limit,
            )
            for resource_iri in predicate_users:
                add_resource(
                    resource_iri,
                    "predicate_usage_subject",
                    "predicate usage subject",
                    source_iri=seed_iri,
                    depth=1,
                )
            if predicate_user_total > len(predicate_users):
                warnings.append(
                    "resource_brief omitted "
                    f"{predicate_user_total - len(predicate_users)} predicate "
                    f"usage subject(s) for '{seed_iri}' after the route cap of "
                    f"{resource_brief_route_limit}. There is no paged predicate-"
                    "usage browser yet; raising max_triples does not recover "
                    "route-capped predicate users."
                )
                add_resource_brief_recovery_action(
                    ("predicate_usage_subject", seed_iri),
                    action_label="Export project graph for predicate scan",
                    tool_name="export_graph",
                    arguments={
                        "path": resource_brief_export_path(seed_iri, "predicate-usage"),
                        "graphs": "project",
                    },
                    reason=(
                        "resource_brief capped subjects using this resource as a "
                        "predicate. There is no paged predicate-usage browser yet; "
                        "export project RDF or narrow from a known subject/search "
                        "hit when exact usage matters."
                    ),
                )

        profile_seed_limit = 25
        for seed in seeds:
            seed_is_subject = self._subject_exists(seed, all_graphs)
            metric_kind_metric_iris = self._subjects(
                all_graphs,
                "rc:profileMetricKind",
                seed,
            )
            observed_column_profile_observation_iris = self._subjects(
                all_graphs,
                "rc:observedColumn",
                seed,
            )
            observed_value_type_profile_observation_iris = self._subjects(
                all_graphs,
                "rc:observedValueType",
                seed,
            )
            seed_is_resource_brief_target = (
                profile == "resource_brief"
                and self._resource_brief_seed_exists(resource_brief_graphs, seed)
            )
            seed_is_observed_column_only = (
                profile in {"dataset_brief", "deep_lore"}
                and not seed_is_subject
                and bool(observed_column_profile_observation_iris)
            )
            if (
                not seed_is_subject
                and not metric_kind_metric_iris
                and not seed_is_observed_column_only
                and not observed_value_type_profile_observation_iris
                and not seed_is_resource_brief_target
            ):
                raise DoxaBaseError(
                    f"Seed resource '{seed}' was not found in visible RDF "
                    "triples. If this IRI may exist only inside staged patch "
                    "payloads, call list_resource_revisions(resource_iri=..., "
                    "include_patch_mentions=True) or search_staged_patch_payloads "
                    "before concluding it is absent."
                )
            add_resource(seed, "seed", "seed resource", depth=0)
            seed_types = self._types_from_graphs(all_graphs, seed)
            if profile == "resource_brief":
                if self.expand_iri("rc:Pattern") in seed_types:
                    warnings.append(
                        "Seed is an rc:Pattern; resource_brief gives a generic "
                        "resource card. Rerun with profile='pattern_brief' or "
                        "'deep_lore' to recover support, evidence, and pattern "
                        "routes."
                    )
                    add_resource_brief_recovery_action(
                        ("pattern_profile", seed),
                        action_label="Rerun as pattern brief",
                        tool_name="describe_context_slice",
                        arguments={
                            "seed_iris": [seed],
                            "profile": "pattern_brief",
                            "max_triples": max_triples,
                        },
                        reason=(
                            "The seed is an rc:Pattern. resource_brief is useful "
                            "for a generic resource card, but pattern_brief exposes "
                            "pattern support, evidence, and implication routes."
                        ),
                    )
                add_resource_brief(seed)
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and (
                    self.expand_iri("rc:Dataset") in seed_types
                    or self.expand_iri("rc:Table") in seed_types
                )
            ):
                add_dataset(seed, None, 0)
            elif (
                profile in {"pattern_brief", "deep_lore"}
                and self.expand_iri("rc:Pattern") in seed_types
            ):
                add_pattern(seed, None, 0)
            elif (
                profile in {"pattern_brief", "deep_lore"}
                and self.expand_iri("rc:Claim") in seed_types
            ):
                add_claim(seed, None, 0)
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and self.expand_iri("rc:Column") in seed_types
            ):
                add_column(seed, None, 0)
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and self.expand_iri("rc:ProfileObservation") in seed_types
            ):
                add_observation(
                    seed,
                    None,
                    0,
                    route="seed_profile_observation",
                    route_label="seed profile observation",
                    expand_observed_dataset=True,
                )
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and self.expand_iri("rc:Observation") in seed_types
            ):
                add_observation(
                    seed,
                    None,
                    0,
                    route="seed_observation",
                    route_label="seed observation",
                    expand_observed_dataset=True,
                )
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and self.expand_iri("rc:ObservedProfileMetric") in seed_types
            ):
                add_profile_metric(seed, None, 0)
            elif seed_is_observed_column_only:
                add_resource(
                    seed,
                    "seed_observed_column",
                    "seed observed column",
                    depth=0,
                )
                for observation_iri in observed_column_profile_observation_iris:
                    add_observation(
                        observation_iri,
                        seed,
                        1,
                        route="seed_profile_observation",
                        route_label="seed profile observation",
                        expand_observed_dataset=True,
                    )
            elif (
                profile in {"dataset_brief", "deep_lore"}
                and observed_value_type_profile_observation_iris
            ):
                add_resource(
                    seed,
                    "seed_observed_value_type",
                    "seed observed value type",
                    depth=0,
                )
                selected_observation_iris = (
                    observed_value_type_profile_observation_iris[:profile_seed_limit]
                )
                omitted_observation_count = len(
                    observed_value_type_profile_observation_iris
                ) - len(selected_observation_iris)
                if omitted_observation_count > 0:
                    warnings.append(
                        "Observed-value-type seed "
                        f"'{seed}' matched "
                        f"{len(observed_value_type_profile_observation_iris)} "
                        "profile observation(s); included "
                        f"{len(selected_observation_iris)} and omitted "
                        f"{omitted_observation_count}. Use a dataset, profile "
                        "observation, or observed column seed for a narrower "
                        "complete handoff."
                    )
                for observation_iri in selected_observation_iris:
                    add_observation(
                        observation_iri,
                        seed,
                        1,
                        route="seed_profile_observation",
                        route_label="seed profile observation",
                        expand_observed_dataset=True,
                    )
            elif (
                profile == "deep_lore"
                and self.expand_iri("rc:GraphRevision") in seed_types
            ):
                add_revision(seed, None, 0)
            elif profile in {"dataset_brief", "deep_lore"} and metric_kind_metric_iris:
                add_resource(
                    seed,
                    "seed_profile_metric_kind",
                    "seed profile metric kind",
                    depth=0,
                )
                selected_metric_iris = metric_kind_metric_iris[:profile_seed_limit]
                omitted_metric_count = len(metric_kind_metric_iris) - len(
                    selected_metric_iris
                )
                if omitted_metric_count > 0:
                    warnings.append(
                        "Metric-kind seed "
                        f"'{seed}' matched {len(metric_kind_metric_iris)} observed "
                        "profile metric(s); included "
                        f"{len(selected_metric_iris)} and omitted "
                        f"{omitted_metric_count}. Use a narrower dataset, profile, "
                        "or observed metric seed for a complete handoff."
                    )
                for metric_iri in selected_metric_iris:
                    add_profile_metric(metric_iri, seed, 1)
            else:
                warnings.append(
                    self._context_slice_profile_mismatch_warning(
                        seed,
                        profile=profile,
                        seed_types=seed_types,
                        metric_kind_metric_iris=metric_kind_metric_iris,
                        observed_value_type_profile_observation_iris=(
                            observed_value_type_profile_observation_iris
                        ),
                    )
                )
                resource_brief_seed_types = {
                    self.expand_iri("rc:StorageAccess"),
                    self.expand_iri("rc:PhysicalLayout"),
                    self.expand_iri("rc:PartitionScheme"),
                }
                if (
                    profile == "deep_lore"
                    and set(seed_types) & resource_brief_seed_types
                ):
                    arguments: dict[str, Any] = {
                        "seed_iris": [seed],
                        "profile": "resource_brief",
                        "max_triples": max_triples,
                    }
                    if include_trig:
                        arguments["include_trig"] = True
                    add_resource_brief_recovery_action(
                        ("deep_lore_resource_brief_retry", seed),
                        action_label="Retry with resource brief",
                        tool_name="describe_context_slice",
                        arguments=arguments,
                        reason=(
                            "The seed is physical/query metadata rather than a "
                            "dataset, pattern, claim, observation, or revision. "
                            "resource_brief follows incoming owner-table routes "
                            "and can then suggest describe_query_context when "
                            "query-planning repair context exists."
                        ),
                    )

        if profile == "deep_lore":
            self._add_revision_context_for_slice(
                resources,
                all_graphs,
                add_resource,
                add_revision,
            )

        resource_iris = self._context_slice_resource_order(resources, all_lookup_graphs)
        triples, candidate_triple_count = self._context_slice_triples(
            self._context_slice_graphs(profile=profile),
            resource_iris,
            max_triples=max_triples,
        )
        omitted_triple_count = max(candidate_triple_count - len(triples), 0)
        truncated = omitted_triple_count > 0
        trig = (
            self._context_slice_trig(triples, graph_iri_prefix=graph_iri_prefix)
            if include_trig
            else None
        )
        graph_counts: dict[str, int] = {}
        for triple in triples:
            graph_counts[triple.graph] = graph_counts.get(triple.graph, 0) + 1
        sensitive_literal_count, matches, omitted_match_count = (
            self._context_slice_sensitive_matches(
                triples,
                limit=privacy_scan_limit,
            )
        )
        privacy_warnings = self._sensitive_literal_warnings(
            match_count=sensitive_literal_count,
            omitted_match_count=omitted_match_count,
        )
        scanner_note = (
            "Context-slice privacy scan covers only the returned raw triples. "
            "This describe_context_slice payload may still contain unredacted "
            "raw triples, TriG, labels, summaries, and project facts; use "
            "preflight_context_slice_export or export_preflight before sharing "
            "or writing handoff artifacts."
            if sensitive_literal_count
            else None
        )
        route_counts = self._context_slice_route_counts(resources)
        if profile == "deep_lore" and not self._context_slice_has_lore_routes(
            route_counts,
        ):
            warnings.append(
                "deep_lore found no claims, patterns, reconsiderations, "
                "evidence, or revision history beyond map context for these seeds."
            )
        warnings.extend(
            self._context_slice_structured_context_warnings(
                resource_count=len(resources),
                dataset_contexts=dataset_contexts.values(),
                truncated=truncated,
            )
        )
        warnings.extend(privacy_warnings)
        if scanner_note is not None:
            warnings.append(scanner_note)
        suggested_next_actions = [
            *self._context_slice_privacy_next_actions(
                seed_iris=seeds,
                profile=profile,
                max_triples=max(candidate_triple_count, max_triples)
                if truncated
                else max_triples,
                privacy_scan_limit=privacy_scan_limit,
                sensitive_literal_count=sensitive_literal_count,
                truncated=truncated,
            ),
            *resource_brief_recovery_actions.values(),
            *self._context_slice_next_actions(
                seed_iris=seeds,
                profile=profile,
                max_triples=max_triples,
                include_trig=include_trig,
                candidate_triple_count=candidate_triple_count,
                truncated=truncated,
                dataset_contexts=dataset_contexts.values(),
                pattern_contexts=pattern_contexts.values(),
                resources=resources,
                lookup_graphs=all_lookup_graphs,
            ),
        ]

        return ContextSlice(
            profile=profile,
            seeds=[
                self._resource_summary(all_lookup_graphs, seed, display_label=True)
                for seed in seeds
            ],
            reading_order=self._context_slice_reading_order(),
            resources=[
                self._context_slice_resource(
                    iri,
                    routes,
                    all_lookup_graphs,
                    profile=profile,
                )
                for iri, routes in self._context_slice_ordered_resources(
                    resources,
                    all_lookup_graphs,
                )
            ],
            resource_count=len(resources),
            route_legend=self._context_slice_route_legend(resources, route_counts),
            route_counts=route_counts,
            graph_counts=graph_counts,
            triples=triples,
            triple_count=len(triples),
            returned_triple_count=len(triples),
            candidate_triple_count=candidate_triple_count,
            omitted_triple_count=omitted_triple_count,
            max_triples=max_triples,
            truncated=truncated,
            truncation_scope="triples_only",
            trig=trig,
            sensitive_literal_count=sensitive_literal_count,
            returned_match_count=len(matches),
            omitted_match_count=omitted_match_count,
            privacy_scan_limit=privacy_scan_limit,
            matches=matches,
            privacy_warnings=privacy_warnings,
            scanner_note=scanner_note,
            seed_profile_observations=list(seed_profile_observations.values()),
            dataset_contexts=list(dataset_contexts.values()),
            pattern_contexts=list(pattern_contexts.values()),
            warnings=warnings,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _context_slice_privacy_next_actions(
        self,
        *,
        seed_iris: list[str],
        profile: str,
        max_triples: int,
        privacy_scan_limit: int,
        sensitive_literal_count: int,
        truncated: bool,
    ) -> list[SuggestedNextAction]:
        if sensitive_literal_count == 0:
            return []
        arguments = {
            "seed_iris": seed_iris,
            "profile": profile,
            "max_triples": max_triples,
            "include_seed_graphs": True,
            "limit": privacy_scan_limit,
        }
        truncation_note = (
            " The current slice is truncated, so this action uses the full "
            "candidate triple cap rather than the returned cap."
            if truncated
            else ""
        )
        return [
            SuggestedNextAction(
                action_label="Preflight context-slice privacy",
                tool_name="preflight_context_slice_export",
                mcp_tool_name="doxabase.preflight_context_slice_export",
                arguments=arguments,
                reason=(
                    "Selected raw context-slice triples matched the sensitive-term "
                    "scanner. Use the redacted export preflight before sharing "
                    "slice content or writing an importable handoff artifact."
                    f"{truncation_note}"
                ),
                call=self._suggested_call_string(
                    "preflight_context_slice_export",
                    arguments,
                ),
            )
        ]

    def _context_slice_next_actions(
        self,
        *,
        seed_iris: list[str],
        profile: str,
        max_triples: int,
        include_trig: bool,
        candidate_triple_count: int,
        truncated: bool,
        dataset_contexts: Iterable[DatasetDescription],
        pattern_contexts: Iterable[PatternDescription],
        resources: Mapping[str, list[ContextSliceRoute]],
        lookup_graphs: list[str],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        dataset_context_list = list(dataset_contexts)
        dataset_context_by_iri = {
            dataset.iri: dataset for dataset in dataset_context_list
        }

        def add_slice_action(
            arguments: dict[str, Any],
            reason: str,
            *,
            action_label: str,
        ) -> None:
            actions.append(
                SuggestedNextAction(
                    action_label=action_label,
                    tool_name="describe_context_slice",
                    mcp_tool_name="doxabase.describe_context_slice",
                    arguments=arguments,
                    reason=reason,
                    call=self._suggested_call_string(
                        "describe_context_slice",
                        arguments,
                    ),
                )
            )

        seed_iris_set = set(seed_iris)

        def resource_reached_from_seed(
            resource_iri: str,
            routes: Iterable[ContextSliceRoute],
        ) -> bool:
            if resource_iri in seed_iris_set:
                return True
            route_list = list(routes)
            if any(route.source_iri in seed_iris_set for route in route_list):
                return True
            if profile != "resource_brief":
                return False
            return any(
                route.route == "observed_asset"
                and route.source_iri is not None
                and any(
                    observation_route.source_iri in seed_iris_set
                    for observation_route in resources.get(route.source_iri, ())
                )
                for route in route_list
            )

        if profile == "resource_brief":
            dataset_type_iris = {
                self.expand_iri("rc:Dataset"),
                self.expand_iri("rc:Table"),
            }
            for resource_iri, routes in resources.items():
                if resource_iri in dataset_context_by_iri:
                    continue
                if not resource_reached_from_seed(resource_iri, routes):
                    continue
                if not (
                    set(self._types_from_graphs(lookup_graphs, resource_iri))
                    & dataset_type_iris
                ):
                    continue
                try:
                    dataset_context_by_iri[resource_iri] = self.describe_dataset(
                        resource_iri
                    )
                except DoxaBaseError:
                    continue
            dataset_context_list = list(dataset_context_by_iri.values())

        def dataset_reached_from_seed(dataset_iri: str) -> bool:
            return resource_reached_from_seed(
                dataset_iri,
                resources.get(dataset_iri, ()),
            )

        queryable_owner_iris: set[str] = {
            dataset.iri
            for dataset in dataset_context_list
            if self.expand_iri("rc:Table") in dataset.types
            and dataset_reached_from_seed(dataset.iri)
        }
        metadata_seed_type_iris = {
            self.expand_iri("rc:StorageAccess"),
            self.expand_iri("rc:PhysicalLayout"),
            self.expand_iri("rc:PartitionScheme"),
            self.expand_iri("rc:CompositePartitionScheme"),
        }
        metadata_seed_has_single_queryable_owner = (
            profile == "resource_brief"
            and any(
                set(self._types_from_graphs(lookup_graphs, seed_iri))
                & metadata_seed_type_iris
                for seed_iri in seed_iris
            )
            and len(queryable_owner_iris) == 1
        )

        seen_dataset_iris: set[str] = set()
        for dataset in dataset_context_list:
            if not dataset_reached_from_seed(dataset.iri):
                continue
            if dataset.iri in seen_dataset_iris:
                continue
            if self.expand_iri("rc:Table") not in dataset.types:
                continue
            operational_issue_codes = sorted(
                {
                    issue.code
                    for issue in dataset.operational_warnings
                    if issue.severity in {"error", "warning"}
                }
            )
            query_context = self.describe_query_context(dataset.iri)
            repair_issue_codes = sorted(
                {
                    group.issue_code
                    for group in query_context.suggested_repair_action_groups
                }
            )
            issue_codes = sorted(
                {*operational_issue_codes, *repair_issue_codes}
            )
            owner_route_without_issues = (
                metadata_seed_has_single_queryable_owner
                and dataset.iri in queryable_owner_iris
            )
            if not issue_codes and not owner_route_without_issues:
                continue
            seen_dataset_iris.add(dataset.iri)
            arguments = {"iri": dataset.iri}
            warning_issue_codes = sorted(
                set(operational_issue_codes) - set(repair_issue_codes)
            )
            issue_reason_parts: list[str] = []
            if repair_issue_codes:
                issue_reason_parts.append(
                    "query-planning repair group(s): "
                    f"{', '.join(repair_issue_codes)}"
                )
            if warning_issue_codes:
                issue_reason_parts.append(
                    "operational query-planning warning(s): "
                    f"{', '.join(warning_issue_codes)}"
                )
            if not issue_reason_parts:
                if owner_route_without_issues:
                    issue_reason_parts.append(
                        "a single queryable owner table reached from storage, "
                        "layout, or partition metadata"
                    )
                else:
                    issue_reason_parts.append(
                        "operational query-planning warning(s): "
                        f"{', '.join(operational_issue_codes)}"
                    )
            actions.append(
                SuggestedNextAction(
                    action_label="Inspect query-planning context",
                    tool_name="describe_query_context",
                    mcp_tool_name="doxabase.describe_query_context",
                    arguments=arguments,
                    reason=(
                        "The seed dataset has "
                        f"{' and '.join(issue_reason_parts)}. "
                        "describe_query_context exposes readiness, target "
                        "candidates, and repair hints before drafting or "
                        "running queries."
                    ),
                    call=self._suggested_call_string(
                        "describe_query_context",
                        arguments,
                    ),
                )
            )

        if not truncated:
            return actions

        seen_pattern_iris: set[str] = set()
        pattern_action_count = 0
        linked_pattern_relevance_ranks = (
            self._context_slice_linked_pattern_relevance_ranks(dataset_context_list)
        )
        sorted_pattern_contexts = sorted(
            pattern_contexts,
            key=lambda pattern_context: self._context_slice_pattern_action_key(
                pattern_context,
                resources=resources,
                lookup_graphs=lookup_graphs,
                linked_pattern_relevance_ranks=linked_pattern_relevance_ranks,
            ),
        )
        for pattern_context in sorted_pattern_contexts:
            if pattern_context.iri in seen_pattern_iris:
                continue
            seen_pattern_iris.add(pattern_context.iri)
            if profile == "pattern_brief":
                continue
            arguments: dict[str, Any] = {
                "seed_iris": [pattern_context.iri],
                "profile": "pattern_brief",
                "max_triples": max_triples,
            }
            if include_trig:
                arguments["include_trig"] = True
            add_slice_action(
                arguments,
                (
                    "Raw triples were truncated, but this linked pattern has "
                    "structured context. Rerun around the pattern for a smaller "
                    "pattern-focused handoff before raising max_triples."
                ),
                action_label="Narrow to pattern context",
            )
            pattern_action_count += 1
            if pattern_action_count >= 3:
                break

        full_triple_cap = max(candidate_triple_count, max_triples)
        arguments = {
            "seed_iris": seed_iris,
            "profile": profile,
            "max_triples": full_triple_cap,
        }
        if include_trig:
            arguments["include_trig"] = True
        add_slice_action(
            arguments,
            (
                "Use this only when exact raw RDF triples are needed; "
                "structured resources, route counts, and context summaries are "
                "already complete despite the raw triple cap."
            ),
            action_label="Return full raw RDF for slice",
        )
        return actions

    def _context_slice_pattern_action_key(
        self,
        pattern_context: PatternDescription,
        *,
        resources: Mapping[str, list[ContextSliceRoute]],
        lookup_graphs: list[str],
        linked_pattern_relevance_ranks: Mapping[str, int],
    ) -> tuple[int, int, int, str, str]:
        routes = resources.get(pattern_context.iri, [])
        if not routes:
            return (
                999,
                999,
                999,
                pattern_context.summary or pattern_context.iri,
                pattern_context.iri,
            )
        best_route_key = min(
            self._context_slice_pattern_action_route_key(route) for route in routes
        )
        if pattern_context.iri in linked_pattern_relevance_ranks:
            best_route_key = min(
                best_route_key,
                (
                    linked_pattern_relevance_ranks[pattern_context.iri],
                    best_route_key[1],
                    best_route_key[2],
                ),
            )
        return (
            *best_route_key,
            self._display_label_from_graphs(lookup_graphs, pattern_context.iri)
            or pattern_context.summary
            or "",
            pattern_context.iri,
        )

    def _context_slice_pattern_action_route_key(
        self,
        route: ContextSliceRoute,
    ) -> tuple[int, int, int]:
        if route.route == "seed":
            return (-1, route.depth, self._context_slice_route_priority(route.route))
        if route.route.startswith("linked_pattern_"):
            relevance_tier = route.route.removeprefix("linked_pattern_")
            return (
                self._linked_pattern_relevance_rank(relevance_tier),
                route.depth,
                self._context_slice_route_priority(route.route),
            )
        if route.route == "linked_pattern":
            return (50, route.depth, self._context_slice_route_priority(route.route))
        return (
            100 + self._context_slice_route_priority(route.route),
            route.depth,
            self._context_slice_route_priority(route.route),
        )

    def _context_slice_linked_pattern_relevance_ranks(
        self,
        dataset_contexts: Iterable[DatasetDescription],
    ) -> dict[str, int]:
        ranks: dict[str, int] = {}
        for dataset in dataset_contexts:
            for reason in dataset.linked_pattern_reasons:
                if not reason.match_groups:
                    continue
                rank = min(
                    self._linked_pattern_relevance_rank(group.relevance_tier)
                    for group in reason.match_groups
                )
                current_rank = ranks.get(reason.pattern_iri)
                if current_rank is None or rank < current_rank:
                    ranks[reason.pattern_iri] = rank
        return ranks

    @staticmethod
    def _context_slice_structured_context_warnings(
        *,
        resource_count: int,
        dataset_contexts: Iterable[DatasetDescription],
        truncated: bool,
    ) -> list[str]:
        if not truncated:
            return []
        wide_datasets = [
            dataset
            for dataset in dataset_contexts
            if len(dataset.columns) >= 50
        ]
        details: list[str] = []
        if resource_count >= 100:
            details.append(f"{resource_count} selected resource(s)")
        if wide_datasets:
            dataset_notes = [
                f"{dataset.label or dataset.iri} has {len(dataset.columns)} column(s)"
                for dataset in wide_datasets[:3]
            ]
            if len(wide_datasets) > 3:
                dataset_notes.append(f"{len(wide_datasets) - 3} more wide dataset(s)")
            details.append("; ".join(dataset_notes))
        detail_text = f" ({'; '.join(details)})" if details else ""
        return [
            "Context slice raw RDF was truncated by max_triples, but structured "
            "contexts are still returned in full"
            f"{detail_text}. Use a narrower column, profile, metric, or pattern "
            "seed for a smaller handoff; suggested_next_actions names concrete "
            "pattern seeds when available and raises max_triples only when exact "
            "raw RDF is needed."
        ]

    def _context_slice_profile_mismatch_warning(
        self,
        seed: str,
        *,
        profile: str,
        seed_types: set[str],
        metric_kind_metric_iris: list[str],
        observed_value_type_profile_observation_iris: list[str],
    ) -> str:
        base = (
            f"Seed '{seed}' was included directly; profile-specific expansion "
            "did not apply."
        )
        dataset_profiles = "profile='dataset_brief' or 'deep_lore'"
        pattern_profiles = "profile='pattern_brief' or 'deep_lore'"
        if self.expand_iri("rc:Pattern") in seed_types:
            return f"{base} Seed is an rc:Pattern; rerun with {pattern_profiles}."
        if self.expand_iri("rc:Claim") in seed_types:
            return f"{base} Seed is an rc:Claim; rerun with {pattern_profiles}."
        if self.expand_iri("rc:Dataset") in seed_types:
            return f"{base} Seed is an rc:Dataset; rerun with {dataset_profiles}."
        if self.expand_iri("rc:Table") in seed_types:
            return f"{base} Seed is an rc:Table; rerun with {dataset_profiles}."
        if self.expand_iri("rc:ProfileObservation") in seed_types:
            return (
                f"{base} Seed is an rc:ProfileObservation; rerun with "
                f"{dataset_profiles}."
            )
        if self.expand_iri("rc:ObservedProfileMetric") in seed_types:
            return (
                f"{base} Seed is an rc:ObservedProfileMetric; rerun with "
                f"{dataset_profiles}."
            )
        if self.expand_iri("rc:StorageAccess") in seed_types:
            return (
                f"{base} Seed is an rc:StorageAccess; rerun with "
                "profile='resource_brief' to recover owner-table routes."
            )
        if self.expand_iri("rc:PhysicalLayout") in seed_types:
            return (
                f"{base} Seed is an rc:PhysicalLayout; rerun with "
                "profile='resource_brief' to recover owner-table routes."
            )
        if self.expand_iri("rc:PartitionScheme") in seed_types:
            return (
                f"{base} Seed is an rc:PartitionScheme; rerun with "
                "profile='resource_brief' to recover owner-table routes."
            )
        if self.expand_iri("rc:GraphRevision") in seed_types:
            return (
                f"{base} Seed is an rc:GraphRevision; rerun with "
                "profile='deep_lore'."
            )
        if metric_kind_metric_iris:
            return (
                f"{base} Seed is used as an rc:profileMetricKind; rerun with "
                f"{dataset_profiles}."
            )
        if observed_value_type_profile_observation_iris:
            return (
                f"{base} Seed is used as an rc:observedValueType; rerun with "
                f"{dataset_profiles}."
            )
        return base

    def _resource_brief_seed_exists(self, graphs: list[str], seed: str) -> bool:
        return (
            self._subject_exists(seed, graphs)
            or self._resource_triple_count(
                graphs,
                object_value=seed,
                object_kind="uri",
            )
            > 0
            or self._resource_brief_predicate_usage_count(
                graphs,
                predicate_iri=seed,
            )
            > 0
        )

    def _is_blank_node_subject(self, graphs: list[str], subject: str) -> bool:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        row = self._conn.execute(
            f"""
            SELECT 1
            FROM quads q
            WHERE q.subject = ?
              AND q.subject_kind = 'bnode'
              {graph_filter}
            LIMIT 1
            """,
            [subject, *graph_params],
        ).fetchone()
        return row is not None

    def _resource_brief_outgoing_references(
        self,
        graphs: list[str],
        *,
        subject: str,
        limit: int,
    ) -> tuple[list[str], int]:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        where = """
            q.subject = ?
            AND q.object_kind = 'uri'
            AND q.predicate != ?
        """
        params: list[Any] = [subject, str(RDF.type), *graph_params]
        return self._resource_brief_distinct_iris(
            where,
            params,
            graph_filter=graph_filter,
            select_column="q.object",
            limit=limit,
        )

    def _resource_brief_incoming_subjects(
        self,
        graphs: list[str],
        *,
        object_iri: str,
        limit: int,
    ) -> tuple[list[str], int]:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        rows = self._conn.execute(
            f"""
            SELECT DISTINCT q.subject AS iri
            FROM quads q
            WHERE q.object = ?
              AND q.object_kind = 'uri'
              AND q.subject_kind = 'uri'
              {graph_filter}
            """,
            [object_iri, *graph_params],
        ).fetchall()
        iris = [str(row["iri"]) for row in rows]
        lookup_graphs = self._lookup_graphs(graphs)
        ordered = sorted(
            iris,
            key=lambda iri: (
                -self._resource_brief_incoming_usefulness_score(graphs, iri),
                self._display_label_from_graphs(lookup_graphs, iri) or "",
                iri,
            ),
        )
        return ordered[:limit], len(ordered)

    def _resource_brief_incoming_usefulness_score(
        self,
        graphs: list[str],
        iri: str,
    ) -> int:
        score = 0
        types = set(self._types_from_graphs(graphs, iri))
        if self.expand_iri("rc:Column") in types:
            score += 12
        if (
            self.expand_iri("rc:Dataset") in types
            or self.expand_iri("rc:Table") in types
        ):
            score += 8
        if self._subjects(graphs, "rc:revisionAnchor", iri):
            score += 70
        if self._subjects(graphs, "rc:claimTarget", iri):
            score += 60
        if self._subjects(graphs, "rc:patternTarget", iri):
            score += 50
        if self._subjects(graphs, "rc:mapImplication", iri):
            score += 45
        if self._subjects(graphs, "rc:observedColumn", iri):
            score += 40
        if self._subjects(graphs, "rc:observedAsset", iri):
            score += 30
        if self._objects(graphs, iri, "rc:hasKnownCaveat"):
            score += 35
        if self._objects(graphs, iri, "rc:caveatDescription"):
            score += 20
        if self._subjects(graphs, "rc:hasColumn", iri):
            score += 10
        return score

    def _resource_brief_predicate_usage_subjects(
        self,
        graphs: list[str],
        *,
        predicate_iri: str,
        limit: int,
    ) -> tuple[list[str], int]:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        where = """
            q.predicate = ?
            AND q.subject_kind = 'uri'
        """
        params: list[Any] = [predicate_iri, *graph_params]
        return self._resource_brief_distinct_iris(
            where,
            params,
            graph_filter=graph_filter,
            select_column="q.subject",
            limit=limit,
        )

    def _resource_brief_predicate_usage_count(
        self,
        graphs: list[str],
        *,
        predicate_iri: str,
    ) -> int:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        row = self._conn.execute(
            f"""
            SELECT COUNT(DISTINCT q.subject) AS count
            FROM quads q
            WHERE q.predicate = ?
              AND q.subject_kind = 'uri'
              {graph_filter}
            """,
            [predicate_iri, *graph_params],
        ).fetchone()
        return int(row["count"])

    def _resource_brief_incoming_blank_node_owners(
        self,
        graphs: list[str],
        *,
        object_iri: str,
        limit: int,
    ) -> tuple[list[str], int]:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        rows = self._conn.execute(
            f"""
            SELECT DISTINCT q.subject AS blank_node
            FROM quads q
            WHERE q.object = ?
              AND q.object_kind = 'uri'
              AND q.subject_kind = 'bnode'
              {graph_filter}
            ORDER BY q.subject
            """,
            [object_iri, *graph_params],
        ).fetchall()
        owners, _depth_exhausted = self._recursive_blank_node_uri_owners(
            graphs,
            blank_nodes=[row["blank_node"] for row in rows],
        )
        ordered_owners = sorted(owners)
        return ordered_owners[:limit], len(ordered_owners)

    def _resource_brief_blank_node_seed_owners(
        self,
        graphs: list[str],
        *,
        blank_node: str,
        limit: int,
        max_depth: int = 4,
    ) -> tuple[list[str], int, bool]:
        owners, depth_exhausted = self._recursive_blank_node_uri_owners(
            graphs,
            blank_nodes=[blank_node],
            max_depth=max_depth,
        )
        ordered_owners = sorted(owners)
        return ordered_owners[:limit], len(ordered_owners), depth_exhausted

    def _recursive_blank_node_uri_owners(
        self,
        graphs: list[str],
        *,
        blank_nodes: Iterable[str],
        max_depth: int = 4,
    ) -> tuple[set[str], bool]:
        frontier = list(dict.fromkeys(blank_nodes))
        visited: set[str] = set()
        owners: set[str] = set()
        for _depth in range(max_depth):
            if not frontier:
                break
            next_frontier: list[str] = []
            for current_blank_node in frontier:
                if current_blank_node in visited:
                    continue
                visited.add(current_blank_node)
                uri_owners, blank_node_owners = self._blank_node_subject_owners(
                    graphs,
                    blank_node=current_blank_node,
                )
                owners.update(uri_owners)
                for owner in blank_node_owners:
                    if owner not in visited and owner not in next_frontier:
                        next_frontier.append(owner)
            frontier = next_frontier
        depth_exhausted = bool(frontier)
        return owners, depth_exhausted

    def _blank_node_subject_owners(
        self,
        graphs: list[str],
        *,
        blank_node: str,
    ) -> tuple[list[str], list[str]]:
        graph_filter, graph_params = self._graph_filter(graphs, alias="q")
        rows = self._conn.execute(
            f"""
            SELECT DISTINCT q.subject, q.subject_kind
            FROM quads q
            WHERE q.object = ?
              AND q.object_kind = 'bnode'
              {graph_filter}
            ORDER BY q.subject
            """,
            [blank_node, *graph_params],
        ).fetchall()
        uri_owners = [
            row["subject"] for row in rows if row["subject_kind"] == "uri"
        ]
        blank_node_owners = [
            row["subject"] for row in rows if row["subject_kind"] == "bnode"
        ]
        return uri_owners, blank_node_owners

    def _resource_brief_blank_node_references(
        self,
        graphs: list[str],
        *,
        subject: str,
        limit: int,
    ) -> tuple[list[str], int, bool]:
        closure_triples, _total_count, depth_exhausted, _unvisited_count = (
            self._resource_blank_node_closure(
                graphs,
                subject=subject,
                max_depth=2,
                limit=max(limit * 20, 100),
            )
        )
        refs = sorted(
            {
                triple.object
                for triple in closure_triples
                if triple.object_kind == "uri"
            }
        )
        return refs[:limit], len(refs), depth_exhausted

    def _resource_brief_distinct_iris(
        self,
        where: str,
        params: list[Any],
        *,
        graph_filter: str,
        select_column: str,
        limit: int,
    ) -> tuple[list[str], int]:
        base_query = f"""
            SELECT DISTINCT {select_column} AS iri
            FROM quads q
            WHERE {where}
              {graph_filter}
        """
        rows = self._conn.execute(
            f"""
            {base_query}
            ORDER BY iri
            LIMIT ?
            """,
            [*params, limit],
        ).fetchall()
        count_row = self._conn.execute(
            f"SELECT COUNT(*) AS count FROM ({base_query})",
            params,
        ).fetchone()
        return [row["iri"] for row in rows], int(count_row["count"])

    def _add_revision_context_for_slice(
        self,
        resources: dict[str, list[ContextSliceRoute]],
        all_graphs: list[str],
        add_resource: Any,
        add_revision: Any,
    ) -> None:
        history_graphs = ["history"]
        support_predicates = (
            ("rc:revisionSupportingPattern", "revision_supporting_pattern"),
            ("rc:revisionSupportingClaim", "revision_supporting_claim"),
            ("rc:revisionSupportingObservation", "revision_supporting_observation"),
        )
        for resource_iri in list(resources):
            for predicate, route in support_predicates:
                for revision_iri in self._subjects(
                    history_graphs,
                    predicate,
                    resource_iri,
                ):
                    add_resource(
                        revision_iri,
                        route,
                        "supporting revision",
                        source_iri=resource_iri,
                        depth=3,
                    )
                    for evidence_iri in self._objects(
                        all_graphs,
                        revision_iri,
                        "rc:evidence",
                    ):
                        add_resource(
                            evidence_iri,
                            "revision_evidence",
                            "revision evidence",
                            source_iri=revision_iri,
                            depth=4,
                        )
            for revision_iri in self._subjects(
                history_graphs,
                "rc:revisionAnchor",
                resource_iri,
            ):
                add_revision(
                    revision_iri,
                    resource_iri,
                    3,
                    route="revision_anchor_match",
                    route_label="revision anchored to selected resource",
                )

    def _context_slice_graphs(self, *, profile: str | None = None) -> list[str]:
        graphs = [
            "base_ontology",
            "ontology",
            "map",
            "observations",
            "patterns",
            "evidence",
            "history",
        ]
        if profile == "resource_brief":
            graphs.insert(1, "base_shapes")
            graphs.insert(3, "shapes")
        return graphs

    def _context_slice_resource(
        self,
        iri: str,
        routes: list[ContextSliceRoute],
        lookup_graphs: list[str],
        *,
        profile: str | None = None,
    ) -> ContextSliceResource:
        summary = self._resource_summary(lookup_graphs, iri, display_label=True)
        sorted_routes = self._context_slice_sorted_routes(routes)
        graphs = self._graphs_for_subject(
            self._context_slice_graphs(profile=profile),
            iri,
        )
        return ContextSliceResource(
            iri=iri,
            label=summary.label,
            description=summary.description,
            types=self._types_from_graphs(lookup_graphs, iri),
            graphs=graphs,
            surface_role=self._context_slice_surface_role(graphs),
            referenced_only=not graphs,
            primary_route=sorted_routes[0],
            routes=sorted_routes,
        )

    @staticmethod
    def _context_slice_surface_role(graphs: Iterable[str]) -> str:
        role_by_graph = DoxaBase._context_slice_surface_role_by_graph()
        roles = {
            role_by_graph[graph]
            for graph in graphs
            if graph in role_by_graph
        }
        if not roles:
            return "referenced_only"
        if len(roles) == 1:
            return next(iter(roles))
        return "mixed_context"

    @staticmethod
    def _context_slice_surface_role_by_graph() -> dict[str, str]:
        return {
            "base_ontology": "vocabulary_context",
            "base_shapes": "validation_shape_context",
            "ontology": "vocabulary_context",
            "shapes": "validation_shape_context",
            "map": "current_map_context",
            "observations": "observation_context",
            "patterns": "pattern_synthesis",
            "evidence": "evidence_support",
            "history": "revision_history",
        }

    @staticmethod
    def _context_slice_surface_roles_for_graphs(
        graphs: Iterable[str],
    ) -> list[str]:
        role_by_graph = DoxaBase._context_slice_surface_role_by_graph()
        return sorted(
            {
                role_by_graph[graph]
                for graph in graphs
                if graph in role_by_graph
            }
        )

    def _context_slice_resource_order(
        self,
        resources: dict[str, list[ContextSliceRoute]],
        lookup_graphs: list[str],
    ) -> list[str]:
        return [
            iri
            for iri, _routes in self._context_slice_ordered_resources(
                resources,
                lookup_graphs,
            )
        ]

    def _context_slice_ordered_resources(
        self,
        resources: dict[str, list[ContextSliceRoute]],
        lookup_graphs: list[str],
    ) -> list[tuple[str, list[ContextSliceRoute]]]:
        return sorted(
            resources.items(),
            key=lambda item: (
                min(self._context_slice_route_priority(route.route) for route in item[1]),
                min(route.depth for route in item[1]),
                self._display_label_from_graphs(lookup_graphs, item[0]) or "",
                item[0],
            ),
        )

    def _context_slice_sorted_routes(
        self,
        routes: Iterable[ContextSliceRoute],
    ) -> list[ContextSliceRoute]:
        return sorted(
            routes,
            key=lambda route: (
                self._context_slice_route_priority(route.route),
                route.depth,
                route.source_iri or "",
                route.route,
            ),
        )

    def _context_slice_route_priority(self, route: str) -> int:
        exact = {
            "seed": 0,
            "seed_dataset": 1,
            "seed_column": 2,
            "seed_observed_column": 2,
            "seed_observed_value_type": 2,
            "seed_revision": 2,
            "linked_pattern": 2,
            "resource_type": 3,
            "outgoing_reference": 4,
            "blank_node_reference": 5,
            "incoming_reference": 6,
            "incoming_blank_node_owner": 7,
            "blank_node_seed_owner": 7,
            "predicate_usage_subject": 8,
            "pattern_target": 3,
            "map_implication": 4,
            "dataset_column": 5,
            "known_caveat": 6,
            "dataset_relationship": 7,
            "relationship_endpoint": 8,
            "relationship_endpoint_dataset": 9,
            "related_dataset_reason": 8,
            "related_dataset": 9,
            "related_column": 9,
            "supporting_claim": 10,
            "claim_reconsideration": 11,
            "incoming_claim_reconsideration": 11,
            "reconsidered_claim": 12,
            "reconsidering_claim": 12,
            "supporting_observation": 13,
            "dataset_observation": 13,
            "dataset_profile_observation": 13,
            "column_profile_observation": 13,
            "unmapped_column_profile_observation": 13,
            "seed_observation": 13,
            "seed_profile_observation": 13,
            "profile_metric_observation": 13,
            "observed_profile_metric": 14,
            "observed_value_frequency": 14,
            "applied_revision": 14,
            "applies_staged_revision": 14,
            "restaged_from_revision": 14,
            "restaged_by_revision": 14,
            "alternative_revision": 14,
            "revision_anchor": 14,
            "revision_anchor_match": 14,
            "profile_metric_kind": 15,
            "profile_metric_target": 15,
            "seed_profile_metric_kind": 15,
            "evidence": 16,
            "source_span": 17,
        }
        if route in exact:
            return exact[route]
        if route.startswith("linked_pattern_"):
            return 2
        if route.startswith("revision_"):
            return 14
        if route.endswith("_term"):
            return 20
        return 30

    def _context_slice_route_counts(
        self,
        resources: dict[str, list[ContextSliceRoute]],
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for routes in resources.values():
            for route in routes:
                counts[route.route] = counts.get(route.route, 0) + 1
        return counts

    def _context_slice_has_lore_routes(self, route_counts: Mapping[str, int]) -> bool:
        lore_routes = {
            "linked_pattern",
            "supporting_claim",
            "claim_reconsideration",
            "incoming_claim_reconsideration",
            "reconsidered_claim",
            "reconsidering_claim",
            "supporting_observation",
            "dataset_observation",
            "dataset_profile_observation",
            "column_profile_observation",
            "unmapped_column_profile_observation",
            "seed_observation",
            "seed_profile_observation",
            "profile_metric_observation",
            "observed_profile_metric",
            "observed_value_frequency",
            "seed_revision",
            "applied_revision",
            "applies_staged_revision",
            "restaged_from_revision",
            "restaged_by_revision",
            "alternative_revision",
            "revision_anchor",
            "evidence",
            "source_span",
        }
        return any(
            route in lore_routes or route.startswith(("linked_pattern_", "revision_"))
            for route, count in route_counts.items()
            if count > 0
        )

    def _context_slice_reading_order(self) -> list[str]:
        return [
            "Start with seeds to confirm the requested entry points.",
            "Check warnings for caps, broad seeds, or missing lore before relying on the slice.",
            (
                "Read dataset_contexts, pattern_contexts, and "
                "seed_profile_observations for compact structured context."
            ),
            "Scan route_counts and route_legend to understand why resources were included.",
            (
                "Use reading_order, route_counts, and route_legend as the route "
                "summary surface; there is no separate route_summaries field."
            ),
            "Read resources in order, using primary_route before secondary routes.",
            "Inspect triples or trig only when exact RDF statements or graph roles matter.",
        ]

    def _context_slice_route_legend(
        self,
        resources: dict[str, list[ContextSliceRoute]],
        route_counts: dict[str, int],
    ) -> list[ContextSliceRouteLegend]:
        labels: dict[str, str] = {}
        for routes in resources.values():
            for route in routes:
                labels.setdefault(route.route, route.route_label)
        return [
            ContextSliceRouteLegend(
                route=route,
                route_label=labels.get(route, route.replace("_", " ")),
                meaning=self._context_slice_route_meaning(route),
                priority=self._context_slice_route_priority(route),
                count=count,
            )
            for route, count in sorted(
                route_counts.items(),
                key=lambda item: (self._context_slice_route_priority(item[0]), item[0]),
            )
        ]

